#include "query1.hpp"

#include <algorithm>
#include <charconv>
#include <cstdint>
#include <iomanip>
#include <limits>
#include <sstream>
#include <stdexcept>
#include <string>
#include <string_view>
#include <utility>
#include <vector>

// SELECT l_returnflag, l_linestatus,
//   sum(l_quantity) as sum_qty, sum(l_extendedprice) as sum_base_price,
//   sum(l_extendedprice*(1-l_discount)) as sum_disc_price,
//   sum(l_extendedprice*(1-l_discount)*(1+l_tax)) as sum_charge,
//   avg(l_quantity) as avg_qty, avg(l_extendedprice) as avg_price,
//   avg(l_discount) as avg_disc, count(*) as count_order
// FROM lineitem
// WHERE l_shipdate <= date '1998-12-01' - interval '[DELTA]' day
// GROUP BY l_returnflag, l_linestatus
// ORDER BY l_returnflag, l_linestatus

// ---------------------------------------------------------------------------
// Date helpers (days since 1992-01-01 = our DATE16 encoding)
// ---------------------------------------------------------------------------
static const int Q1_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};
static bool q1_leap(int y) { return (y%4==0&&y%100!=0)||y%400==0; }
static uint16_t q1_date(const std::string& s) {
    int y=std::stoi(s.substr(0,4)), m=std::stoi(s.substr(5,2)), d=std::stoi(s.substr(8,2));
    int tot=0; for(int i=1992;i<y;++i) tot+=q1_leap(i)?366:365;
    int lp=q1_leap(y)?1:0; for(int i=1;i<m;++i) tot+=Q1_DIM[lp][i-1];
    return static_cast<uint16_t>(tot+(d-1));
}

// ---------------------------------------------------------------------------
// Format helpers
// ---------------------------------------------------------------------------

// Integer scaled value → decimal string with `scale` fractional digits,
// trailing zeros stripped but >= 2dp kept.
static std::string fmt_scaled(int64_t v, int scale) {
    bool neg=(v<0); if(neg) v=-v;
    int64_t div=1; for(int i=0;i<scale;++i) div*=10;
    std::ostringstream oss;
    if(neg) oss<<'-';
    oss<<v/div<<'.'<<std::setw(scale)<<std::setfill('0')<<v%div;
    std::string s=oss.str();
    size_t dot=s.find('.'); size_t last=s.size()-1;
    while(last>dot+2&&s[last]=='0') --last;
    s.resize(last+1); return s;
}

// __int128 scaled value → decimal string (same as fmt_scaled but for i128)
static std::string fmt_scaled_i128(__int128 v, int scale) {
    bool neg=(v<0); if(neg) v=-v;
    __int128 div=1; for(int i=0;i<scale;++i) div*=10;
    __int128 whole=v/div, frac=v%div;
    // convert to string
    std::string w_str, f_str;
    if(whole==0) { w_str="0"; }
    else { __int128 tmp=whole; while(tmp>0){w_str=(char)('0'+tmp%10)+w_str; tmp/=10;} }
    // frac: zero-pad to `scale` digits
    std::string fr_raw;
    { __int128 tmp=frac; for(int i=0;i<scale;++i){fr_raw=(char)('0'+tmp%10)+fr_raw; tmp/=10;} }
    std::string result = (neg?"-":"") + w_str + "." + fr_raw;
    // strip trailing zeros, keep >= 2dp
    size_t dot=result.find('.'); size_t last=result.size()-1;
    while(last>dot+2&&result[last]=='0') --last;
    result.resize(last+1);
    return result;
}

// Double → shortest round-trip decimal string (matches Python repr/str).
static std::string fmt_float(double v) {
    char buf[32];
    auto [ptr, ec] = std::to_chars(buf, buf + sizeof(buf), v);
    if (ec != std::errc()) {
        std::ostringstream oss;
        oss << std::setprecision(17) << std::defaultfloat << v;
        return oss.str();
    }
    return std::string(buf, ptr);
}

// ---------------------------------------------------------------------------
// Per-group accumulator
// ---------------------------------------------------------------------------
struct Q1Bucket {
    int64_t  sum_qty               = 0;
    int64_t  sum_base_price        = 0;   // raw ep (scale=2)
    int64_t  sum_disc_price_x10000 = 0;   // sum(ep*(100-disc)); /10000 → 4dp
    // sum_charge: use __int128 to match DuckDB's Hugeint (128-bit) DECIMAL aggregation.
    // This avoids int64 overflow at large scale factors and exactly replicates DuckDB's
    // internal DECIMAL(38,6) arithmetic path.
    __int128 sum_charge_x1000000   = 0;
    int64_t  sum_disc              = 0;   // raw discount codes
    int64_t  count                 = 0;
};

std::vector<std::vector<std::string>> run_q1(Database* db, const Q1Args& args) {
    if (!db) throw std::runtime_error("run_q1: db is null");

    int delta = std::stoi(args.DELTA);
    uint16_t base = q1_date("1998-12-01");
    uint16_t cutoff = (delta<=(int)base) ? static_cast<uint16_t>(base-delta) : uint16_t{0};

    // returnflag: A=0, N=1, R=2  |  linestatus: O=0, F=1
    static const char RF[3] = {'A','N','R'};
    static const char LS[2] = {'O','F'};
    Q1Bucket bk[6]; bool used[6]={};

    const Lineitem& li = db->lineitem;
    const uint32_t n   = li.row_count;
    const uint16_t* sd = li.l_shipdate.data();
    const uint8_t*  rfl= li.l_returnflag.data();
    const uint8_t*  lss= li.l_linestatus.data();
    const uint8_t*  qt = li.l_quantity.data();
    const int64_t*  ep = li.l_extendedprice.data();
    const uint8_t*  dc = li.l_discount.data();
    const uint8_t*  tx = li.l_tax.data();

    for (uint32_t i = 0; i < n; ++i) {
        if (sd[i] > cutoff) continue;
        int idx = rfl[i]*2 + lss[i];
        used[idx] = true;
        int64_t e=ep[i], d=dc[i], t=tx[i];
        // disc_price at scale-4: ep * (100-disc)
        int64_t dp = e * (100 - d);
        bk[idx].sum_qty               += qt[i];
        bk[idx].sum_base_price        += e;
        bk[idx].sum_disc_price_x10000 += dp;
        // charge at scale-6: dp * (100+tx)  -- accumulate as __int128 (Hugeint)
        bk[idx].sum_charge_x1000000   += (__int128)dp * (100 + t);
        bk[idx].sum_disc              += d;
        bk[idx].count                 += 1;
    }

    std::vector<std::vector<std::string>> rows;
    rows.push_back({"l_returnflag","l_linestatus","sum_qty","sum_base_price",
                    "sum_disc_price","sum_charge","avg_qty","avg_price","avg_disc","count_order"});

    // OUTPUT ORDER: l_returnflag ASC, l_linestatus ASC
    // rf: A(0) < N(1) < R(2) alphabetically
    // ls: F(1) < O(0) alphabetically ('F'=70 < 'O'=79)
    static const int LS_ORDER[2] = {1, 0};  // F first, then O
    for (int r = 0; r < 3; ++r) {
        for (int li_ord = 0; li_ord < 2; ++li_ord) {
            int l   = LS_ORDER[li_ord];
            int idx = r * 2 + l;
            if (!used[idx]) continue;
            const Q1Bucket& b = bk[idx];
            int64_t cnt = b.count;
            rows.push_back({
                std::string(1,RF[r]), std::string(1,LS[l]),
                std::to_string(b.sum_qty),
                fmt_scaled(b.sum_base_price, 2),
                fmt_scaled(b.sum_disc_price_x10000, 4),
                fmt_scaled_i128(b.sum_charge_x1000000, 6),
                fmt_float((double)b.sum_qty / cnt),
                fmt_float((double)b.sum_base_price / (cnt * 100.0)),
                fmt_float((double)b.sum_disc / (cnt * 100.0)),
                std::to_string(cnt)
            });
        }
    }
    return rows;
}

