    // at SF20 (~120M rows): 1.2e8 * 1.08e10 = 1.296e18 — well within int64 max 9.2e18.
    int64_t  sum_charge_x1000000   = 0;
    int64_t  sum_disc              = 0;  // raw discount codes (0..10)
    int64_t  count                 = 0;
