std::vector<std::vector<std::string>> run_q1(Database* db, const Q1Args& args) {
    if (!db) throw std::runtime_error("run_q1: db is null");

    PROFILE_SCOPE("q1_total");

    int delta = std::stoi(args.DELTA);
    uint16_t base = q1_date("1998-12-01");
    uint16_t cutoff = (delta<=(int)base) ? static_cast<uint16_t>(base-delta) : uint16_t{0};

    // returnflag: A=0, N=1, R=2  |  linestatus: O=0, F=1
    static const char RF[3] = {'A','N','R'};
    static const char LS[2] = {'O','F'};
    // 6 accumulators: idx = returnflag*2 + linestatus
    Q1Bucket bk[6];

    const Lineitem& li = db->lineitem;
    const uint32_t n   = li.row_count;
    const uint16_t* __restrict__ sd = li.l_shipdate.data();
    const uint8_t*  __restrict__ rfl= li.l_returnflag.data();
    const uint8_t*  __restrict__ lss= li.l_linestatus.data();
    const uint8_t*  __restrict__ qty= li.l_quantity.data();
    const int64_t*  __restrict__ ep = li.l_extendedprice.data();
    const uint8_t*  __restrict__ dc = li.l_discount.data();
    const uint8_t*  __restrict__ tx = li.l_tax.data();

    // ------------------------------------------------------------------
    // Scan + filter + aggregate with zone-map chunk skipping.
    // ------------------------------------------------------------------
    uint64_t rows_scanned  = 0;
    uint64_t rows_emitted  = 0;
    uint64_t chunks_skipped = 0;

    constexpr uint32_t CHUNK_SZ = 65536;
    const uint32_t n_chunks = (n + CHUNK_SZ - 1) / CHUNK_SZ;
    const uint16_t* cmin = li.shipdate_chunk_min.data();

    {
        PROFILE_SCOPE("q1_lineitem_scan_filter_agg");
        for (uint32_t ci = 0; ci < n_chunks; ++ci) {
            // Skip entire chunk if all shipdates > cutoff
            if (cmin[ci] > cutoff) { ++chunks_skipped; continue; }

            uint32_t row_lo = ci * CHUNK_SZ;
            uint32_t row_hi = std::min(row_lo + CHUNK_SZ, n);
            rows_scanned += (row_hi - row_lo);

            for (uint32_t i = row_lo; i < row_hi; ++i) {
                if (sd[i] > cutoff) continue;
                ++rows_emitted;
                int idx = rfl[i]*2 + lss[i];
                int64_t e = ep[i];
                int64_t d = dc[i];
                int64_t t = tx[i];
                int64_t dp = e * (100 - d);
                bk[idx].sum_qty               += qty[i];
                bk[idx].sum_base_price        += e;
                bk[idx].sum_disc_price_x10000 += dp;
                bk[idx].sum_charge_x1000000   += dp * (100 + t);
                bk[idx].sum_disc              += d;
                bk[idx].count                 += 1;
            }
        }
    }

    // Count distinct groups actually populated
    int groups_created = 0;
    for (int g = 0; g < 6; ++g) if (bk[g].count > 0) ++groups_created;

    TRACE_COUNT("q1_lineitem_rows_scanned",  static_cast<int64_t>(rows_scanned));
    TRACE_COUNT("q1_lineitem_rows_emitted",  static_cast<int64_t>(rows_emitted));
    TRACE_COUNT("q1_chunks_skipped",         static_cast<int64_t>(chunks_skipped));
    TRACE_COUNT("q1_groups_created",         static_cast<int64_t>(groups_created));
    TRACE_COUNT("q1_agg_rows_emitted",       static_cast<int64_t>(groups_created));

    std::vector<std::vector<std::string>> rows;
    rows.push_back({"l_returnflag","l_linestatus","sum_qty","sum_base_price",
                    "sum_disc_price","sum_charge","avg_qty","avg_price","avg_disc","count_order"});

    // OUTPUT ORDER: l_returnflag ASC, l_linestatus ASC
    // rf: A(0) < N(1) < R(2) alphabetically
    // ls: F(1) < O(0) alphabetically ('F'=70 < 'O'=79)
    static const int LS_ORDER[2] = {1, 0};  // F first, then O
    {
        PROFILE_SCOPE("q1_format_output");
        for (int r = 0; r < 3; ++r) {
            for (int li_ord = 0; li_ord < 2; ++li_ord) {
                int l   = LS_ORDER[li_ord];
                int idx = r * 2 + l;
                if (bk[idx].count == 0) continue;
                const Q1Bucket& b = bk[idx];
                int64_t cnt = b.count;
                rows.push_back({
                    std::string(1,RF[r]), std::string(1,LS[l]),
                    std::to_string(b.sum_qty),
                    fmt_scaled(b.sum_base_price, 2),
                    fmt_scaled(b.sum_disc_price_x10000, 4),
                    fmt_scaled(b.sum_charge_x1000000, 6),
                    fmt_float((double)b.sum_qty / cnt),
                    fmt_float((double)b.sum_base_price / (cnt * 100.0)),
                    fmt_float((double)b.sum_disc / (cnt * 100.0)),
                    std::to_string(cnt)
                });
            }
        }
    }

    // rows includes header; subtract 1 for actual data rows
    TRACE_COUNT("q1_query_output_rows", static_cast<int64_t>(rows.size() - 1));

    return rows;
}

