//     Build a map suppkey -> nationkey for quick lookup.
//  4. For each part with p_size==SIZE and p_type LIKE '%TYPE':
//       a. Scan its partsupp rows (via partkey_to_first_row CSR).
//       b. For each ps row, check if ps_suppkey is in suppkey set.
//       c. Track min(ps_supplycost) over all such rows (for this partkey).
//  5. Second pass: for each qualifying (part, ps) pair where
//     ps_supplycost == min and suppkey is in region:
//       emit (s_acctbal, s_name, n_name, p_partkey, p_mfgr, s_address, s_phone, s_comment).
//  6. Sort by s_acctbal DESC, n_name ASC, s_name ASC, p_partkey ASC.
// ---------------------------------------------------------------------------

std::vector<std::vector<std::string>> run_q2(Database* db, const Q2Args& args) {
    if (!db) {
        throw std::runtime_error("run_q2: db is null");
    }

    const int    target_size   = std::stoi(args.SIZE);
    const std::string type_suffix = args.TYPE;    // e.g. "NICKEL"
    const std::string region_name = args.REGION;  // e.g. "EUROPE"

    PROFILE_SCOPE("q2_total");

    const Region&   reg = db->region;
    const Nation&   nat = db->nation;
    const Part&     prt = db->part;
    const Supplier& sup = db->supplier;
    const PartSupp& ps  = db->partsupp;

    // ------------------------------------------------------------------
    // Step 1: resolve region key
    // ------------------------------------------------------------------
    int region_key = reg.name_to_key(region_name);
    if (region_key < 0) {
        // No matching region -> empty result
        std::vector<std::vector<std::string>> rows;
        rows.push_back({"s_acctbal","s_name","n_name","p_partkey",
                        "p_mfgr","s_address","s_phone","s_comment"});
        return rows;
    }

    // ------------------------------------------------------------------
    // Step 2: build set of nation keys in that region
    // ------------------------------------------------------------------
    bool nation_in_region[25] = {};
    {
        PROFILE_SCOPE("q2_nation_scan");
        uint64_t rows_scanned = 0, rows_emitted = 0;
        for (int i = 0; i < 25; ++i) {
            ++rows_scanned;
            if (nat.n_regionkey[i] == static_cast<uint8_t>(region_key)) {
                nation_in_region[i] = true;
                ++rows_emitted;
            }
        }
        TRACE_COUNT("q2_nation_rows_scanned", static_cast<int64_t>(rows_scanned));
        TRACE_COUNT("q2_nation_rows_emitted", static_cast<int64_t>(rows_emitted));
    }

    // ------------------------------------------------------------------
    // Step 3: build supplier filter bitmap (suppkey -> in_region bool)
    // ------------------------------------------------------------------
    uint32_t max_sk = static_cast<uint32_t>(sup.suppkey_to_row.size());
    std::vector<bool> supp_in_region(max_sk, false);
    {
        PROFILE_SCOPE("q2_supplier_scan");
        uint64_t rows_scanned = 0, rows_emitted = 0;
        for (uint32_t row = 0; row < sup.row_count; ++row) {
            ++rows_scanned;
            int32_t sk = sup.s_suppkey[row];
            if (sk > 0 && static_cast<uint32_t>(sk) < max_sk) {
                if (nation_in_region[sup.s_nationkey[row]]) {
                    supp_in_region[static_cast<uint32_t>(sk)] = true;
                    ++rows_emitted;
                }
            }
        }
        TRACE_COUNT("q2_supplier_rows_scanned", static_cast<int64_t>(rows_scanned));
        TRACE_COUNT("q2_supplier_rows_emitted", static_cast<int64_t>(rows_emitted));
    }

    // ------------------------------------------------------------------
    // Step 3b: pre-compute which p_type_code values match type_suffix
    //          (dictionary is tiny: ~30 values; avoids string ops in hot loop)
    // ------------------------------------------------------------------
    uint32_t num_type_codes = static_cast<uint32_t>(prt.p_type_dict.size());
    // Use uint8_t (not vector<bool>) so we can take .data() pointer
    std::vector<uint8_t> type_code_ok(num_type_codes, 0);
    for (uint32_t tc = 0; tc < num_type_codes; ++tc)
        type_code_ok[tc] = ends_with(prt.p_type_dict[tc], type_suffix) ? 1 : 0;

    // ------------------------------------------------------------------
    // Step 4: Part scan + partsupp nested-loop join
    // ------------------------------------------------------------------
    struct ResultRow {
        int64_t     s_acctbal;   // raw *100
        std::string s_name;
        std::string n_name;
        int32_t     p_partkey;
        std::string p_mfgr;
        std::string s_address;
        std::string s_phone;
        std::string s_comment;
    };
    std::vector<ResultRow> result;

    uint32_t ps_size = static_cast<uint32_t>(ps.partkey_to_first_row.size()); // = max_pk+1

    {
        PROFILE_SCOPE("q2_part_scan_and_partsupp_probe");
        uint64_t part_rows_scanned  = 0;
        uint64_t part_rows_emitted  = 0;
        uint64_t ps_build_rows_in   = 0;
        uint64_t ps_probe_rows_in   = 0;
        uint64_t join_rows_emitted  = 0;

        const uint8_t  target_sz    = static_cast<uint8_t>(target_size);
        const uint8_t* p_size_ptr   = prt.p_size.data();
        const uint16_t* p_type_ptr  = prt.p_type_code.data();
        const int32_t* p_key_ptr    = prt.p_partkey.data();
        const uint8_t* type_ok_ptr  = type_code_ok.data();
        const uint32_t* ps_first    = ps.partkey_to_first_row.data();
        const uint32_t  part_count  = prt.row_count;

        for (uint32_t part_row = 0; part_row < part_count; ++part_row) {
            ++part_rows_scanned;

            if (p_size_ptr[part_row] != target_sz) continue;

            if (!type_ok_ptr[p_type_ptr[part_row]]) continue;

            ++part_rows_emitted;

            int32_t pk = p_key_ptr[part_row];
            if (pk <= 0 || static_cast<uint32_t>(pk) >= ps_size) continue;

            uint32_t ps_begin = ps_first[static_cast<uint32_t>(pk)];
            uint32_t ps_end;
            if (static_cast<uint32_t>(pk) + 1 < ps_size)
                ps_end = ps_first[static_cast<uint32_t>(pk) + 1];
            else
                ps_end = ps.row_count;

            if (ps_begin >= ps_end) continue;

            // Pass 1 (build side): min supplycost in region
            int64_t min_cost = INT64_MAX;
            for (uint32_t r = ps_begin; r < ps_end; ++r) {
                ++ps_build_rows_in;
                int32_t sk = ps.ps_suppkey[r];
                if (sk > 0 && static_cast<uint32_t>(sk) < max_sk && supp_in_region[static_cast<uint32_t>(sk)]) {
                    if (ps.ps_supplycost[r] < min_cost)
                        min_cost = ps.ps_supplycost[r];
                }
            }
            if (min_cost == INT64_MAX) continue;

            // Pass 2 (probe side): emit matching rows
            for (uint32_t r = ps_begin; r < ps_end; ++r) {
                ++ps_probe_rows_in;
                if (ps.ps_supplycost[r] != min_cost) continue;
                int32_t sk = ps.ps_suppkey[r];
                if (sk <= 0 || static_cast<uint32_t>(sk) >= max_sk) continue;
                if (!supp_in_region[static_cast<uint32_t>(sk)]) continue;

                ++join_rows_emitted;

                uint32_t s_row = sup.suppkey_to_row[static_cast<uint32_t>(sk)];
                uint8_t  nk    = sup.s_nationkey[s_row];

                ResultRow rr;
                rr.s_acctbal = sup.s_acctbal[s_row];
                rr.s_name    = sup.s_name[s_row];
                rr.n_name    = std::string(nat.n_name[nk]);
                rr.p_partkey = pk;
                rr.p_mfgr    = prt.p_mfgr_dict[prt.p_mfgr_code[part_row]];
                rr.s_address = sup.s_address[s_row];
                rr.s_phone   = sup.s_phone[s_row];
                rr.s_comment = sup.s_comment[s_row];
                result.push_back(std::move(rr));
            }
        }

        TRACE_COUNT("q2_part_rows_scanned",       static_cast<int64_t>(part_rows_scanned));
        TRACE_COUNT("q2_part_rows_emitted",       static_cast<int64_t>(part_rows_emitted));
        TRACE_COUNT("q2_partsupp_build_rows_in",  static_cast<int64_t>(ps_build_rows_in));
        TRACE_COUNT("q2_partsupp_probe_rows_in",  static_cast<int64_t>(ps_probe_rows_in));
        TRACE_COUNT("q2_join_rows_emitted",       static_cast<int64_t>(join_rows_emitted));
    }

    // ------------------------------------------------------------------
    // Sort
    // ------------------------------------------------------------------
    {
        PROFILE_SCOPE("q2_sort");
        TRACE_COUNT("q2_sort_rows_in",  static_cast<int64_t>(result.size()));
        std::sort(result.begin(), result.end(), [](const ResultRow& a, const ResultRow& b) {
            if (a.s_acctbal != b.s_acctbal) return a.s_acctbal > b.s_acctbal;
            if (a.n_name    != b.n_name)    return a.n_name    < b.n_name;
            if (a.s_name    != b.s_name)    return a.s_name    < b.s_name;
            return a.p_partkey < b.p_partkey;
        });
        TRACE_COUNT("q2_sort_rows_out", static_cast<int64_t>(result.size()));
    }

    // ------------------------------------------------------------------
    // Assemble output
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);
    rows.push_back({"s_acctbal","s_name","n_name","p_partkey",
                    "p_mfgr","s_address","s_phone","s_comment"});

    {
        PROFILE_SCOPE("q2_format_output");
        for (const auto& rr : result) {
            rows.push_back({
                fmt_money(rr.s_acctbal),
                rr.s_name,
                rr.n_name,
                std::to_string(rr.p_partkey),
                rr.p_mfgr,
                rr.s_address,
                rr.s_phone,
                rr.s_comment
            });
        }
    }

    TRACE_COUNT("q2_query_output_rows", static_cast<int64_t>(rows.size() - 1));

    return rows;
}

#include "query3.hpp"

#include <algorithm>
#include <cstdint>
#include <iomanip>
#include <sstream>
#include <stdexcept>
#include <string>
#include <cstdio>
#include <vector>

// SQL:
/** select l_orderkey,  
    sum(l_extendedprice*(1-l_discount)) as revenue, 
    o_orderdate,  
    o_shippriority 
FROM
    customer,  
    orders,  
    lineitem 
WHERE
    c_mktsegment = '[SEGMENT]' 
    and c_custkey = o_custkey 
    and l_orderkey = o_orderkey 
    and o_orderdate < date '[DATE]' 
    and l_shipdate > date '[DATE]' 
GROUP BY
    l_orderkey,  
    o_orderdate,  
    o_shippriority 
ORDER BY
    revenue desc,  
    o_orderdate; */

// ---------------------------------------------------------------------------
// Date helper: parse "YYYY-MM-DD" -> DATE16 (days since 1992-01-01)
// ---------------------------------------------------------------------------
static bool q3_leap(int y) { return (y % 4 == 0 && y % 100 != 0) || y % 400 == 0; }
static const int Q3_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};
static uint16_t q3_date(const std::string& s) {
    int y = std::stoi(s.substr(0, 4));
    int m = std::stoi(s.substr(5, 2));
    int d = std::stoi(s.substr(8, 2));
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q3_leap(i) ? 366 : 365;
    int lp = q3_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q3_DIM[lp][i - 1];
    return static_cast<uint16_t>(tot + (d - 1));
}

// ---------------------------------------------------------------------------
// Format helpers
// ---------------------------------------------------------------------------

// Integer scaled *100 -> "NNNN.NN" with trailing zeros stripped (keep >=2dp)
static std::string fmt_scaled_q3(int64_t v, int scale) {
    bool neg = (v < 0); if (neg) v = -v;
    int64_t div = 1; for (int i = 0; i < scale; ++i) div *= 10;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << v / div << '.' << std::setw(scale) << std::setfill('0') << v % div;
    std::string s = oss.str();
    size_t dot = s.find('.'); size_t last = s.size() - 1;
    while (last > dot + 2 && s[last] == '0') --last;
    s.resize(last + 1);
    return s;
}

// DATE16 (days since 1992-01-01) -> "YYYY-MM-DD"
static std::string fmt_date_q3(uint16_t d16) {
    static const int DIM[2][12] = {
        {31,28,31,30,31,30,31,31,30,31,30,31},
        {31,29,31,30,31,30,31,31,30,31,30,31}
    };
    int rem = static_cast<int>(d16);
    int y = 1992;
    while (true) {
        int dy = ((y % 4 == 0 && y % 100 != 0) || y % 400 == 0) ? 366 : 365;
        if (rem < dy) break;
        rem -= dy; ++y;
    }
    int lp = ((y % 4 == 0 && y % 100 != 0) || y % 400 == 0) ? 1 : 0;
    int m = 1;
    while (m <= 12 && rem >= DIM[lp][m - 1]) { rem -= DIM[lp][m - 1]; ++m; }
    char buf[12];
    std::snprintf(buf, sizeof(buf), "%04d-%02d-%02d", y, m, rem + 1);
    return std::string(buf);
}

// ---------------------------------------------------------------------------
// Result row accumulator
// ---------------------------------------------------------------------------
struct Q3Row {
    int32_t  orderkey;
    int64_t  revenue;      // scale=4: sum(ep*(100-disc)); divide by 10000 for display
    uint16_t orderdate;
    uint8_t  shippriority;
};

std::vector<std::vector<std::string>> run_q3(Database* db, const Q3Args& args) {
    if (!db) {
        throw std::runtime_error("run_q3: db is null");
    }

    const uint16_t date_cutoff = q3_date(args.DATE);

    // ------------------------------------------------------------------
    // Step 1: find mktsegment dict code for SEGMENT
    // ------------------------------------------------------------------
    const Customer& cust = db->customer;
    int seg_code = -1;
    for (int i = 0; i < (int)cust.c_mktsegment_dict.size(); ++i) {
        if (cust.c_mktsegment_dict[i] == args.SEGMENT) { seg_code = i; break; }
    }
    // If segment not found, return empty result (header only)
    if (seg_code < 0) {
        std::vector<std::vector<std::string>> rows;
        rows.push_back({"l_orderkey", "revenue", "o_orderdate", "o_shippriority"});
        return rows;
    }

    // ------------------------------------------------------------------
    // Step 2: build bitmap of custkeys matching the segment
    // ------------------------------------------------------------------
    const uint32_t max_cust = static_cast<uint32_t>(cust.custkey_to_row.size());
    std::vector<bool> seg_cust(max_cust, false);
    for (uint32_t row = 0; row < cust.row_count; ++row) {
        if (cust.c_mktsegment_code[row] == static_cast<uint8_t>(seg_code)) {
            int32_t ck = cust.c_custkey[row];
            if (ck >= 0 && static_cast<uint32_t>(ck) < max_cust)
                seg_cust[static_cast<uint32_t>(ck)] = true;
        }
    }

    // ------------------------------------------------------------------
    // Step 3: scan orders filtered by o_orderdate < date_cutoff and segment
    //         For each qualifying order, scan its lineitems for l_shipdate > date_cutoff
    // ------------------------------------------------------------------
    const Orders&   ord = db->orders;
    const Lineitem& li  = db->lineitem;

    std::vector<Q3Row> results;
    results.reserve(4096);

    const uint32_t n_orders = ord.row_count;
    for (uint32_t oi = 0; oi < n_orders; ++oi) {
        // Filter: o_orderdate < date_cutoff
        if (ord.o_orderdate[oi] >= date_cutoff) continue;
        // Filter: customer matches segment
        int32_t ck = ord.o_custkey[oi];
        if (ck < 0 || static_cast<uint32_t>(ck) >= max_cust || !seg_cust[static_cast<uint32_t>(ck)]) continue;

        int32_t ok = ord.o_orderkey[oi];

        // Locate first lineitem for this orderkey
        uint32_t li_start = (static_cast<uint32_t>(ok) < (uint32_t)li.orderkey_to_first_li.size())
                            ? li.orderkey_to_first_li[static_cast<uint32_t>(ok)]
                            : 0xFFFFFFFFu;
        if (li_start == 0xFFFFFFFFu) continue;  // no lineitems

        // Accumulate revenue from qualifying lineitems (l_shipdate > date_cutoff)
        int64_t rev = 0;
        for (uint32_t li_row = li_start;
             li_row < li.row_count && li.l_orderkey[li_row] == ok;
             ++li_row) {
            if (li.l_shipdate[li_row] <= date_cutoff) continue;
            int64_t ep   = li.l_extendedprice[li_row];
            int64_t disc = li.l_discount[li_row];
            // ep * (100 - disc): scale=4 (ep is scale=2, disc is 0..10 = disc*100 raw)
            rev += ep * (100 - disc);
        }
        if (rev == 0) continue;  // no qualifying lineitems for this order

        Q3Row r;
        r.orderkey     = ok;
        r.revenue      = rev;
        r.orderdate    = ord.o_orderdate[oi];
        r.shippriority = ord.o_shippriority[oi];
        results.push_back(r);
    }

    // ------------------------------------------------------------------
    // Step 4: sort by revenue DESC, o_orderdate ASC
    // ------------------------------------------------------------------
    std::sort(results.begin(), results.end(), [](const Q3Row& a, const Q3Row& b) {
        if (a.revenue != b.revenue) return a.revenue > b.revenue;  // DESC
        return a.orderdate < b.orderdate;                            // ASC
    });

    // ------------------------------------------------------------------
    // Step 5: assemble output rows
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(results.size() + 1);
    rows.push_back({"l_orderkey", "revenue", "o_orderdate", "o_shippriority"});

    for (const Q3Row& r : results) {
        rows.push_back({
            std::to_string(r.orderkey),
            fmt_scaled_q3(r.revenue, 4),
            fmt_date_q3(r.orderdate),
            std::to_string(static_cast<int>(r.shippriority))
        });
    }

    return rows;
}

