    }

    // ------------------------------------------------------------------
    // Step 3: orders scan (filter + join to customer bitmap)
    //         then nested lineitem scan per qualifying order
    // ------------------------------------------------------------------
    const Orders&   ord = db->orders;
    const Lineitem& li  = db->lineitem;

    std::vector<Q3Row> results;
    results.reserve(4096);

    {
        PROFILE_SCOPE("q3_orders_scan_and_lineitem_probe");
        uint64_t ord_rows_scanned   = 0;
        uint64_t ord_rows_emitted   = 0;
        uint64_t li_rows_scanned    = 0;
        uint64_t li_rows_emitted    = 0;
        uint64_t join_rows_emitted  = 0;

        const uint32_t n_orders = ord.row_count;
        // Raw pointers for tight loops
        const uint16_t* __restrict__ o_orderdate  = ord.o_orderdate.data();
        const int32_t*  __restrict__ o_custkey    = ord.o_custkey.data();
        const int32_t*  __restrict__ o_orderkey   = ord.o_orderkey.data();
        const uint8_t*  __restrict__ o_shippriority = ord.o_shippriority.data();
        const uint32_t* __restrict__ o_to_li      = ord.order_row_to_li_start.data();
        const int32_t*  __restrict__ l_orderkey   = li.l_orderkey.data();
        const uint16_t* __restrict__ l_shipdate   = li.l_shipdate.data();
        const int64_t*  __restrict__ l_extprice   = li.l_extendedprice.data();
        const uint8_t*  __restrict__ l_discount   = li.l_discount.data();
        const uint32_t li_row_count = li.row_count;

        for (uint32_t oi = 0; oi < n_orders; ++oi) {
            ++ord_rows_scanned;
            if (o_orderdate[oi] >= date_cutoff) continue;
            int32_t ck = o_custkey[oi];
            if (static_cast<uint32_t>(ck) >= max_cust || !seg_cust[static_cast<uint32_t>(ck)]) continue;
            ++ord_rows_emitted;
            int32_t ok = o_orderkey[oi];
            uint32_t li_start = o_to_li[oi];
            if (li_start == 0xFFFFFFFFu) continue;
            int64_t rev = 0;
            for (uint32_t li_row = li_start;
                 li_row < li_row_count && l_orderkey[li_row] == ok;
                 ++li_row) {
                ++li_rows_scanned;
                if (l_shipdate[li_row] <= date_cutoff) continue;
                ++li_rows_emitted;
                int64_t ep   = l_extprice[li_row];
                int64_t disc = l_discount[li_row];
                rev += ep * (100 - disc);
            }
            if (rev == 0) continue;
            ++join_rows_emitted;
            Q3Row r;
            r.orderkey     = ok;
            r.revenue      = rev;
            r.orderdate    = o_orderdate[oi];
            r.shippriority = o_shippriority[oi];
            results.push_back(r);
        }
        TRACE_COUNT("q3_orders_rows_scanned",  static_cast<int64_t>(ord_rows_scanned));
        TRACE_COUNT("q3_orders_rows_emitted",  static_cast<int64_t>(ord_rows_emitted));
        TRACE_COUNT("q3_lineitem_rows_scanned", static_cast<int64_t>(li_rows_scanned));
        TRACE_COUNT("q3_lineitem_rows_emitted", static_cast<int64_t>(li_rows_emitted));
        TRACE_COUNT("q3_join_rows_emitted",    static_cast<int64_t>(join_rows_emitted));
    }

    TRACE_COUNT("q3_agg_rows_in",      static_cast<int64_t>(results.size()));
    TRACE_COUNT("q3_groups_created",   static_cast<int64_t>(results.size()));
    TRACE_COUNT("q3_agg_rows_emitted", static_cast<int64_t>(results.size()));

    // ------------------------------------------------------------------
    // Sort: revenue DESC, o_orderdate ASC
    // ------------------------------------------------------------------
    {
        PROFILE_SCOPE("q3_sort");
        TRACE_COUNT("q3_sort_rows_in",  static_cast<int64_t>(results.size()));
        std::sort(results.begin(), results.end(), [](const Q3Row& a, const Q3Row& b) {
            if (a.revenue != b.revenue) return a.revenue > b.revenue;
            return a.orderdate < b.orderdate;
        });
        TRACE_COUNT("q3_sort_rows_out", static_cast<int64_t>(results.size()));
    }

    // ------------------------------------------------------------------
    // Assemble output rows
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(results.size() + 1);
    rows.push_back({"l_orderkey", "revenue", "o_orderdate", "o_shippriority"});

    {
        PROFILE_SCOPE("q3_format_output");
        for (const Q3Row& r : results) {
            rows.push_back({
                std::to_string(r.orderkey),
                fmt_scaled_q3(r.revenue, 4),
                fmt_date_q3(r.orderdate),
                std::to_string(static_cast<int>(r.shippriority))
            });
        }
    }

    TRACE_COUNT("q3_query_output_rows", static_cast<int64_t>(rows.size() - 1));

    return rows;
}

