// ---------------------------------------------------------------------------
// Date helper: parse "YYYY-MM-DD" -> DATE16 (days since 1992-01-01)
// ---------------------------------------------------------------------------
static bool q3_leap(int y) { return (y % 4 == 0 && y % 100 != 0) || y % 400 == 0; }
static const int Q3_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};
static uint16_t q3_date(const std::string& s) {
    int y = std::stoi(s.substr(0, 4));
    int m = std::stoi(s.substr(5, 2));
    int d = std::stoi(s.substr(8, 2));
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q3_leap(i) ? 366 : 365;
    int lp = q3_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q3_DIM[lp][i - 1];
    return static_cast<uint16_t>(tot + (d - 1));
}

// ---------------------------------------------------------------------------
// Format helpers
// ---------------------------------------------------------------------------

// Integer scaled *100 -> "NNNN.NN" with trailing zeros stripped (keep >=2dp)
static std::string fmt_scaled_q3(int64_t v, int scale) {
    bool neg = (v < 0); if (neg) v = -v;
    int64_t div = 1; for (int i = 0; i < scale; ++i) div *= 10;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << v / div << '.' << std::setw(scale) << std::setfill('0') << v % div;
    std::string s = oss.str();
    size_t dot = s.find('.'); size_t last = s.size() - 1;
    while (last > dot + 2 && s[last] == '0') --last;
    s.resize(last + 1);
    return s;
}

// DATE16 (days since 1992-01-01) -> "YYYY-MM-DD"
static std::string fmt_date_q3(uint16_t d16) {
    static const int DIM[2][12] = {
        {31,28,31,30,31,30,31,31,30,31,30,31},
        {31,29,31,30,31,30,31,31,30,31,30,31}
    };
    int rem = static_cast<int>(d16);
    int y = 1992;
    while (true) {
        int dy = ((y % 4 == 0 && y % 100 != 0) || y % 400 == 0) ? 366 : 365;
        if (rem < dy) break;
        rem -= dy; ++y;
    }
    int lp = ((y % 4 == 0 && y % 100 != 0) || y % 400 == 0) ? 1 : 0;
    int m = 1;
    while (m <= 12 && rem >= DIM[lp][m - 1]) { rem -= DIM[lp][m - 1]; ++m; }
    char buf[12];
    std::snprintf(buf, sizeof(buf), "%04d-%02d-%02d", y, m, rem + 1);
    return std::string(buf);
}

