#include "query4.hpp"

#include <algorithm>
#include <cstdint>
#include <iomanip>
#include <cstdio>
#include <sstream>
#include <stdexcept>
#include <string>
#include <vector>

// SQL:
/**
 * select
 *     o_orderpriority,
 *     count(*) as order_count
 * from
 *     orders
 * where
 *     o_orderdate >= date '[DATE]'
 *     and o_orderdate < date '[DATE]' + interval '3' month
 *     and exists (
 *         select *
 *         from lineitem
 *         where l_orderkey = o_orderkey
 *           and l_commitdate < l_receiptdate
 *     )
 * group by  o_orderpriority
 * order by  o_orderpriority;
 */

// ---------------------------------------------------------------------------
// Date helpers
// ---------------------------------------------------------------------------
static bool q4_leap(int y) {
    return (y % 4 == 0 && y % 100 != 0) || y % 400 == 0;
}
static const int Q4_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};

// Parse "YYYY-MM-DD" -> DATE16 (days since 1992-01-01)
static uint16_t q4_parse_date(const std::string& s) {
    int y = std::stoi(s.substr(0, 4));
    int m = std::stoi(s.substr(5, 2));
    int d = std::stoi(s.substr(8, 2));
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q4_leap(i) ? 366 : 365;
    int lp = q4_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q4_DIM[lp][i - 1];
    return static_cast<uint16_t>(tot + (d - 1));
}

// Add N months to a DATE16 value (calendar arithmetic)
static uint16_t q4_add_months(uint16_t d16, int months) {
    // Decode d16 -> year, month, day
    int rem = static_cast<int>(d16);
    int y = 1992;
    while (true) {
        int dy = q4_leap(y) ? 366 : 365;
        if (rem < dy) break;
        rem -= dy; ++y;
    }
    int lp = q4_leap(y) ? 1 : 0;
    int mo = 1;
    while (mo <= 12 && rem >= Q4_DIM[lp][mo - 1]) { rem -= Q4_DIM[lp][mo - 1]; ++mo; }
    int day = rem + 1;  // 1-based day

    // Add months
    mo += months;
    while (mo > 12) { mo -= 12; ++y; }
    while (mo < 1)  { mo += 12; --y; }

    // Clamp day to end of target month
    int lp2 = q4_leap(y) ? 1 : 0;
    int max_day = Q4_DIM[lp2][mo - 1];
    if (day > max_day) day = max_day;

    // Re-encode -> DATE16
    return q4_parse_date(
        std::to_string(y) + "-"
        + (mo < 10 ? "0" : "") + std::to_string(mo) + "-"
        + (day < 10 ? "0" : "") + std::to_string(day)
    );
}

// ---------------------------------------------------------------------------
// Q4 implementation
// ---------------------------------------------------------------------------
std::vector<std::vector<std::string>> run_q4(Database* db, const Q4Args& args) {
    if (!db) throw std::runtime_error("run_q4: db is null");

    // -----------------------------------------------------------------------
    // Step 1: compute date range [date_lo, date_hi)
    // -----------------------------------------------------------------------
    const uint16_t date_lo = q4_parse_date(args.DATE);
    const uint16_t date_hi = q4_add_months(date_lo, 3);

    // -----------------------------------------------------------------------
    // Step 2: determine the number of priority codes
    // -----------------------------------------------------------------------
    const Orders&   ord = db->orders;
    const Lineitem& li  = db->lineitem;

    const int n_prio = static_cast<int>(ord.o_orderpriority_dict.size());
    // count[code] = number of qualifying orders with that priority
    std::vector<int64_t> count(n_prio, 0);

    // -----------------------------------------------------------------------
    // Step 3: scan orders, filter by date range, then check EXISTS via lineitem
    // -----------------------------------------------------------------------
    const uint32_t n_orders = ord.row_count;
    const uint32_t li_size  = static_cast<uint32_t>(li.orderkey_to_first_li.size());

    for (uint32_t oi = 0; oi < n_orders; ++oi) {
        // Date filter: o_orderdate >= date_lo AND < date_hi
        const uint16_t odate = ord.o_orderdate[oi];
        if (odate < date_lo || odate >= date_hi) continue;

        const int32_t ok = ord.o_orderkey[oi];

        // EXISTS subquery: find at least one lineitem for this orderkey
        // with l_commitdate < l_receiptdate (i.e., l_commit_late bit set)
        const uint32_t uok = static_cast<uint32_t>(ok);
        if (uok >= li_size) continue;  // no lineitem index entry
        const uint32_t li_start = li.orderkey_to_first_li[uok];
        if (li_start == 0xFFFFFFFFu) continue;  // no lineitems for this order

        bool found = false;
        for (uint32_t li_row = li_start;
             li_row < li.row_count && li.l_orderkey[li_row] == ok;
             ++li_row) {
            if (li.l_commit_late.test(li_row)) {
                found = true;
                break;
            }
        }
        if (!found) continue;

        // Increment count for this priority
        const uint8_t prio_code = ord.o_orderpriority_code[oi];
        if (prio_code < static_cast<uint8_t>(n_prio)) {
            count[prio_code]++;
        }
    }

    // -----------------------------------------------------------------------
    // Step 4: collect results and sort by o_orderpriority ASC
    // -----------------------------------------------------------------------
    // Build (priority_string, count) pairs for non-zero entries
    std::vector<std::pair<std::string, int64_t>> results;
    results.reserve(n_prio);
    for (int c = 0; c < n_prio; ++c) {
        if (count[c] > 0) {
            results.push_back({ord.o_orderpriority_dict[c], count[c]});
        }
    }
    // Sort ascending by priority string (TPC-H: "1-URGENT" < "2-HIGH" < ...)
    std::sort(results.begin(), results.end(),
              [](const auto& a, const auto& b) { return a.first < b.first; });

    // -----------------------------------------------------------------------
    // Step 5: assemble output rows
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(results.size() + 1);
    rows.push_back({"o_orderpriority", "order_count"});
    for (const auto& [prio, cnt] : results) {
        rows.push_back({prio, std::to_string(cnt)});
    }
    return rows;
}

