    while (mo <= 12 && rem >= Q4_DIM[lp][mo - 1]) { rem -= Q4_DIM[lp][mo - 1]; ++mo; }
    int day = rem + 1;  // 1-based day

    // Add months
    mo += months;
    while (mo > 12) { mo -= 12; ++y; }
    while (mo < 1)  { mo += 12; --y; }

    // Clamp day to end of target month
    int lp2 = q4_leap(y) ? 1 : 0;
    int max_day = Q4_DIM[lp2][mo - 1];
    if (day > max_day) day = max_day;

    // Re-encode -> DATE16
    return q4_parse_date(
        std::to_string(y) + "-"
        + (mo < 10 ? "0" : "") + std::to_string(mo) + "-"
        + (day < 10 ? "0" : "") + std::to_string(day)
    );
}

// ---------------------------------------------------------------------------
// Q4 implementation
// ---------------------------------------------------------------------------
std::vector<std::vector<std::string>> run_q4(Database* db, const Q4Args& args) {
    if (!db) throw std::runtime_error("run_q4: db is null");

    PROFILE_SCOPE("q4_total");

    // -----------------------------------------------------------------------
    // Step 1: compute date range [date_lo, date_hi)
    // -----------------------------------------------------------------------
    const uint16_t date_lo = q4_parse_date(args.DATE);
    const uint16_t date_hi = q4_add_months(date_lo, 3);

    // -----------------------------------------------------------------------
    // Step 2: determine the number of priority codes
    // -----------------------------------------------------------------------
    const Orders&   ord = db->orders;
    const Lineitem& li  = db->lineitem;

    // -----------------------------------------------------------------------
    // Step 3: scan lineitem once to build a bitset of qualifying orderkeys.
    //         A qualifying orderkey has at least one lineitem with
    //         l_commitdate < l_receiptdate (i.e., l_commit_late bit set).
    // -----------------------------------------------------------------------
    const uint32_t ok_range = static_cast<uint32_t>(li.orderkey_to_first_li.size());
    const uint32_t n_words  = (ok_range + 63u) / 64u;
    std::vector<uint64_t> ok_bitset(n_words, 0ULL);

    {
        PROFILE_SCOPE("q4_build_ok_bitset");
        const uint32_t  li_n      = li.row_count;
        const int32_t*  ok_arr    = li.l_orderkey.data();
        const uint64_t* cl_words  = li.l_commit_late.words.data();
        uint64_t*       obs_w     = ok_bitset.data();

        // Iterate over l_commit_late 64-bits at a time; for each set bit,
        // mark that orderkey in the bitset.
        const uint32_t full_words = li_n / 64u;
        for (uint32_t w = 0; w < full_words; ++w) {
            uint64_t mask = cl_words[w];
            while (mask) {
                const uint32_t bit    = static_cast<uint32_t>(__builtin_ctzll(mask));
                const uint32_t li_row = w * 64u + bit;
                const uint32_t uok    = static_cast<uint32_t>(ok_arr[li_row]);
                obs_w[uok >> 6] |= (1ULL << (uok & 63u));
                mask &= mask - 1u;
            }
        }
        // Tail rows
        const uint32_t tail = full_words * 64u;
        for (uint32_t r = tail; r < li_n; ++r) {
            if ((cl_words[r >> 6] >> (r & 63u)) & 1ULL) {
                const uint32_t uok = static_cast<uint32_t>(ok_arr[r]);
                obs_w[uok >> 6] |= (1ULL << (uok & 63u));
            }
        }
    }

    // -----------------------------------------------------------------------
    // Step 4: scan orders, filter by date range, probe bitset for EXISTS (O(1))
    // -----------------------------------------------------------------------
    const int      n_prio  = static_cast<int>(ord.o_orderpriority_dict.size());
    const uint32_t n_orders = static_cast<uint32_t>(ord.row_count);
    std::vector<int64_t> count(n_prio, 0);

    const uint16_t* odate_arr = ord.o_orderdate.data();
    const int32_t*  okey_arr  = ord.o_orderkey.data();
    const uint8_t*  oprio_arr = ord.o_orderpriority_code.data();
    const uint64_t* obs       = ok_bitset.data();

    {
        PROFILE_SCOPE("q4_orders_scan");
        constexpr uint32_t CHUNK_SZ = 65536u;
        const uint32_t n_chunks = static_cast<uint32_t>(ord.odate_chunk_min.size());
        const uint16_t* cmin = ord.odate_chunk_min.data();
        const uint16_t* cmax = ord.odate_chunk_max.data();

        for (uint32_t chunk = 0; chunk < n_chunks; ++chunk) {
            // Zone-map skip: if chunk's max < date_lo or chunk's min >= date_hi
            if (cmax[chunk] < date_lo || cmin[chunk] >= date_hi) continue;

            const uint32_t row_start = chunk * CHUNK_SZ;
            const uint32_t row_end   = std::min(row_start + CHUNK_SZ, n_orders);
            for (uint32_t oi = row_start; oi < row_end; ++oi) {
                const uint16_t odate = odate_arr[oi];
                if (odate < date_lo || odate >= date_hi) continue;

                const uint32_t uok = static_cast<uint32_t>(okey_arr[oi]);
                // EXISTS: one bit-test
                if (uok >= ok_range || !((obs[uok >> 6] >> (uok & 63u)) & 1ULL)) continue;

                const uint8_t prio_code = oprio_arr[oi];
                if (prio_code < static_cast<uint8_t>(n_prio))
                    count[prio_code]++;
            }
        }
    }

    // -----------------------------------------------------------------------
    // Step 5: collect results and sort by o_orderpriority ASC
    // -----------------------------------------------------------------------
    std::vector<std::pair<std::string, int64_t>> results;
    {
        PROFILE_SCOPE("q4_sort");
        results.reserve(n_prio);
        // Build (priority_string, count) pairs for non-zero entries
        for (int c = 0; c < n_prio; ++c) {
            if (count[c] > 0)
                results.push_back({ord.o_orderpriority_dict[c], count[c]});
        }
        // Sort ascending by priority string (TPC-H: "1-URGENT" < "2-HIGH" < ...)
        std::sort(results.begin(), results.end(),
                  [](const auto& a, const auto& b) { return a.first < b.first; });
    }

    // -----------------------------------------------------------------------
    // Step 6: assemble output rows
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    {
        PROFILE_SCOPE("q4_format_output");
        rows.reserve(results.size() + 1);
        rows.push_back({"o_orderpriority", "order_count"});
        for (const auto& [prio, cnt] : results) {
            rows.push_back({prio, std::to_string(cnt)});
        }
    }

    TRACE_COUNT("q4_query_output_rows", static_cast<int64_t>(rows.size() - 1));

    return rows;
}

