#include "query5.hpp"

#include <algorithm>
#include <cstdint>
#include <cstdio>
#include <iomanip>
#include <sstream>
#include <stdexcept>
#include <string>
#include <vector>

// SQL:
/** select n_name,  
    sum(l_extendedprice * (1 - l_discount)) as revenue 
FROM
    customer, orders, lineitem, supplier, nation, region
WHERE
    c_custkey = o_custkey 
    and l_orderkey = o_orderkey 
    and l_suppkey = s_suppkey 
    and c_nationkey = s_nationkey 
    and s_nationkey = n_nationkey 
    and n_regionkey = r_regionkey 
    and r_name = '[REGION]' 
    and o_orderdate >= date '[DATE]' 
    and o_orderdate < date '[DATE]' + interval '1' year 
GROUP BY
    n_name 
ORDER BY
    revenue desc; */

// ---------------------------------------------------------------------------
// Date helpers (days since 1992-01-01)
// ---------------------------------------------------------------------------
static bool q5_leap(int y) {
    return (y % 4 == 0 && y % 100 != 0) || y % 400 == 0;
}
static const int Q5_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};

static uint16_t q5_parse_date(const std::string& s) {
    int y = std::stoi(s.substr(0, 4));
    int m = std::stoi(s.substr(5, 2));
    int d = std::stoi(s.substr(8, 2));
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q5_leap(i) ? 366 : 365;
    int lp = q5_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q5_DIM[lp][i - 1];
    return static_cast<uint16_t>(tot + (d - 1));
}

// Add N years to a DATE16 value
static uint16_t q5_add_years(uint16_t d16, int years) {
    // Decode
    int rem = static_cast<int>(d16);
    int y = 1992;
    while (true) {
        int dy = q5_leap(y) ? 366 : 365;
        if (rem < dy) break;
        rem -= dy; ++y;
    }
    int lp = q5_leap(y) ? 1 : 0;
    int mo = 1;
    while (mo <= 12 && rem >= Q5_DIM[lp][mo - 1]) { rem -= Q5_DIM[lp][mo - 1]; ++mo; }
    int day = rem + 1;

    // Add years
    y += years;
    // Clamp day for leap year boundary (Feb 29 -> Feb 28)
    int lp2 = q5_leap(y) ? 1 : 0;
    int max_day = Q5_DIM[lp2][mo - 1];
    if (day > max_day) day = max_day;

    // Re-encode
    char buf[12];
    std::snprintf(buf, sizeof(buf), "%04d-%02d-%02d", y, mo, day);
    return q5_parse_date(std::string(buf));
}

// ---------------------------------------------------------------------------
// Format: int64 scale=4 intermediate -> decimal string, exactly 2 decimal places
// display_value = intermediate / 10000  (ep is scale=2, (100-disc) adds 2 more)
// ---------------------------------------------------------------------------
static std::string q5_fmt_revenue(int64_t v4) {
    bool neg = (v4 < 0); if (neg) v4 = -v4;
    // Truncate to 2 decimal places (matches DuckDB DECIMAL(15,2) output)
    int64_t whole = v4 / 10000;
    int64_t frac2 = (v4 % 10000) / 100;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << whole << '.' << std::setw(2) << std::setfill('0') << frac2;
    return oss.str();
}

// ---------------------------------------------------------------------------
// Q5 implementation
// ---------------------------------------------------------------------------
std::vector<std::vector<std::string>> run_q5(Database* db, const Q5Args& args) {
    if (!db) throw std::runtime_error("run_q5: db is null");

    // ------------------------------------------------------------------
    // Step 1: resolve region name -> regionkey
    // ------------------------------------------------------------------
    const Region& reg = db->region;
    int region_key = reg.name_to_key(args.REGION);
    if (region_key < 0) {
        std::vector<std::vector<std::string>> rows;
        rows.push_back({"n_name", "revenue"});
        return rows;
    }

    // ------------------------------------------------------------------
    // Step 2: collect nations in this region
    //         Build nationkey -> slot_index (0xFF = not in region)
    // ------------------------------------------------------------------
    const Nation& nat = db->nation;
    uint8_t nation_slot[25];
    std::fill(nation_slot, nation_slot + 25, 0xFFu);
    std::vector<std::string> slot_to_name;
    slot_to_name.reserve(5);

    for (int nk = 0; nk < 25; ++nk) {
        if (nat.n_regionkey[nk] == static_cast<uint8_t>(region_key)) {
            nation_slot[nk] = static_cast<uint8_t>(slot_to_name.size());
            slot_to_name.push_back(std::string(nat.n_name[nk]));
        }
    }
    const int n_nations = static_cast<int>(slot_to_name.size());
    if (n_nations == 0) {
        std::vector<std::vector<std::string>> rows;
        rows.push_back({"n_name", "revenue"});
        return rows;
    }

    // Revenue accumulator per nation slot (scale=4: ep_scale2 * (100-disc))
    std::vector<int64_t> revenue(n_nations, 0LL);

    // ------------------------------------------------------------------
    // Step 3: date range  [date_lo, date_hi)
    // ------------------------------------------------------------------
    const uint16_t date_lo = q5_parse_date(args.DATE);
    const uint16_t date_hi = q5_add_years(date_lo, 1);

    // ------------------------------------------------------------------
    // Step 4: short-circuit refs to DB tables
    // ------------------------------------------------------------------
    const Supplier& sup        = db->supplier;
    const Customer& cust       = db->customer;
    const Orders&   ord        = db->orders;
    const Lineitem& li         = db->lineitem;

    const uint32_t sup_map_sz  = static_cast<uint32_t>(sup.suppkey_to_row.size());
    const uint32_t cust_map_sz = static_cast<uint32_t>(cust.custkey_to_row.size());
    const uint32_t li_idx_sz   = static_cast<uint32_t>(li.orderkey_to_first_li.size());

    // ------------------------------------------------------------------
    // Step 5: scan orders filtered by date range
    // ------------------------------------------------------------------
    const uint32_t n_orders = ord.row_count;
    for (uint32_t oi = 0; oi < n_orders; ++oi) {
        const uint16_t odate = ord.o_orderdate[oi];
        if (odate < date_lo || odate >= date_hi) continue;

        // Resolve customer nationkey and check region membership
        const int32_t ck = ord.o_custkey[oi];
        if (ck < 0 || static_cast<uint32_t>(ck) >= cust_map_sz) continue;
        const uint32_t crow = cust.custkey_to_row[static_cast<uint32_t>(ck)];
        if (crow == 0xFFFFFFFFu) continue;
        const uint8_t c_nk   = cust.c_nationkey[crow];
        const uint8_t c_slot = nation_slot[c_nk];
        if (c_slot == 0xFFu) continue;  // customer not in target region

        // Locate lineitems for this order
        const int32_t ok  = ord.o_orderkey[oi];
        const uint32_t uok = static_cast<uint32_t>(ok);
        if (uok >= li_idx_sz) continue;
        const uint32_t li_start = li.orderkey_to_first_li[uok];
        if (li_start == 0xFFFFFFFFu) continue;

        // Walk lineitems; keep only those where s_nationkey == c_nk
        for (uint32_t lr = li_start;
             lr < li.row_count && li.l_orderkey[lr] == ok;
             ++lr) {
            const int32_t sk = li.l_suppkey[lr];
            if (sk < 0 || static_cast<uint32_t>(sk) >= sup_map_sz) continue;
            const uint32_t srow = sup.suppkey_to_row[static_cast<uint32_t>(sk)];
            if (srow == 0xFFFFFFFFu) continue;
            if (sup.s_nationkey[srow] != c_nk) continue;

            // Accumulate: ep * (100 - disc)  [scale=4]
            revenue[c_slot] += li.l_extendedprice[lr] * (int64_t)(100 - li.l_discount[lr]);
        }
    }

    // ------------------------------------------------------------------
    // Step 6: collect non-zero results, sort by revenue DESC
    // ------------------------------------------------------------------
    std::vector<std::pair<std::string, int64_t>> results;
    results.reserve(n_nations);
    for (int s = 0; s < n_nations; ++s) {
        if (revenue[s] > 0)
            results.push_back({slot_to_name[s], revenue[s]});
    }
    std::sort(results.begin(), results.end(),
              [](const auto& a, const auto& b) { return a.second > b.second; });

    // ------------------------------------------------------------------
    // Step 7: assemble output
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(results.size() + 1);
    rows.push_back({"n_name", "revenue"});
    for (const auto& [name, rev] : results) {
        rows.push_back({name, q5_fmt_revenue(rev)});
    }

    return rows;
}

