#include "query6.hpp"

#include <algorithm>
#include <cstdint>
#include <iomanip>
#include <sstream>
#include <stdexcept>
#include <string>
#include <cmath>
#include <vector>

// SQL:
/**
select
    sum(l_extendedprice*l_discount) as revenue
from
    lineitem
where
    l_shipdate >= date '[DATE]'
    and l_shipdate < date '[DATE]' + interval '1' year
    and l_discount between [DISCOUNT] - 0.01 and [DISCOUNT] + 0.01
    and l_quantity < [QUANTITY];
 */

// ---------------------------------------------------------------------------
// Date helpers (days since 1992-01-01 = DATE16 encoding)
// ---------------------------------------------------------------------------
static const int Q6_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};
static bool q6_leap(int y) { return (y%4==0&&y%100!=0)||y%400==0; }

static uint16_t q6_parse_date(const std::string& s) {
    // Parse "YYYY-MM-DD" -> days since 1992-01-01
    int y = std::stoi(s.substr(0,4));
    int m = std::stoi(s.substr(5,2));
    int d = std::stoi(s.substr(8,2));
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q6_leap(i) ? 366 : 365;
