// ---------------------------------------------------------------------------
// Format helper: scaled integer -> decimal string, trailing zeros stripped
// but at least 2 decimal places kept.
// ---------------------------------------------------------------------------
static std::string fmt_scaled(int64_t v, int scale) {
    bool neg = (v < 0);
    if (neg) v = -v;
    int64_t div = 1;
    for (int i = 0; i < scale; ++i) div *= 10;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << v/div << '.' << std::setw(scale) << std::setfill('0') << v%div;
    std::string s = oss.str();
    size_t dot  = s.find('.');
    size_t last = s.size() - 1;
    while (last > dot + 2 && s[last] == '0') --last;
    s.resize(last + 1);
    return s;
}

std::vector<std::vector<std::string>> run_q6(Database* db, const Q6Args& args) {
    if (!db) throw std::runtime_error("run_q6: db is null");

    // -----------------------------------------------------------------------
    // Parse parameters
    // -----------------------------------------------------------------------
    uint16_t date_lo = q6_parse_date(args.DATE);   // inclusive lower bound
    uint16_t date_hi = q6_add_one_year(date_lo);    // exclusive upper bound

    // DISCOUNT is a decimal like "0.09"; stored as integer 0-10 (x100).
    // e.g. "0.09" -> disc_center=9; range BETWEEN disc-0.01 AND disc+0.01
    // -> stored codes BETWEEN disc_center-1 AND disc_center+1 (inclusive).
    double discount_d = std::stod(args.DISCOUNT);
    int disc_center = static_cast<int>(std::round(discount_d * 100.0));
    int disc_lo = disc_center - 1;  // inclusive
    int disc_hi = disc_center + 1;  // inclusive
    if (disc_lo < 0)  disc_lo = 0;
    if (disc_hi > 10) disc_hi = 10;

    // QUANTITY: l_quantity < QUANTITY (l_quantity stored as 1..50 whole number, uint8)
    uint8_t qty_limit = static_cast<uint8_t>(std::stoi(args.QUANTITY));

    // -----------------------------------------------------------------------
    // Scan lineitem: accumulate sum(extendedprice * discount)
    //
    // Both l_extendedprice and l_discount are scaled x100:
    //   actual revenue = sum(ep_raw * disc_raw) / 10000
    //   -> accumulate product as int64, format with 4 decimal places.
    // -----------------------------------------------------------------------
    const Lineitem& li = db->lineitem;
    const uint32_t  n  = li.row_count;

    const uint16_t* sd = li.l_shipdate.data();
    const uint8_t*  dc = li.l_discount.data();
    const uint8_t*  qt = li.l_quantity.data();
    const int64_t*  ep = li.l_extendedprice.data();

    // Use zone-maps to skip chunks of 65536 rows quickly.
    constexpr uint32_t CHUNK = 65536;
    const uint32_t num_chunks = (uint32_t)li.shipdate_chunk_min.size();

    int64_t revenue_x10000 = 0;

    for (uint32_t c = 0; c < num_chunks; ++c) {
        // Skip chunk if shipdate range doesn't overlap [date_lo, date_hi)
        if (li.shipdate_chunk_max[c] < date_lo) continue;
        if (li.shipdate_chunk_min[c] >= date_hi) continue;

        uint32_t row_start = c * CHUNK;
        uint32_t row_end   = std::min(row_start + CHUNK, n);

        for (uint32_t i = row_start; i < row_end; ++i) {
            uint16_t shipdate = sd[i];
            if (shipdate < date_lo || shipdate >= date_hi) continue;

            uint8_t disc = dc[i];
            if (disc < (uint8_t)disc_lo || disc > (uint8_t)disc_hi) continue;

            if (qt[i] >= qty_limit) continue;

            // Both ep and disc are x100; product is x10000
            revenue_x10000 += ep[i] * static_cast<int64_t>(disc);
        }
    }

    // -----------------------------------------------------------------------
    // Assemble result
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.push_back({"revenue"});
    rows.push_back({fmt_scaled(revenue_x10000, 4)});
    return rows;
}

