        else if (snk == static_cast<uint8_t>(nk2)) suppkey_tag[static_cast<uint32_t>(sk)] = 2;
    }

    // ------------------------------------------------------------------
    // Step 4: build orderkey -> customer-nation-tag lookup (fused join)
    //
    //   Pre-materialise a single flat byte array indexed by orderkey so
    //   the hot lineitem scan needs only ONE random access (instead of
    //   the original two: orderkey_to_row then o_custkey then custkey_tag).
    //
    //   Build: customer nation tags, then walk orders table once to stamp
    //   each orderkey with its customer's nation tag.
    // ------------------------------------------------------------------
    const Customer& cust    = db->customer;
    const uint32_t  cust_sz = static_cast<uint32_t>(cust.custkey_to_row.size());
    const Orders&   ord     = db->orders;
    const uint32_t  ok_sz   = static_cast<uint32_t>(ord.orderkey_to_row.size());

    // custkey -> nation-tag (small, fits in cache)
    std::vector<uint8_t> custkey_tag(cust_sz, 0);
    for (uint32_t row = 0; row < cust.row_count; ++row) {
        int32_t ck = cust.c_custkey[row];
        if (ck < 0 || static_cast<uint32_t>(ck) >= cust_sz) continue;
        uint8_t cnk = cust.c_nationkey[row];
        if      (cnk == static_cast<uint8_t>(nk1)) custkey_tag[static_cast<uint32_t>(ck)] = 1;
        else if (cnk == static_cast<uint8_t>(nk2)) custkey_tag[static_cast<uint32_t>(ck)] = 2;
    }

    // orderkey -> customer-nation-tag (single flat lookup for the hot lineitem scan)
    std::vector<uint8_t> orderkey_custtag(ok_sz, 0);
    for (uint32_t ord_row = 0; ord_row < ord.row_count; ++ord_row) {
        int32_t ck = ord.o_custkey[ord_row];
        if (ck < 0 || static_cast<uint32_t>(ck) >= cust_sz) continue;
        uint8_t ctag = custkey_tag[static_cast<uint32_t>(ck)];
        if (ctag == 0) continue;
        int32_t ok_val = ord.o_orderkey[ord_row];
        if (ok_val < 0 || static_cast<uint32_t>(ok_val) >= ok_sz) continue;
        orderkey_custtag[static_cast<uint32_t>(ok_val)] = ctag;
    }

    // ------------------------------------------------------------------
    // Step 5: scan lineitems (with zone-map pruning)
    //
    //   revenue[stag-1][ctag-1][year_idx]:
    //     stag in {1,2}, ctag in {1,2}, year_idx in {0=1995, 1=1996}
    //   Only valid combinations: (stag=1,ctag=2) or (stag=2,ctag=1)
    // ------------------------------------------------------------------
    int64_t revenue[2][2][2] = {};
    int64_t result_row_count = 0;

    {
    PROFILE_SCOPE("q7_lineitem_scan");

    const Lineitem& li       = db->lineitem;
    const uint32_t  n_li     = li.row_count;

    constexpr uint32_t CHUNK = 65536;
    const uint32_t num_chunks = static_cast<uint32_t>(li.shipdate_chunk_min.size());

    for (uint32_t ch = 0; ch < num_chunks; ++ch) {
        if (li.shipdate_chunk_max[ch] < date_lo ||
            li.shipdate_chunk_min[ch] > date_hi) {
            continue;
        }

        uint32_t row_start = ch * CHUNK;
        uint32_t row_end   = std::min(row_start + CHUNK, n_li);

        for (uint32_t li_row = row_start; li_row < row_end; ++li_row) {
            uint16_t shipdate = li.l_shipdate[li_row];
            if (shipdate < date_lo || shipdate > date_hi) continue;

            // Supplier nation tag (small array, likely cached)
            int32_t sk = li.l_suppkey[li_row];
            if (sk < 0 || static_cast<uint32_t>(sk) >= sup_sz) continue;
            uint8_t stag = suppkey_tag[static_cast<uint32_t>(sk)];
            if (stag == 0) continue;

            // Order -> customer nation tag: single flat array lookup
            int32_t ok_val = li.l_orderkey[li_row];
            if (ok_val < 0 || static_cast<uint32_t>(ok_val) >= ok_sz) continue;
            uint8_t ctag = orderkey_custtag[static_cast<uint32_t>(ok_val)];
            if (ctag == 0) continue;

            // Directions: (supp nk1, cust nk2) or (supp nk2, cust nk1)
            if (stag == ctag) continue;

            int year_idx = q7_year(shipdate) - 1995;
            // year_idx should be 0 or 1 given date range, but guard anyway
            if (year_idx < 0 || year_idx > 1) continue;

            revenue[stag - 1][ctag - 1][year_idx] +=
                static_cast<int64_t>(li.l_extendedprice[li_row]) * (int64_t)(100 - li.l_discount[li_row]);
        }
    }
    } // end q7_lineitem_scan

    // ------------------------------------------------------------------
    // Step 6: collect results and sort
    // ------------------------------------------------------------------
    const std::string name1(nat.n_name[nk1]);
    const std::string name2(nat.n_name[nk2]);

    struct ResultRow {
        std::string supp_nation;
        std::string cust_nation;
        int         l_year;
        int64_t     revenue_raw;
    };
    std::vector<ResultRow> results;
    results.reserve(4);

    // Direction (s=nk1, c=nk2): stag=1 -> index [0], ctag=2 -> index [1]
    for (int yi = 0; yi <= 1; ++yi) {
        int64_t rev = revenue[0][1][yi];
        if (rev != 0)
            results.push_back({name1, name2, 1995 + yi, rev});
    }
    // Direction (s=nk2, c=nk1): stag=2 -> index 1, ctag=1 -> index 0
    for (int yi = 0; yi <= 1; ++yi) {
        int64_t rev = revenue[1][0][yi];
        if (rev != 0)
            results.push_back({name2, name1, 1995 + yi, rev});
    }

    std::sort(results.begin(), results.end(), [](const ResultRow& a, const ResultRow& b) {
        if (a.supp_nation != b.supp_nation) return a.supp_nation < b.supp_nation;
        if (a.cust_nation != b.cust_nation) return a.cust_nation < b.cust_nation;
        return a.l_year < b.l_year;
    });

    // ------------------------------------------------------------------
    // Step 7: assemble output rows
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    {
    PROFILE_SCOPE("q7_format_output");
    rows.reserve(results.size() + 1);
    rows.push_back({"supp_nation", "cust_nation", "l_year", "revenue"});
    for (const ResultRow& r : results) {
        rows.push_back({
            r.supp_nation,
            r.cust_nation,
            std::to_string(r.l_year),
            q7_fmt_revenue(r.revenue_raw)
        });
    }
    result_row_count = static_cast<int64_t>(rows.size() - 1);
    } // end q7_format_output

    TRACE_COUNT("q7_agg_groups",        static_cast<int64_t>(results.size()));
    TRACE_COUNT("q7_query_output_rows", result_row_count);

    return rows;
}

#include "query8.hpp"

#include <algorithm>
#include <cstdint>
#include <cstdio>
#include <sstream>
#include <stdexcept>
#include <string>
#include <vector>
#include <unordered_map>

// SQL:
/** select
    o_year,
    sum(case
        when nation = '[NATION]'
        then volume
        else 0
    end) / sum(volume) as mkt_share
from (
    select
        extract(year from o_orderdate) as o_year,
        l_extendedprice * (1-l_discount) as volume,
        n2.n_name as nation
    from
        part,
        supplier,
        lineitem,
        orders,
        customer,
        nation n1,
        nation n2,
        region
    where
        p_partkey = l_partkey
        and s_suppkey = l_suppkey
        and l_orderkey = o_orderkey
        and o_custkey = c_custkey
        and c_nationkey = n1.n_nationkey
        and n1.n_regionkey = r_regionkey
        and r_name = '[REGION]'
        and s_nationkey = n2.n_nationkey
        and o_orderdate between date '1995-01-01' and date '1996-12-31'
        and p_type = '[TYPE]'
    ) as all_nations
group by
    o_year
order by
    o_year; */

// ---------------------------------------------------------------------------
// Date helpers (days since 1992-01-01 = DATE16 encoding)
// ---------------------------------------------------------------------------
static bool q8_leap(int y) {
    return (y % 4 == 0 && y % 100 != 0) || y % 400 == 0;
}
static const int Q8_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};
static uint16_t q8_parse_date(const char* s) {
    // "YYYY-MM-DD"
    int y = (s[0]-'0')*1000 + (s[1]-'0')*100 + (s[2]-'0')*10 + (s[3]-'0');
    int m = (s[5]-'0')*10  + (s[6]-'0');
    int d = (s[8]-'0')*10  + (s[9]-'0');
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q8_leap(i) ? 366 : 365;
    int lp = q8_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q8_DIM[lp][i - 1];
    return static_cast<uint16_t>(tot + (d - 1));
}

// Decode DATE16 -> calendar year
static int q8_year(uint16_t d16) {
    int rem = static_cast<int>(d16);
    int y = 1992;
    while (true) {
        int dy = q8_leap(y) ? 366 : 365;
        if (rem < dy) break;
        rem -= dy; ++y;
    }
    return y;
}

// ---------------------------------------------------------------------------
// Format mkt_share as a decimal ratio with 2 decimal places.
// volume accumulator is scale=4: ep_scale2 * (100-disc).
// mkt_share = num / den  (both scale=4, so units cancel).
// DuckDB returns this as a double; output with full double precision
// (up to 15 significant digits, trailing zeros stripped).
// ---------------------------------------------------------------------------
static std::string q8_fmt_share(int64_t num, int64_t den) {
    if (den == 0) return "0.00";
    double ratio = static_cast<double>(num) / static_cast<double>(den);
    char buf[32];
    // Use enough precision so the validator can round-trip the double correctly.
    // "%.15g" gives up to 15 significant digits and drops trailing zeros.
    std::snprintf(buf, sizeof(buf), "%.15g", ratio);
    return std::string(buf);
}

std::vector<std::vector<std::string>> run_q8(Database* db, const Q8Args& args) {
    if (!db) {
        throw std::runtime_error("run_q8: db is null");
    }

    // ------------------------------------------------------------------
    // Step 1: resolve REGION name -> regionkey
    // ------------------------------------------------------------------
    const Region& reg = db->region;
    int region_key = reg.name_to_key(args.REGION);

    std::vector<std::vector<std::string>> empty_result;
    empty_result.push_back({"o_year", "mkt_share"});

    if (region_key < 0) return empty_result;

    // ------------------------------------------------------------------
    // Step 2: resolve NATION name -> nationkey (the target nation for CASE)
    // ------------------------------------------------------------------
    const Nation& nat = db->nation;
    int target_nk = nat.name_to_key(args.NATION);
    // target_nk may be -1 if NATION is unknown; numerator accumulator will stay 0

    // ------------------------------------------------------------------
    // Step 3: resolve TYPE -> type_code in Part dictionary (exact match)
    // ------------------------------------------------------------------
    const Part& part = db->part;
    int type_code = -1;
    for (int tc = 0; tc < static_cast<int>(part.p_type_dict.size()); ++tc) {
        if (part.p_type_dict[tc] == args.TYPE) {
            type_code = tc;
            break;
        }
    }
    if (type_code < 0) return empty_result;

    // ------------------------------------------------------------------
    // Step 4: build partkey_matches[] — direct-addressed boolean array
    //   1 if part has the matching type, 0 otherwise
    // ------------------------------------------------------------------
    const uint32_t partkey_map_sz = static_cast<uint32_t>(part.partkey_to_row.size());
    std::vector<uint8_t> partkey_matches(partkey_map_sz, 0);
    for (uint32_t row = 0; row < part.row_count; ++row) {
        if (part.p_type_code[row] == static_cast<uint16_t>(type_code)) {
            int32_t pk = part.p_partkey[row];
            if (pk > 0 && static_cast<uint32_t>(pk) < partkey_map_sz)
                partkey_matches[static_cast<uint32_t>(pk)] = 1;
        }
    }

    // ------------------------------------------------------------------
    // Step 5: determine which nation keys belong to the target region (n1 join)
    // ------------------------------------------------------------------
    uint8_t nation_in_region[25] = {};
    for (int nk = 0; nk < 25; ++nk) {
        if (nat.n_regionkey[nk] == static_cast<uint8_t>(region_key))
            nation_in_region[nk] = 1;
    }

    // ------------------------------------------------------------------
    // Step 6: build custkey_in_region[] — direct-addressed boolean array
    //   1 if customer's nation is in the target region
    // ------------------------------------------------------------------
    const Customer& cust        = db->customer;
    const uint32_t  cust_map_sz = static_cast<uint32_t>(cust.custkey_to_row.size());
    std::vector<uint8_t> custkey_in_region(cust_map_sz, 0);
    for (uint32_t row = 0; row < cust.row_count; ++row) {
        int32_t ck = cust.c_custkey[row];
        if (ck <= 0 || static_cast<uint32_t>(ck) >= cust_map_sz) continue;
        if (nation_in_region[cust.c_nationkey[row]])
            custkey_in_region[static_cast<uint32_t>(ck)] = 1;
    }

    // ------------------------------------------------------------------
    // Step 7: build suppkey_nk[] — direct-addressed supplier nationkey array
    //   0xFF = absent/unknown
    // ------------------------------------------------------------------
    const Supplier& sup        = db->supplier;
    const uint32_t  sup_map_sz = static_cast<uint32_t>(sup.suppkey_to_row.size());
    std::vector<uint8_t> suppkey_nk(sup_map_sz, 0xFFu);
    for (uint32_t row = 0; row < sup.row_count; ++row) {
        int32_t sk = sup.s_suppkey[row];
        if (sk <= 0 || static_cast<uint32_t>(sk) >= sup_map_sz) continue;
        suppkey_nk[static_cast<uint32_t>(sk)] = sup.s_nationkey[row];
    }

    // ------------------------------------------------------------------
    // Step 8: fixed order-date range (inclusive): 1995-01-01 .. 1996-12-31
    // ------------------------------------------------------------------
    const uint16_t odate_lo = q8_parse_date("1995-01-01");
    const uint16_t odate_hi = q8_parse_date("1996-12-31");

    // ------------------------------------------------------------------
    // Step 9: accumulators for 2 years (yi=0 → 1995, yi=1 → 1996)
    //   vol_target[yi] = sum of volume where s_nationkey == target_nk
    //   vol_total[yi]  = sum of all qualifying volume
    // ------------------------------------------------------------------
    int64_t vol_target[2] = {0, 0};
    int64_t vol_total[2]  = {0, 0};

    // ------------------------------------------------------------------
    // Step 10: outer loop: orders filtered by date range
    //          inner loop: lineitems of that order, filtered by part type
    // ------------------------------------------------------------------
    const Orders&   ord       = db->orders;
    const Lineitem& li        = db->lineitem;
    const uint32_t  n_orders  = ord.row_count;
    const uint32_t  li_idx_sz = static_cast<uint32_t>(li.orderkey_to_first_li.size());

    for (uint32_t oi = 0; oi < n_orders; ++oi) {
        const uint16_t odate = ord.o_orderdate[oi];
        if (odate < odate_lo || odate > odate_hi) continue;

        // year index: 0=1995, 1=1996
        const int yr = q8_year(odate);
        const int yi = yr - 1995;
        if (yi < 0 || yi > 1) continue;

        // Customer must belong to a nation in the target region
        const int32_t ck = ord.o_custkey[oi];
        if (ck <= 0 || static_cast<uint32_t>(ck) >= cust_map_sz) continue;
        if (!custkey_in_region[static_cast<uint32_t>(ck)]) continue;

        // Walk this order's lineitems (stored sorted by orderkey)
        const int32_t  ok     = ord.o_orderkey[oi];
        const uint32_t uok    = static_cast<uint32_t>(ok);
        if (uok >= li_idx_sz) continue;
        const uint32_t li_start = li.orderkey_to_first_li[uok];
        if (li_start == 0xFFFFFFFFu) continue;

        for (uint32_t lr = li_start;
             lr < li.row_count && li.l_orderkey[lr] == ok;
             ++lr) {

            // p_type filter via pre-built boolean array
            const int32_t pk = li.l_partkey[lr];
            if (pk <= 0 || static_cast<uint32_t>(pk) >= partkey_map_sz) continue;
            if (!partkey_matches[static_cast<uint32_t>(pk)]) continue;

            // Supplier nationkey (n2 join)
            const int32_t sk = li.l_suppkey[lr];
            if (sk <= 0 || static_cast<uint32_t>(sk) >= sup_map_sz) continue;
            const uint8_t snk = suppkey_nk[static_cast<uint32_t>(sk)];
            if (snk == 0xFFu) continue;

            // volume = ep * (100 - disc)  [scale=4: ep is scale=2, factor (100-disc) adds 2]
            const int64_t vol =
                li.l_extendedprice[lr] * static_cast<int64_t>(100 - li.l_discount[lr]);

            vol_total[yi] += vol;
            if (static_cast<int>(snk) == target_nk)
                vol_target[yi] += vol;
        }
    }

    // ------------------------------------------------------------------
    // Step 11: emit one row per year that has qualifying data (ordered by year)
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.push_back({"o_year", "mkt_share"});

    for (int yi = 0; yi <= 1; ++yi) {
        if (vol_total[yi] > 0) {
            rows.push_back({
                std::to_string(1995 + yi),
                q8_fmt_share(vol_target[yi], vol_total[yi])
            });
        }
    }

    return rows;
}

