    // Step 6: build custkey_in_region[] — direct-addressed boolean array
    //   1 if customer's nation is in the target region
    // ------------------------------------------------------------------
    const Customer& cust        = db->customer;
    const uint32_t  cust_map_sz = static_cast<uint32_t>(cust.custkey_to_row.size());
    std::vector<uint8_t> custkey_in_region(cust_map_sz, 0);
    int64_t cust_in_region = 0;
    for (uint32_t row = 0; row < cust.row_count; ++row) {
        int32_t ck = cust.c_custkey[row];
        if (ck <= 0 || static_cast<uint32_t>(ck) >= cust_map_sz) continue;
        if (nation_in_region[cust.c_nationkey[row]]) {
            custkey_in_region[static_cast<uint32_t>(ck)] = 1;
            ++cust_in_region;
        }
    }
    TRACE_COUNT("q8_cust_in_region", cust_in_region);

    // ------------------------------------------------------------------
    // Step 7: build suppkey_nk[] — direct-addressed supplier nationkey array
    //   0xFF = absent/unknown
    // ------------------------------------------------------------------
    const Supplier& sup        = db->supplier;
    const uint32_t  sup_map_sz = static_cast<uint32_t>(sup.suppkey_to_row.size());
    std::vector<uint8_t> suppkey_nk(sup_map_sz, 0xFFu);
    for (uint32_t row = 0; row < sup.row_count; ++row) {
        int32_t sk = sup.s_suppkey[row];
        if (sk <= 0 || static_cast<uint32_t>(sk) >= sup_map_sz) continue;
        suppkey_nk[static_cast<uint32_t>(sk)] = sup.s_nationkey[row];
    }
    TRACE_COUNT("q8_supplier_rows", static_cast<int64_t>(sup.row_count));

    // ------------------------------------------------------------------
    // Step 8: fixed order-date range (inclusive): 1995-01-01 .. 1996-12-31
    // ------------------------------------------------------------------
    const uint16_t odate_lo = q8_parse_date("1995-01-01");
    const uint16_t odate_hi = q8_parse_date("1996-12-31");

    // ------------------------------------------------------------------
    // Step 9: (inline order lookup in lineitem scan)
    // ------------------------------------------------------------------

    // ------------------------------------------------------------------
    // Step 10: accumulators for 2 years (yi=0 → 1995, yi=1 → 1996)
    //   vol_target[yi] = sum of volume where s_nationkey == target_nk
    //   vol_total[yi]  = sum of all qualifying volume
    // ------------------------------------------------------------------
    int64_t vol_target[2] = {0, 0};
    int64_t vol_total[2]  = {0, 0};

    int64_t result_row_count = 0;

    {
    PROFILE_SCOPE("q8_lineitem_scan");
    int64_t li_rows_scanned   = 0;
    int64_t li_part_type_pass = 0;
    int64_t li_order_pass     = 0;
    int64_t li_cust_pass      = 0;
    int64_t li_supp_pass      = 0;
    int64_t li_emitted        = 0;
    int64_t li_target_nation  = 0;

    // ------------------------------------------------------------------
    // Step 11: Scan lineitem as outermost loop (follows DuckDB plan)
    //   Filter: partkey_matches -> order date range -> custkey_in_region
    //           -> accumulate volume grouped by year
    // ------------------------------------------------------------------
    const Orders&   ord       = db->orders;
    const Lineitem& li        = db->lineitem;
    const uint32_t  n_li      = li.row_count;

    // Need orderkey -> row index in orders for fast date/custkey lookup
    const uint32_t ord_key_sz = static_cast<uint32_t>(ord.orderkey_to_row.size());

    for (uint32_t lr = 0; lr < n_li; ++lr) {
        ++li_rows_scanned;

        // Filter 1: partkey must match p_type
        const int32_t pk = li.l_partkey[lr];
        if (pk <= 0 || static_cast<uint32_t>(pk) >= partkey_map_sz) continue;
        if (!partkey_matches[static_cast<uint32_t>(pk)]) continue;
        ++li_part_type_pass;

        // Filter 2: order date range via orderkey -> orders row
        const int32_t  ok  = li.l_orderkey[lr];
        const uint32_t uok = static_cast<uint32_t>(ok);
        if (uok >= ord_key_sz) continue;
        const uint32_t oi = ord.orderkey_to_row[uok];
        if (oi == 0xFFFFFFFFu) continue;

        const uint16_t odate = ord.o_orderdate[oi];
        if (odate < odate_lo || odate > odate_hi) continue;
        ++li_order_pass;

        // year index: 0=1995, 1=1996
        const int yi = q8_year(odate) - 1995;
        if (yi < 0 || yi > 1) continue;

        // Filter 3: custkey must belong to a nation in the target region
        const int32_t ck = ord.o_custkey[oi];
        if (ck <= 0 || static_cast<uint32_t>(ck) >= cust_map_sz) continue;
        if (!custkey_in_region[static_cast<uint32_t>(ck)]) continue;
        ++li_cust_pass;

        // Filter 4: Supplier nationkey (n2 join)
        const int32_t sk = li.l_suppkey[lr];
        if (sk <= 0 || static_cast<uint32_t>(sk) >= sup_map_sz) continue;
        const uint8_t snk = suppkey_nk[static_cast<uint32_t>(sk)];
        if (snk == 0xFFu) continue;
        ++li_supp_pass;

        // volume = ep * (100 - disc)  [scale=4]
        const int64_t vol =
            li.l_extendedprice[lr] * static_cast<int64_t>(100 - li.l_discount[lr]);

        vol_total[yi] += vol;
        ++li_emitted;
        if (static_cast<int>(snk) == target_nk) {
            vol_target[yi] += vol;
            ++li_target_nation;
        }
    }

    TRACE_COUNT("q8_li_rows_scanned",   li_rows_scanned);
    TRACE_COUNT("q8_li_part_type_pass", li_part_type_pass);
    TRACE_COUNT("q8_li_order_pass",     li_order_pass);
    TRACE_COUNT("q8_li_cust_pass",      li_cust_pass);
    TRACE_COUNT("q8_li_supp_pass",      li_supp_pass);
    TRACE_COUNT("q8_li_emitted",        li_emitted);
    TRACE_COUNT("q8_li_target_nation",  li_target_nation);
    } // end q8_lineitem_scan

    // ------------------------------------------------------------------
    // Step 12: emit one row per year that has qualifying data (ordered by year)
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    {
    PROFILE_SCOPE("q8_format_output");
    rows.push_back({"o_year", "mkt_share"});

    for (int yi = 0; yi <= 1; ++yi) {
        if (vol_total[yi] > 0) {
            rows.push_back({
                std::to_string(1995 + yi),
                q8_fmt_share(vol_target[yi], vol_total[yi])
            });
        }
    }
    result_row_count = static_cast<int64_t>(rows.size() - 1);
    } // end q8_format_output

    TRACE_COUNT("q8_vol_total_1995",    vol_total[0]);
    TRACE_COUNT("q8_vol_target_1995",   vol_target[0]);
    TRACE_COUNT("q8_vol_total_1996",    vol_total[1]);
    TRACE_COUNT("q8_vol_target_1996",   vol_target[1]);
    TRACE_COUNT("q8_query_output_rows", result_row_count);

    return rows;
}

