#include "query9.hpp"

#include <algorithm>
#include <cstdint>
#include <cstdio>
#include <iomanip>
#include <stdexcept>
#include <string>
#include <vector>
#include <unordered_map>

// SQL:
/** select
    nation,
    o_year,
    sum(amount) as sum_profit
from (
    select
        n_name as nation,
        extract(year from o_orderdate) as o_year,
        l_extendedprice * (1 - l_discount) - ps_supplycost * l_quantity as amount
    from
        part,
        supplier,
        lineitem,
        partsupp,
        orders,
        nation
    where
        s_suppkey = l_suppkey
        and ps_suppkey = l_suppkey
        and ps_partkey = l_partkey
        and p_partkey = l_partkey
        and o_orderkey = l_orderkey
        and s_nationkey = n_nationkey
        and p_name like '%[COLOR]%'
    ) as profit
group by
    nation,
    o_year
order by
    nation,
    o_year desc; */

// ---------------------------------------------------------------------------
// Date helpers (DATE16: days since 1992-01-01)
// ---------------------------------------------------------------------------
static bool q9_leap(int y) {
    return (y % 4 == 0 && y % 100 != 0) || y % 400 == 0;
}
static int q9_year(uint16_t d16) {
    int rem = static_cast<int>(d16);
    int y = 1992;
    while (true) {
        int dy = q9_leap(y) ? 366 : 365;
        if (rem < dy) break;
        rem -= dy; ++y;
    }
    return y;
}

// ---------------------------------------------------------------------------
// Format sum_profit:
//   amount = l_extendedprice*(100-l_discount)/100 - ps_supplycost*l_quantity/100
//   Both terms are scale=2 cents. We accumulate as integer scale=4 to avoid
//   loss of precision:
//     ep_s2 * (100 - disc) = ep*100-disc term [scale=4]
//   minus
//     supplycost_s2 * qty  [scale=2 * unit = scale=2, need to multiply by 100 for scale=4]
//
//   Actually cleaner in int64 scale=4:
//     term1 = ep_s2 * (100 - disc)          [scale=4]
//     term2 = supplycost_s2 * qty * 100      [scale=4: supplycost is scale=2, qty is integer, ×100]
//   amount_s4 = term1 - term2
//   Output: amount_s4 / 10000.0  -> 2 decimal places
// ---------------------------------------------------------------------------
static std::string q9_fmt_profit(int64_t v4) {
    // v4 is sum of amounts in scale=4.  Output with 2 decimal places.
    bool neg = (v4 < 0);
    if (neg) v4 = -v4;
    int64_t whole = v4 / 10000;
    int64_t frac2 = (v4 % 10000) / 100;
    char buf[48];
    std::snprintf(buf, sizeof(buf), "%s%lld.%02lld",
                  neg ? "-" : "",
                  (long long)whole,
                  (long long)frac2);
    return std::string(buf);
}

std::vector<std::vector<std::string>> run_q9(Database* db, const Q9Args& args) {
    if (!db) {
        throw std::runtime_error("run_q9: db is null");
    }

    const std::string& color = args.COLOR;

    // ------------------------------------------------------------------
    // Step 1: Build set of partkeys whose p_name contains COLOR (LIKE '%color%').
    //   Direct-addressed bitmap: partkey_matches[pk] = 1 if matched.
    // ------------------------------------------------------------------
    const Part&     part        = db->part;
    const uint32_t  pk_map_sz   = static_cast<uint32_t>(part.partkey_to_row.size());

    std::vector<uint8_t> partkey_matches(pk_map_sz, 0);
    for (uint32_t row = 0; row < part.row_count; ++row) {
        const std::string& name = part.p_name[row];
        if (name.find(color) != std::string::npos) {
            int32_t pk = part.p_partkey[row];
            if (pk > 0 && static_cast<uint32_t>(pk) < pk_map_sz)
                partkey_matches[static_cast<uint32_t>(pk)] = 1;
        }
    }

    // ------------------------------------------------------------------
    // Step 2: Build suppkey -> nationkey lookup (direct-addressed).
    //   0xFF = not present.
    // ------------------------------------------------------------------
    const Supplier& sup        = db->supplier;
    const uint32_t  sup_map_sz = static_cast<uint32_t>(sup.suppkey_to_row.size());

    std::vector<uint8_t> suppkey_nk(sup_map_sz, 0xFFu);
    for (uint32_t row = 0; row < sup.row_count; ++row) {
        int32_t sk = sup.s_suppkey[row];
        if (sk > 0 && static_cast<uint32_t>(sk) < sup_map_sz)
            suppkey_nk[static_cast<uint32_t>(sk)] = sup.s_nationkey[row];
    }

    // ------------------------------------------------------------------
    // Step 3: Build (partkey, suppkey) -> ps_supplycost lookup from PartSupp.
    //   Only include entries for partkeys that match the color filter.
    //   Key encoded as (int64)(pk << 20) | sk.
    //   TPC-H partkey <=  SF*200K (fits in int32), suppkey <= SF*10K (fits in int32).
    //   pk<<20 is safe for SF up to ~5000 (pk<=10^9 would overflow, but max pk
    //   at SF20 is 4M << 2^22, so use <<20 only up to pk<4096 which is wrong).
    //   Use a safer encoding: key = (int64)pk * 1000000LL + sk
    //   (suppkey <= 500K at SF50, pk <= 10M at SF50; product < 5e15, fits in int64)
    // ------------------------------------------------------------------
    const PartSupp& ps        = db->partsupp;

    std::unordered_map<int64_t, int64_t> ps_cost_map;
    ps_cost_map.reserve(ps.row_count / 4);

    for (uint32_t row = 0; row < ps.row_count; ++row) {
        int32_t pk = ps.ps_partkey[row];
        if (pk <= 0 || static_cast<uint32_t>(pk) >= pk_map_sz) continue;
        if (!partkey_matches[static_cast<uint32_t>(pk)]) continue;
        int32_t sk = ps.ps_suppkey[row];
        int64_t key = static_cast<int64_t>(pk) * 1000000LL + static_cast<int64_t>(sk);
        ps_cost_map[key] = ps.ps_supplycost[row];
    }

    // ------------------------------------------------------------------
    // Step 4: Scan all lineitems.  For each row:
    //   - partkey must be in partkey_matches
    //   - suppkey must have a known nationkey
    //   - look up ps_supplycost from ps_cost_map
    //   - join to orders via orderkey_to_row to get o_orderdate -> year
    //   - accumulate amount into profit_acc[nationkey][year-1992] (scale=4)
    // ------------------------------------------------------------------
    const Orders&   ord       = db->orders;
    const Lineitem& li        = db->lineitem;
    const uint32_t  n_li      = li.row_count;
    const uint32_t  ok_map_sz = static_cast<uint32_t>(ord.orderkey_to_row.size());
    const Nation&   nat       = db->nation;

    // Accumulator [25 nations][7 years: 1992..1998], scale=4 int64
    int64_t profit_acc[25][7] = {};

    for (uint32_t li_row = 0; li_row < n_li; ++li_row) {
        // Part color filter
        const int32_t pk = li.l_partkey[li_row];
        if (pk <= 0 || static_cast<uint32_t>(pk) >= pk_map_sz) continue;
        if (!partkey_matches[static_cast<uint32_t>(pk)]) continue;

        // Supplier nationkey
        const int32_t sk = li.l_suppkey[li_row];
        if (sk <= 0 || static_cast<uint32_t>(sk) >= sup_map_sz) continue;
        const uint8_t nk = suppkey_nk[static_cast<uint32_t>(sk)];
        if (nk == 0xFFu) continue;

        // PartSupp supplycost
        const int64_t ps_key = static_cast<int64_t>(pk) * 1000000LL + static_cast<int64_t>(sk);
        auto it = ps_cost_map.find(ps_key);
        if (it == ps_cost_map.end()) continue;
        const int64_t supplycost_s2 = it->second;  // scale=2

        // Order -> year
        const int32_t ok_val = li.l_orderkey[li_row];
        if (ok_val <= 0 || static_cast<uint32_t>(ok_val) >= ok_map_sz) continue;
        const uint32_t ord_row = ord.orderkey_to_row[static_cast<uint32_t>(ok_val)];
        if (ord_row == 0xFFFFFFFFu) continue;
        const int year = q9_year(ord.o_orderdate[ord_row]);
        const int yi = year - 1992;
        if (yi < 0 || yi > 6) continue;

        // amount (scale=4):
        //   disc_price_s4 = ep_s2 * (100 - disc)    [scale=4]
        //   cost_s4       = supplycost_s2 * qty * 100 [scale=4]
        const int64_t ep_s2          = li.l_extendedprice[li_row];
        const int64_t disc           = static_cast<int64_t>(li.l_discount[li_row]);
        const int64_t qty            = static_cast<int64_t>(li.l_quantity[li_row]);
        const int64_t disc_price_s4  = ep_s2 * (100LL - disc);
        const int64_t cost_s4        = supplycost_s2 * qty * 100LL;
        const int64_t amount_s4      = disc_price_s4 - cost_s4;

        profit_acc[nk][yi] += amount_s4;
    }

    // ------------------------------------------------------------------
    // Step 5: Collect non-zero results, sort by (nation ASC, o_year DESC).
    // ------------------------------------------------------------------
    struct ResultRow {
        std::string nation;
        int         o_year;
        int64_t     sum_profit_s4;
    };
    std::vector<ResultRow> results;
    results.reserve(25 * 7);

    for (int nk = 0; nk < 25; ++nk) {
        const std::string nation_name(nat.n_name[nk]);
        for (int yi = 0; yi <= 6; ++yi) {
            if (profit_acc[nk][yi] != 0) {
                results.push_back({nation_name, 1992 + yi, profit_acc[nk][yi]});
            }
        }
    }

    std::sort(results.begin(), results.end(), [](const ResultRow& a, const ResultRow& b) {
        if (a.nation != b.nation) return a.nation < b.nation;
        return a.o_year > b.o_year;  // year DESC
    });

    // ------------------------------------------------------------------
    // Step 6: Assemble output rows.
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(results.size() + 1);
    rows.push_back({"nation", "o_year", "sum_profit"});

    for (const ResultRow& r : results) {
        rows.push_back({
            r.nation,
            std::to_string(r.o_year),
            q9_fmt_profit(r.sum_profit_s4)
        });
    }

    return rows;
}

