    //   exists in partsupp (it always will if supplier exists, so skip check).
    // ------------------------------------------------------------------
    const PartSupp& ps        = db->partsupp;
    const uint32_t  ps_map_sz = static_cast<uint32_t>(ps.partkey_to_first_row.size());

    // ------------------------------------------------------------------
    // Step 4: Pre-build orderdate year lookup table (DATE16 -> year_index 0..6).
    //   Avoids per-row loop-based year extraction.
    // ------------------------------------------------------------------
    // We use a compact lookup: date16 values for orders are in [0, 2556].
    // Max date16 in TPC-H orders is 1998-12-31 = 2556. Build array size 2600.
    static const uint16_t MAX_DATE16 = 2600;
    uint8_t date16_to_yi[MAX_DATE16];
    for (uint16_t d = 0; d < MAX_DATE16; ++d) {
        date16_to_yi[d] = build_date16_year_lut(d);
    }

    // ------------------------------------------------------------------
    // Step 5: Scan all lineitems.  For each row:
    //   - partkey must be in partkey_matches
    //   - suppkey must have a known nationkey
    //   - look up ps_supplycost by scanning ~4 partsupp entries for partkey
    //   - join to orders via orderkey_to_row to get o_orderdate -> year
    //   - accumulate amount into profit_acc[nationkey][year-1992] (scale=4)
    // ------------------------------------------------------------------
    const Orders&   ord       = db->orders;
    const Lineitem& li        = db->lineitem;
    const uint32_t  n_li      = li.row_count;
    const uint32_t  ok_map_sz = static_cast<uint32_t>(ord.orderkey_to_row.size());
    const Nation&   nat       = db->nation;

    // Accumulator [25 nations][7 years: 1992..1998], scale=4 int64
    int64_t profit_acc[25][7] = {};

    {
    PROFILE_SCOPE("q9_lineitem_scan");

    for (uint32_t li_row = 0; li_row < n_li; ++li_row) {
        // Part color filter
        const int32_t pk = li.l_partkey[li_row];
        if (pk <= 0 || static_cast<uint32_t>(pk) >= pk_map_sz) continue;
        if (!partkey_matches[static_cast<uint32_t>(pk)]) continue;

        // Supplier nationkey
        const int32_t sk = li.l_suppkey[li_row];
        if (sk <= 0 || static_cast<uint32_t>(sk) >= sup_map_sz) continue;
        const uint8_t nk = suppkey_nk[static_cast<uint32_t>(sk)];
        if (nk == 0xFFu) continue;

        // PartSupp supplycost: scan the ~4 entries for this partkey
        const uint32_t upk = static_cast<uint32_t>(pk);
        if (upk >= ps_map_sz) continue;
        const uint32_t ps_start = ps.partkey_to_first_row[upk];
        // End of this partkey's group: next entry in partkey_to_first_row
        // partkey_to_first_row has size = max_pk+1, so upk+1 may be valid
        const uint32_t ps_end = (upk + 1 < ps_map_sz)
                                  ? ps.partkey_to_first_row[upk + 1]
                                  : ps.row_count;
        int64_t supplycost_s2 = -1;
        for (uint32_t psi = ps_start; psi < ps_end; ++psi) {
            if (ps.ps_suppkey[psi] == sk) {
                supplycost_s2 = ps.ps_supplycost[psi];
                break;
            }
        }
        if (supplycost_s2 < 0) continue;

        // Order -> year
        const int32_t ok_val = li.l_orderkey[li_row];
        if (ok_val <= 0 || static_cast<uint32_t>(ok_val) >= ok_map_sz) continue;
        const uint32_t ord_row = ord.orderkey_to_row[static_cast<uint32_t>(ok_val)];
        if (ord_row == 0xFFFFFFFFu) continue;
        const uint16_t odate = ord.o_orderdate[ord_row];
        if (odate >= MAX_DATE16) continue;
        const uint8_t yi = date16_to_yi[odate];
        if (yi == 0xFFu || yi > 6) continue;

        // amount (scale=4):
        //   disc_price_s4 = ep_s2 * (100 - disc)    [scale=4]
        //   cost_s4       = supplycost_s2 * qty * 100 [scale=4]
        const int64_t ep_s2          = static_cast<int64_t>(li.l_extendedprice[li_row]);
        const int64_t disc           = static_cast<int64_t>(li.l_discount[li_row]);
        const int64_t qty            = static_cast<int64_t>(li.l_quantity[li_row]);
        const int64_t disc_price_s4  = ep_s2 * (100LL - disc);
        const int64_t cost_s4        = supplycost_s2 * qty * 100LL;
        const int64_t amount_s4      = disc_price_s4 - cost_s4;

        profit_acc[nk][yi] += amount_s4;
    }
    } // end q9_lineitem_scan

    // ------------------------------------------------------------------
    // Step 6: Collect non-zero results, sort by (nation ASC, o_year DESC).
    // ------------------------------------------------------------------
    struct ResultRow {
        std::string nation;
        int         o_year;
        int64_t     sum_profit_s4;
    };
    std::vector<ResultRow> results;
    results.reserve(25 * 7);

    for (int nk = 0; nk < 25; ++nk) {
        const std::string nation_name(nat.n_name[nk]);
        for (int yi = 0; yi <= 6; ++yi) {
            if (profit_acc[nk][yi] != 0) {
                results.push_back({nation_name, 1992 + yi, profit_acc[nk][yi]});
            }
        }
    }

    std::sort(results.begin(), results.end(), [](const ResultRow& a, const ResultRow& b) {
        if (a.nation != b.nation) return a.nation < b.nation;
        return a.o_year > b.o_year;  // year DESC
    });

    // ------------------------------------------------------------------
    // Step 7: Assemble output rows.
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    {
    PROFILE_SCOPE("q9_format_output");
    rows.reserve(results.size() + 1);
    rows.push_back({"nation", "o_year", "sum_profit"});

    for (const ResultRow& r : results) {
        rows.push_back({
            r.nation,
            std::to_string(r.o_year),
            q9_fmt_profit(r.sum_profit_s4)
        });
    }
    } // end q9_format_output

    return rows;
}

