// SQL:
/**
select 
    c_custkey,  
    c_name,  
    sum(l_extendedprice * (1 - l_discount)) as revenue, 
    c_acctbal,  
    n_name,  
    c_address,  
    c_phone,  
    c_comment 
from  
    customer, orders, lineitem, nation 
where  
    c_custkey = o_custkey 
    and l_orderkey = o_orderkey 
    and o_orderdate >= date '[DATE]'
    and o_orderdate < date '[DATE]' + interval '3' month
    and l_returnflag = 'R' 
    and c_nationkey = n_nationkey 
group by  
    c_custkey, c_name, c_acctbal, c_phone, n_name, c_address, c_comment 
order by  
    revenue desc;
*/

// ---------------------------------------------------------------------------
// Date helpers (days since 1992-01-01)
// ---------------------------------------------------------------------------
static bool q10_leap(int y) {
    return (y % 4 == 0 && y % 100 != 0) || y % 400 == 0;
}
static const int Q10_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};

static uint16_t q10_parse_date(const std::string& s) {
    int y = std::stoi(s.substr(0, 4));
    int m = std::stoi(s.substr(5, 2));
    int d = std::stoi(s.substr(8, 2));
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q10_leap(i) ? 366 : 365;
    int lp = q10_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q10_DIM[lp][i - 1];
    return static_cast<uint16_t>(tot + (d - 1));
}

// Add N months to a DATE16 value (date encoded as days since 1992-01-01)
static uint16_t q10_add_months(uint16_t d16, int months) {
    // Decode d16 -> (y, m, day)
    int rem = static_cast<int>(d16);
    int y = 1992;
    while (true) {
        int dy = q10_leap(y) ? 366 : 365;
        if (rem < dy) break;
        rem -= dy; ++y;
    }
    int lp = q10_leap(y) ? 1 : 0;
    int mo = 1;
    while (mo <= 12 && rem >= Q10_DIM[lp][mo - 1]) {
        rem -= Q10_DIM[lp][mo - 1]; ++mo;
    }
    int day = rem + 1;

    // Add months
    mo += months;
    while (mo > 12) { mo -= 12; ++y; }
    while (mo < 1)  { mo += 12; --y; }

    // Clamp day to end of resulting month
    int lp2 = q10_leap(y) ? 1 : 0;
    int max_day = Q10_DIM[lp2][mo - 1];
    if (day > max_day) day = max_day;

    // Re-encode
    char buf[12];
    std::snprintf(buf, sizeof(buf), "%04d-%02d-%02d", y, mo, day);
    return q10_parse_date(std::string(buf));
}

// ---------------------------------------------------------------------------
// Format: int64 scale=4 intermediate -> decimal string, exactly 4 decimal places
// Revenue = ep(scale=2) * (100-disc); intermediate scale=4; display = v/10000
// ---------------------------------------------------------------------------
static std::string q10_fmt_revenue(int64_t v4) {
    bool neg = (v4 < 0); if (neg) v4 = -v4;
    int64_t whole = v4 / 10000;
    int64_t frac4 = v4 % 10000;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << whole << '.' << std::setw(4) << std::setfill('0') << frac4;
    return oss.str();
}

// Format c_acctbal (stored scaled *100) -> 2 decimal places
static std::string q10_fmt_acctbal(int64_t v) {
    bool neg = (v < 0); if (neg) v = -v;
    int64_t whole = v / 100;
    int64_t frac  = v % 100;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << whole << '.' << std::setw(2) << std::setfill('0') << frac;
    return oss.str();
}

// ---------------------------------------------------------------------------
// Result row
// ---------------------------------------------------------------------------
struct Q10Row {
    int32_t  custkey;
    int64_t  revenue;  // scale=4
};

std::vector<std::vector<std::string>> run_q10(Database* db, const Q10Args& args) {
    if (!db) {
        throw std::runtime_error("run_q10: db is null");
    }

    // ------------------------------------------------------------------
    // Step 1: parse date range  [date_lo, date_hi)
    // ------------------------------------------------------------------
    const uint16_t date_lo = q10_parse_date(args.DATE);
    const uint16_t date_hi = q10_add_months(date_lo, 3);

    // ------------------------------------------------------------------
    // Step 2: scan orders filtered by date range
    //         For each qualifying order, walk its lineitems summing revenue
    //         for rows with l_returnflag == 'R' (code = 2)
    // ------------------------------------------------------------------
    const Orders&   ord  = db->orders;
    const Lineitem& li   = db->lineitem;
    const Customer& cust = db->customer;
    const Nation&   nat  = db->nation;

    const uint32_t li_idx_sz = static_cast<uint32_t>(li.orderkey_to_first_li.size());

    // custkey -> accumulated revenue (scale=4)
    std::unordered_map<int32_t, int64_t> cust_rev;
    cust_rev.reserve(8192);

    const uint32_t n_orders = ord.row_count;
    for (uint32_t oi = 0; oi < n_orders; ++oi) {
        const uint16_t odate = ord.o_orderdate[oi];
        if (odate < date_lo || odate >= date_hi) continue;

        const int32_t  ok  = ord.o_orderkey[oi];
        const uint32_t uok = static_cast<uint32_t>(ok);
        if (uok >= li_idx_sz) continue;
        const uint32_t li_start = li.orderkey_to_first_li[uok];
        if (li_start == 0xFFFFFFFFu) continue;

        const int32_t ck = ord.o_custkey[oi];

        // Walk lineitems for this order; accumulate revenue for l_returnflag='R' (code=2)
        for (uint32_t lr = li_start;
             lr < li.row_count && li.l_orderkey[lr] == ok;
             ++lr) {
            if (li.l_returnflag[lr] != 2u) continue;  // only 'R'
            int64_t ep   = li.l_extendedprice[lr];
            int64_t disc = li.l_discount[lr];
            cust_rev[ck] += ep * (int64_t)(100 - disc);  // scale=4
        }
    }

    // ------------------------------------------------------------------
    // Step 3: collect results into sortable vector
    // ------------------------------------------------------------------
    std::vector<Q10Row> results;
    results.reserve(cust_rev.size());
    for (auto& [ck, rev] : cust_rev) {
        if (rev != 0)
            results.push_back({ck, rev});
    }

    // Sort by revenue DESC
    std::sort(results.begin(), results.end(), [](const Q10Row& a, const Q10Row& b) {
        return a.revenue > b.revenue;
    });

    // ------------------------------------------------------------------
    // Step 4: assemble output rows (top 20 per TPC-H spec)
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(results.size() + 1);
    rows.push_back({"c_custkey", "c_name", "revenue", "c_acctbal",
                    "n_name", "c_address", "c_phone", "c_comment"});

    const uint32_t cust_map_sz = static_cast<uint32_t>(cust.custkey_to_row.size());

    for (const Q10Row& r : results) {
        const int32_t  ck   = r.custkey;
        const uint32_t crow = (ck >= 0 && static_cast<uint32_t>(ck) < cust_map_sz)
                              ? cust.custkey_to_row[static_cast<uint32_t>(ck)]
                              : 0xFFFFFFFFu;
        if (crow == 0xFFFFFFFFu) continue;  // should not happen

        const uint8_t  nk     = cust.c_nationkey[crow];
        const std::string n_name(nat.n_name[nk]);

        rows.push_back({
            std::to_string(ck),
            cust.c_name[crow],
            q10_fmt_revenue(r.revenue),
            q10_fmt_acctbal(cust.c_acctbal[crow]),
            n_name,
            cust.c_address[crow],
            cust.c_phone[crow],
            cust.c_comment[crow]
        });
    }

    return rows;
}

