    and l_orderkey = o_orderkey 
    and o_orderdate >= date '[DATE]'
    and o_orderdate < date '[DATE]' + interval '3' month
    and l_returnflag = 'R' 
    and c_nationkey = n_nationkey 
group by  
    c_custkey, c_name, c_acctbal, c_phone, n_name, c_address, c_comment 
order by  
    revenue desc;
*/

// ---------------------------------------------------------------------------
// Date helpers (days since 1992-01-01)
// ---------------------------------------------------------------------------
static bool q10_leap(int y) {
    return (y % 4 == 0 && y % 100 != 0) || y % 400 == 0;
}
static const int Q10_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};

static uint16_t q10_parse_date(const std::string& s) {
    int y = std::stoi(s.substr(0, 4));
    int m = std::stoi(s.substr(5, 2));
    int d = std::stoi(s.substr(8, 2));
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q10_leap(i) ? 366 : 365;
    int lp = q10_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q10_DIM[lp][i - 1];
    return static_cast<uint16_t>(tot + (d - 1));
}

// Add N months to a DATE16 value (date encoded as days since 1992-01-01)
static uint16_t q10_add_months(uint16_t d16, int months) {
    int rem = static_cast<int>(d16);
    int y = 1992;
    while (true) {
        int dy = q10_leap(y) ? 366 : 365;
        if (rem < dy) break;
        rem -= dy; ++y;
    }
    int lp = q10_leap(y) ? 1 : 0;
    int mo = 1;
    while (mo <= 12 && rem >= Q10_DIM[lp][mo - 1]) {
        rem -= Q10_DIM[lp][mo - 1]; ++mo;
    }
    int day = rem + 1;

    mo += months;
    while (mo > 12) { mo -= 12; ++y; }
    while (mo < 1)  { mo += 12; --y; }

    int lp2 = q10_leap(y) ? 1 : 0;
    int max_day = Q10_DIM[lp2][mo - 1];
    if (day > max_day) day = max_day;

    char buf[12];
    std::snprintf(buf, sizeof(buf), "%04d-%02d-%02d", y, mo, day);
    return q10_parse_date(std::string(buf));
}

// ---------------------------------------------------------------------------
// Format revenue (scale=4) -> decimal string with 4 decimal places
// ---------------------------------------------------------------------------
static std::string q10_fmt_revenue(int64_t v4) {
    bool neg = (v4 < 0); if (neg) v4 = -v4;
    int64_t whole = v4 / 10000;
    int64_t frac4 = v4 % 10000;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << whole << '.' << std::setw(4) << std::setfill('0') << frac4;
    return oss.str();
}

// Format c_acctbal (stored scaled *100) -> 2 decimal places
static std::string q10_fmt_acctbal(int64_t v) {
    bool neg = (v < 0); if (neg) v = -v;
    int64_t whole = v / 100;
    int64_t frac  = v % 100;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << whole << '.' << std::setw(2) << std::setfill('0') << frac;
    return oss.str();
}

// ---------------------------------------------------------------------------
// Result row
// ---------------------------------------------------------------------------
struct Q10Row {
    int32_t  custkey;
    int64_t  revenue;  // scale=4
};

std::vector<std::vector<std::string>> run_q10(Database* db, const Q10Args& args) {
    if (!db) {
        throw std::runtime_error("run_q10: db is null");
    }

    PROFILE_SCOPE("q10_total");

    // ------------------------------------------------------------------
    // Step 1: parse date range [date_lo, date_hi)
    // ------------------------------------------------------------------
    const uint16_t date_lo = q10_parse_date(args.DATE);
    const uint16_t date_hi = q10_add_months(date_lo, 3);

    const Orders&   ord  = db->orders;
    const Lineitem& li   = db->lineitem;
    const Customer& cust = db->customer;
    const Nation&   nat  = db->nation;

    const uint32_t cust_map_sz = static_cast<uint32_t>(cust.custkey_to_row.size());
    const uint32_t li_idx_sz   = static_cast<uint32_t>(li.orderkey_to_first_li.size());

    // ------------------------------------------------------------------
    // Step 2: scan orders filtered by date range (~3.75% pass at SF20),
    //         walk lineitems for each qualifying order, accumulate revenue
    //         for l_returnflag='R' (code=2) into flat custkey array.
    //
    // Key optimizations vs baseline:
    // - Replace unordered_map<int32_t,int64_t> with flat vector<int64_t>
    //   indexed by custkey for O(1) random access with no hash overhead.
    // - Use raw pointers for inner loop column accesses.
    // ------------------------------------------------------------------
    std::vector<int64_t> cust_rev(cust_map_sz, 0LL);

    {
    PROFILE_SCOPE("q10_orders_lineitem_scan");

    const uint32_t  n_orders    = ord.row_count;
    const uint16_t* odate_arr   = ord.o_orderdate.data();
    const int32_t*  ok_arr      = ord.o_orderkey.data();
    const int32_t*  ck_arr      = ord.o_custkey.data();
    const uint32_t* li_start_arr = ord.order_row_to_li_start.data();

    const uint32_t  n_li    = li.row_count;
    const int32_t*  li_ok   = li.l_orderkey.data();
    const uint8_t*  rflag   = li.l_returnflag.data();
    const int32_t*  ep      = li.l_extendedprice.data();
    const uint8_t*  disc    = li.l_discount.data();

    int64_t* cr = cust_rev.data();

    for (uint32_t oi = 0; oi < n_orders; ++oi) {
        const uint16_t odate = odate_arr[oi];
        if (odate < date_lo || odate >= date_hi) continue;

        const uint32_t li_start = li_start_arr[oi];
        if (li_start == 0xFFFFFFFFu) continue;

        const int32_t  ok = ok_arr[oi];
        const uint32_t ck = static_cast<uint32_t>(ck_arr[oi]);

        int64_t order_rev = 0;
        for (uint32_t lr = li_start;
             lr < n_li && li_ok[lr] == ok;
             ++lr) {
            if (rflag[lr] != 2u) continue;  // only 'R'
            order_rev += ep[lr] * static_cast<int64_t>(100 - disc[lr]);
        }
        if (order_rev != 0 && ck < cust_map_sz)
            cr[ck] += order_rev;
    }
    }

    TRACE_COUNT("q10_date_lo", static_cast<int64_t>(date_lo));
    TRACE_COUNT("q10_date_hi", static_cast<int64_t>(date_hi));
    (void)li_idx_sz;

    // ------------------------------------------------------------------
    // Step 3: collect nonzero custkey entries into sortable vector
    // ------------------------------------------------------------------
    std::vector<Q10Row> results;
    results.reserve(4096);
    for (uint32_t ck = 0; ck < cust_map_sz; ++ck) {
        const int64_t rev = cust_rev[ck];
        if (rev != 0LL && cust.custkey_to_row[ck] != 0xFFFFFFFFu)
            results.push_back({static_cast<int32_t>(ck), rev});
    }

    // Sort by revenue DESC
    std::sort(results.begin(), results.end(), [](const Q10Row& a, const Q10Row& b) {
        return a.revenue > b.revenue;
    });

    // ------------------------------------------------------------------
    // Step 4: assemble output rows
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(results.size() + 1);
    rows.push_back({"c_custkey", "c_name", "revenue", "c_acctbal",
                    "n_name", "c_address", "c_phone", "c_comment"});

    {
    PROFILE_SCOPE("q10_format_output");

    for (const Q10Row& r : results) {
        const uint32_t ck   = static_cast<uint32_t>(r.custkey);
        const uint32_t crow = cust.custkey_to_row[ck];
        if (crow == 0xFFFFFFFFu) continue;

        const uint8_t  nk = cust.c_nationkey[crow];
        const std::string n_name(nat.n_name[nk]);

        rows.push_back({
            std::to_string(ck),
            cust.c_name[crow],
            q10_fmt_revenue(r.revenue),
            q10_fmt_acctbal(cust.c_acctbal[crow]),
            n_name,
            cust.c_address[crow],
            cust.c_phone[crow],
            cust.c_comment[crow]
        });
    }

    }

    TRACE_COUNT("q10_output_rows", static_cast<int64_t>(rows.size() - 1));

    return rows;
}

#include "query11.hpp"

#include <algorithm>
#include <cstdint>
#include <iomanip>
#include <sstream>
#include <stdexcept>
#include <string>
#include <unordered_map>
#include <vector>

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

// Format int64 scaled *100 value as decimal string with exactly 2 dp.
// e.g. 1234567 -> "12345.67"
static std::string fmt_money(int64_t v) {
    bool neg = (v < 0);
    if (neg) v = -v;
    int64_t whole = v / 100;
    int64_t frac  = v % 100;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << whole << '.' << std::setw(2) << std::setfill('0') << frac;
    return oss.str();
}

std::vector<std::vector<std::string>> run_q11(Database* db, const Q11Args& args) {
    if (!db) {
        throw std::runtime_error("run_q11: db is null");
    }

    const Nation&    nat = db->nation;
    const Supplier&  sup = db->supplier;
    const PartSupp&  ps  = db->partsupp;

    // ------------------------------------------------------------------
    // Step 1: resolve nation name -> nationkey
    // ------------------------------------------------------------------
    int nation_key = nat.name_to_key(args.NATION);
    if (nation_key < 0) {
        // No matching nation -> empty result
        std::vector<std::vector<std::string>> rows;
        rows.push_back({"ps_partkey", "value"});
        return rows;
    }

    // ------------------------------------------------------------------
    // Step 2: build boolean bitmap over suppkey space for suppliers in
    //         the target nation.
    //         suppkey_to_row[sk] gives the supplier row for key sk.
    // ------------------------------------------------------------------
    uint32_t max_sk = static_cast<uint32_t>(sup.suppkey_to_row.size());
    // supp_in_nation[sk] = true when supplier sk belongs to the nation
    std::vector<bool> supp_in_nation(max_sk, false);
    for (uint32_t row = 0; row < sup.row_count; ++row) {
        if (sup.s_nationkey[row] == static_cast<uint8_t>(nation_key)) {
            int32_t sk = sup.s_suppkey[row];
            if (sk > 0 && static_cast<uint32_t>(sk) < max_sk) {
                supp_in_nation[static_cast<uint32_t>(sk)] = true;
            }
        }
    }

    // ------------------------------------------------------------------
    // Step 3: scan all partsupp rows.
    //         For each row where ps_suppkey is in the nation:
    //           - accumulate global total
    //           - accumulate per-partkey value = ps_supplycost * ps_availqty
    //
    //         ps_supplycost is scaled *100 (int64), ps_availqty is int32.
    //         product = supplycost_cents * availqty  (still scaled *100)
    // ------------------------------------------------------------------
    int64_t global_total = 0;

    // We need partkey -> accumulated value.
    // partkeys are dense 1..max_pk; use a flat vector for O(1) access.
    // partkey_to_first_row.size() == max_pk+1 (after trim in builder).
    uint32_t max_pk = static_cast<uint32_t>(ps.partkey_to_first_row.size());  // == max_pk+1
    std::vector<int64_t> pk_value(max_pk + 1, 0);  // index by partkey (1-based)

    uint32_t n_ps = ps.row_count;
    for (uint32_t r = 0; r < n_ps; ++r) {
        int32_t sk = ps.ps_suppkey[r];
        if (sk <= 0 || static_cast<uint32_t>(sk) >= max_sk) continue;
        if (!supp_in_nation[static_cast<uint32_t>(sk)]) continue;

        int32_t pk = ps.ps_partkey[r];
        if (pk <= 0 || static_cast<uint32_t>(pk) > max_pk) continue;

        // value contribution (scaled *100)
        int64_t contrib = ps.ps_supplycost[r] * static_cast<int64_t>(ps.ps_availqty[r]);
        pk_value[static_cast<uint32_t>(pk)] += contrib;
        global_total += contrib;
    }

    // ------------------------------------------------------------------
    // Step 4: compute threshold = global_total * FRACTION
    //         Use double arithmetic; FRACTION is a small number like 0.0001.
    // ------------------------------------------------------------------
    double fraction  = std::stod(args.FRACTION);
    // threshold in the same scale as pk_value (i.e. *100 cents)
    double threshold_d = static_cast<double>(global_total) * fraction;

    // ------------------------------------------------------------------
    // Step 5: collect partkeys where pk_value > threshold, sort DESC by value
    // ------------------------------------------------------------------
    struct Row {
        int32_t ps_partkey;
        int64_t value;  // scaled *100
    };
    std::vector<Row> result;
    result.reserve(512);

    for (uint32_t pk = 1; pk <= max_pk; ++pk) {
        int64_t v = pk_value[pk];
        if (v == 0) continue;
        // HAVING sum(...) > threshold
        if (static_cast<double>(v) > threshold_d) {
            result.push_back({static_cast<int32_t>(pk), v});
        }
    }

    // Sort by value DESC
    std::sort(result.begin(), result.end(), [](const Row& a, const Row& b) {
        return a.value > b.value;
    });

    // ------------------------------------------------------------------
    // Step 6: assemble output
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);
    rows.push_back({"ps_partkey", "value"});

    for (const auto& rr : result) {
        rows.push_back({
            std::to_string(rr.ps_partkey),
            fmt_money(rr.value)
        });
    }

    return rows;
}

