    oss << whole << '.' << std::setw(2) << std::setfill('0') << frac;
    return oss.str();
}

std::vector<std::vector<std::string>> run_q11(Database* db, const Q11Args& args) {
    if (!db) {
        throw std::runtime_error("run_q11: db is null");
    }

    PROFILE_SCOPE("q11_total");

    const Nation&    nat = db->nation;
    const Supplier&  sup = db->supplier;
    const PartSupp&  ps  = db->partsupp;

    // ------------------------------------------------------------------
    // Step 1: resolve nation name -> nationkey
    // ------------------------------------------------------------------
    int nation_key = nat.name_to_key(args.NATION);
    if (nation_key < 0) {
        // No matching nation -> empty result
        std::vector<std::vector<std::string>> rows;
        rows.push_back({"ps_partkey", "value"});
        return rows;
    }

    TRACE_COUNT("q11_nation_key", static_cast<int64_t>(nation_key));

    // ------------------------------------------------------------------
    // Step 2: build boolean bitmap over suppkey space for suppliers in
    //         the target nation.
    //         suppkey_to_row[sk] gives the supplier row for key sk.
    // ------------------------------------------------------------------
    uint32_t max_sk = static_cast<uint32_t>(sup.suppkey_to_row.size());
    // supp_in_nation[sk] = true when supplier sk belongs to the nation
    std::vector<uint8_t> supp_in_nation(max_sk, 0);
    int64_t supp_in_nation_count = 0;
    for (uint32_t row = 0; row < sup.row_count; ++row) {
        if (sup.s_nationkey[row] == static_cast<uint8_t>(nation_key)) {
            int32_t sk = sup.s_suppkey[row];
            if (sk > 0 && static_cast<uint32_t>(sk) < max_sk) {
                supp_in_nation[static_cast<uint32_t>(sk)] = 1;
                ++supp_in_nation_count;
            }
        }
    }

    TRACE_COUNT("q11_suppliers_in_nation", supp_in_nation_count);

    // ------------------------------------------------------------------
    // Step 3: scan all partsupp rows.
    //         For each row where ps_suppkey is in the nation:
    //           - accumulate global total
    //           - accumulate per-partkey value = ps_supplycost * ps_availqty
    //
    //         ps_supplycost is scaled *100 (int64), ps_availqty is int32.
    //         product = supplycost_cents * availqty  (still scaled *100)
    // ------------------------------------------------------------------
    uint32_t max_pk = static_cast<uint32_t>(ps.partkey_to_first_row.size());  // == max_pk+1

    // Two-pass: first pass accumulate both per-partkey and global total
    int64_t global_total = 0;
    std::vector<int64_t> pk_value(max_pk + 1, 0);  // index by partkey (1-based)

    {
    PROFILE_SCOPE("q11_partsupp_scan");
    uint32_t n_ps = ps.row_count;

    // Use raw pointers for hot loop to avoid bounds-check overhead
    const int32_t*  sk_arr   = ps.ps_suppkey.data();
    const int32_t*  pk_arr   = ps.ps_partkey.data();
    const int32_t*  qty_arr  = ps.ps_availqty.data();
    const int64_t*  cost_arr = ps.ps_supplycost.data();
    const uint8_t*  nation_flag = supp_in_nation.data();
    int64_t*        val_arr  = pk_value.data();

    for (uint32_t r = 0; r < n_ps; ++r) {
        uint32_t sk = static_cast<uint32_t>(sk_arr[r]);
        // Single bounds check: 0 < sk < max_sk (unsigned, so sk==0 wraps to large)
        if (sk - 1u >= max_sk - 1u) continue;
        if (!nation_flag[sk]) continue;

        uint32_t pk = static_cast<uint32_t>(pk_arr[r]);
        // bounds check for pk
        if (pk - 1u > max_pk - 1u) continue;

        int64_t contrib = cost_arr[r] * static_cast<int64_t>(qty_arr[r]);
        val_arr[pk] += contrib;
        global_total += contrib;
    }
    } // end q11_partsupp_scan

    TRACE_COUNT("q11_global_total_s2",  global_total);

    // ------------------------------------------------------------------
    // Step 4: compute threshold = global_total * FRACTION
    //         Use double arithmetic; FRACTION is a small number like 0.0001.
    // ------------------------------------------------------------------
    double fraction  = std::stod(args.FRACTION);
    // threshold in the same scale as pk_value (i.e. *100 cents)
    double threshold_d = static_cast<double>(global_total) * fraction;

    TRACE_COUNT("q11_threshold_int", static_cast<int64_t>(threshold_d));

    // ------------------------------------------------------------------
    // Step 5: collect partkeys where pk_value > threshold, sort DESC by value
    // ------------------------------------------------------------------
    struct Row {
        int32_t ps_partkey;
        int64_t value;  // scaled *100
    };
    std::vector<Row> result;
    result.reserve(512);

    for (uint32_t pk = 1; pk <= max_pk; ++pk) {
        int64_t v = pk_value[pk];
        if (v == 0) continue;
        // HAVING sum(...) > threshold
        if (static_cast<double>(v) > threshold_d) {
            result.push_back({static_cast<int32_t>(pk), v});
        }
    }

    TRACE_COUNT("q11_partkeys_with_value",  static_cast<int64_t>(
        std::count_if(pk_value.begin() + 1, pk_value.end(), [](int64_t x){ return x > 0; })));
    TRACE_COUNT("q11_partkeys_above_threshold", static_cast<int64_t>(result.size()));

    // Sort by value DESC
    std::sort(result.begin(), result.end(), [](const Row& a, const Row& b) {
        return a.value > b.value;
    });

    // ------------------------------------------------------------------
    // Step 6: assemble output
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);

    {
    PROFILE_SCOPE("q11_format_output");
    rows.push_back({"ps_partkey", "value"});

    for (const auto& rr : result) {
        rows.push_back({
            std::to_string(rr.ps_partkey),
            fmt_money(rr.value)
        });
    }

    } // end q11_format_output

    TRACE_COUNT("q11_output_rows", static_cast<int64_t>(rows.size() - 1));

    return rows;
}

