    int64_t*        val_arr  = pk_value.data();

    for (uint32_t r = 0; r < n_ps; ++r) {
        uint32_t sk = static_cast<uint32_t>(sk_arr[r]);
        // Single bounds check: 0 < sk < max_sk (unsigned, so sk==0 wraps to large)
        if (sk - 1u >= max_sk - 1u) continue;
        if (!nation_flag[sk]) continue;

        uint32_t pk = static_cast<uint32_t>(pk_arr[r]);
        // bounds check for pk
        if (pk - 1u > max_pk - 1u) continue;

        int64_t contrib = cost_arr[r] * static_cast<int64_t>(qty_arr[r]);
        val_arr[pk] += contrib;
        global_total += contrib;
    }
    } // end q11_partsupp_scan

    TRACE_COUNT("q11_global_total_s2",  global_total);

    // ------------------------------------------------------------------
    // Step 4: compute threshold = global_total * FRACTION
    //         Use double arithmetic; FRACTION is a small number like 0.0001.
    // ------------------------------------------------------------------
    double fraction  = std::stod(args.FRACTION);
    // threshold in the same scale as pk_value (i.e. *100 cents)
    double threshold_d = static_cast<double>(global_total) * fraction;

    TRACE_COUNT("q11_threshold_int", static_cast<int64_t>(threshold_d));

    // ------------------------------------------------------------------
    // Step 5: collect partkeys where pk_value > threshold, sort DESC by value
    // ------------------------------------------------------------------
    struct Row {
        int32_t ps_partkey;
        int64_t value;  // scaled *100
    };
    std::vector<Row> result;
    result.reserve(512);

    for (uint32_t pk = 1; pk <= max_pk; ++pk) {
        int64_t v = pk_value[pk];
        if (v == 0) continue;
        // HAVING sum(...) > threshold
        if (static_cast<double>(v) > threshold_d) {
            result.push_back({static_cast<int32_t>(pk), v});
        }
    }

    TRACE_COUNT("q11_partkeys_with_value",  static_cast<int64_t>(
        std::count_if(pk_value.begin() + 1, pk_value.end(), [](int64_t x){ return x > 0; })));
    TRACE_COUNT("q11_partkeys_above_threshold", static_cast<int64_t>(result.size()));

    // Sort by value DESC
    std::sort(result.begin(), result.end(), [](const Row& a, const Row& b) {
        return a.value > b.value;
    });

    // ------------------------------------------------------------------
    // Step 6: assemble output
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);

    {
    PROFILE_SCOPE("q11_format_output");
    rows.push_back({"ps_partkey", "value"});

    for (const auto& rr : result) {
        rows.push_back({
            std::to_string(rr.ps_partkey),
            fmt_money(rr.value)
        });
    }

    } // end q11_format_output

    TRACE_COUNT("q11_output_rows", static_cast<int64_t>(rows.size() - 1));

    return rows;
}

#include "query12.hpp"

#include <algorithm>
#include <cstdint>
#include <iomanip>
#include <sstream>
#include <stdexcept>
#include <string>
#include <vector>

// ---------------------------------------------------------------------------
// Date helpers (days since 1992-01-01 = DATE16 encoding)
// ---------------------------------------------------------------------------
static const int Q12_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};
static bool q12_leap(int y) { return (y%4==0&&y%100!=0)||y%400==0; }

static uint16_t q12_parse_date(const std::string& s) {
    int y = std::stoi(s.substr(0,4));
    int m = std::stoi(s.substr(5,2));
    int d = std::stoi(s.substr(8,2));
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q12_leap(i) ? 366 : 365;
    int lp = q12_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q12_DIM[lp][i-1];
    return static_cast<uint16_t>(tot + (d-1));
}

static uint16_t q12_add_one_year(uint16_t date16) {
    int remaining = date16;
    int y = 1992;
    while (true) {
        int days_in_year = q12_leap(y) ? 366 : 365;
        if (remaining < days_in_year) break;
        remaining -= days_in_year;
        ++y;
    }
    int lp = q12_leap(y) ? 1 : 0;
    int m = 0;
    while (remaining >= Q12_DIM[lp][m]) {
        remaining -= Q12_DIM[lp][m];
        ++m;
    }
    int d = remaining;
    int ny = y + 1;
    int tot = 0;
    for (int i = 1992; i < ny; ++i) tot += q12_leap(i) ? 366 : 365;
    int nlp = q12_leap(ny) ? 1 : 0;
    for (int i = 0; i < m; ++i) tot += Q12_DIM[nlp][i];
    tot += d;
    return static_cast<uint16_t>(tot);
}

std::vector<std::vector<std::string>> run_q12(Database* db, const Q12Args& args) {
    if (!db) throw std::runtime_error("run_q12: db is null");

    // -----------------------------------------------------------------------
    // Parse parameters
    // -----------------------------------------------------------------------
    uint16_t rd_lo = q12_parse_date(args.DATE);
    uint16_t rd_hi = q12_add_one_year(rd_lo);  // exclusive upper bound

    // Resolve SHIPMODE1 and SHIPMODE2 to their dictionary codes.
    const Lineitem& li  = db->lineitem;
    const Orders&   or_ = db->orders;

    auto find_shipmode_code = [&](const std::string& name) -> uint8_t {
        if (name == "<<NULL>>") return 255;
        for (uint8_t c = 0; c < (uint8_t)li.l_shipmode_dict.size(); ++c) {
            if (li.l_shipmode_dict[c] == name) return c;
        }
        return 255; // not found -> will never match any row
    };

    uint8_t code1 = find_shipmode_code(args.SHIPMODE1);
    uint8_t code2 = find_shipmode_code(args.SHIPMODE2);

    // Resolve orderpriority codes for "1-URGENT" and "2-HIGH"
    auto find_prio_code = [&](const std::string& name) -> int {
        for (int c = 0; c < (int)or_.o_orderpriority_dict.size(); ++c) {
            if (or_.o_orderpriority_dict[c] == name) return c;
        }
        return -1;
    };

    int urgent_code = find_prio_code("1-URGENT");
    int high_code   = find_prio_code("2-HIGH");

    // -----------------------------------------------------------------------
    // Accumulators: one slot per tracked shipmode (up to 2)
    // -----------------------------------------------------------------------
    static const int MAX_CODES = 2;
    uint8_t  tracked_codes[MAX_CODES] = {code1, code2};
    int64_t  high_count[MAX_CODES]    = {0, 0};
    int64_t  low_count[MAX_CODES]     = {0, 0};
    bool     active[MAX_CODES]        = {code1 != 255, code2 != 255};

    // -----------------------------------------------------------------------
    // Lineitem scan with receiptdate zone-map pruning
    // -----------------------------------------------------------------------
    const uint32_t n = li.row_count;

    const uint8_t*  sm  = li.l_shipmode_code.data();
    const uint16_t* rda = li.l_receiptdate.data();
    const uint16_t* cda = li.l_commitdate.data();
    const uint16_t* sda = li.l_shipdate.data();
    const int32_t*  ok  = li.l_orderkey.data();
    // l_commit_late bit[i] = (receiptdate[i] > commitdate[i])
    const auto&     commit_late = li.l_commit_late;

    constexpr uint32_t CHUNK = 65536;
    const uint32_t num_chunks = (uint32_t)li.receiptdate_chunk_min.size();

    for (uint32_t c = 0; c < num_chunks; ++c) {
        // Zone-map prune on receiptdate
        if (li.receiptdate_chunk_max[c] < rd_lo) continue;
        if (li.receiptdate_chunk_min[c] >= rd_hi) continue;

        uint32_t row_start = c * CHUNK;
        uint32_t row_end   = std::min(row_start + CHUNK, n);

        for (uint32_t i = row_start; i < row_end; ++i) {
            // Filter: l_receiptdate in [rd_lo, rd_hi)
            uint16_t rdt = rda[i];
            if (rdt < rd_lo || rdt >= rd_hi) continue;

            // Filter: l_shipmode in (SHIPMODE1, SHIPMODE2)
            uint8_t mode = sm[i];
            int slot = -1;
            if (active[0] && mode == tracked_codes[0]) slot = 0;
            else if (active[1] && mode == tracked_codes[1]) slot = 1;
            else continue;

            // Filter: l_commitdate < l_receiptdate (precomputed bitmap)
            if (!commit_late.test(i)) continue;

            // Filter: l_shipdate < l_commitdate
            if (sda[i] >= cda[i]) continue;

            // Join to orders via direct-address lookup
            int32_t orderkey = ok[i];
            if (orderkey < 0 || (uint32_t)orderkey >= or_.orderkey_to_row.size()) continue;
            uint32_t orow = or_.orderkey_to_row[(uint32_t)orderkey];
            if (orow == 0xFFFFFFFF) continue;

            uint8_t prio = or_.o_orderpriority_code[orow];
            bool is_high = ((int)prio == urgent_code || (int)prio == high_code);

            if (is_high)
                ++high_count[slot];
            else
                ++low_count[slot];
        }
    }

    // -----------------------------------------------------------------------
    // Assemble result rows, ORDER BY l_shipmode ASC
    // -----------------------------------------------------------------------
    struct ResultRow {
        std::string shipmode;
        int64_t high_cnt;
        int64_t low_cnt;
    };

    std::vector<ResultRow> result_rows;
    for (int s = 0; s < MAX_CODES; ++s) {
        if (!active[s]) continue;
        // Deduplicate: if code1 == code2, emit only one row (from slot 0)
        if (s == 1 && tracked_codes[0] == tracked_codes[1]) continue;
        result_rows.push_back({li.l_shipmode_dict[tracked_codes[s]],
                               high_count[s], low_count[s]});
    }
    std::sort(result_rows.begin(), result_rows.end(),
              [](const ResultRow& a, const ResultRow& b) {
                  return a.shipmode < b.shipmode;
              });

    std::vector<std::vector<std::string>> rows;
    rows.push_back({"l_shipmode", "high_line_count", "low_line_count"});
    for (const auto& r : result_rows) {
        rows.push_back({r.shipmode,
                        std::to_string(r.high_cnt),
                        std::to_string(r.low_cnt)});
    }
    return rows;
}

