            if (li.l_shipmode_dict[c] == name) return c;
        }
        return 255; // not found -> will never match any row
    };

    uint8_t code1 = find_shipmode_code(args.SHIPMODE1);
    uint8_t code2 = find_shipmode_code(args.SHIPMODE2);

    // Resolve orderpriority codes for "1-URGENT" and "2-HIGH"
    auto find_prio_code = [&](const std::string& name) -> int {
        for (int c = 0; c < (int)or_.o_orderpriority_dict.size(); ++c) {
            if (or_.o_orderpriority_dict[c] == name) return c;
        }
        return -1;
    };

    int urgent_code = find_prio_code("1-URGENT");
    int high_code   = find_prio_code("2-HIGH");

    // -----------------------------------------------------------------------
    // Accumulators and compact shipmode -> slot lookup table (256 bytes in L1)
    // -----------------------------------------------------------------------
    static const int MAX_CODES = 2;
    uint8_t  tracked_codes[MAX_CODES] = {code1, code2};
    bool     active[MAX_CODES]        = {code1 != 255, code2 != 255};
    // sm_slot[code] = 0 or 1 if code is tracked, 0xFF otherwise
    uint8_t  sm_slot[256];
    std::memset(sm_slot, 0xFF, sizeof(sm_slot));
    if (active[0]) sm_slot[code1] = 0;
    if (active[1]) sm_slot[code2] = 1;
    // If both codes are the same, slot 1 is invalid — keep sm_slot consistent
    if (active[0] && active[1] && code1 == code2) sm_slot[code2] = 0;

    int64_t  high_count[MAX_CODES]    = {0, 0};
    int64_t  low_count[MAX_CODES]     = {0, 0};

    // -----------------------------------------------------------------------
    // Lineitem scan with receiptdate zone-map pruning
    // -----------------------------------------------------------------------
    const uint32_t n = li.row_count;

    const uint8_t*  sm  = li.l_shipmode_code.data();
    const uint16_t* rda = li.l_receiptdate.data();
    const uint16_t* cda = li.l_commitdate.data();
    const uint16_t* sda = li.l_shipdate.data();
    const int32_t*  ok  = li.l_orderkey.data();

    constexpr uint32_t CHUNK = 65536;
    const uint32_t num_chunks = (uint32_t)li.receiptdate_chunk_min.size();

    // Direct pointer to orderkey_to_priority for single-level lookup
    const uint8_t*  ok_prio = or_.orderkey_to_priority.data();
    const uint32_t  ok_prio_size = (uint32_t)or_.orderkey_to_priority.size();

    // -----------------------------------------------------------------------
    // Emit pre-scan diagnostics
    // -----------------------------------------------------------------------
    TRACE_COUNT("q12_date_lo",      static_cast<int64_t>(rd_lo));
    TRACE_COUNT("q12_date_hi",      static_cast<int64_t>(rd_hi));
    TRACE_COUNT("q12_code1",        static_cast<int64_t>(code1));
    TRACE_COUNT("q12_code2",        static_cast<int64_t>(code2));
    TRACE_COUNT("q12_urgent_code",  static_cast<int64_t>(urgent_code));
    TRACE_COUNT("q12_high_code",    static_cast<int64_t>(high_code));
    TRACE_COUNT("q12_num_chunks",   static_cast<int64_t>(num_chunks));

    int64_t chunks_scanned     = 0;
    int64_t chunks_pruned      = 0;
    int64_t li_rows_scanned    = 0;
    int64_t li_date_pass       = 0;
    int64_t li_shipmode_pass   = 0;
    int64_t li_commit_late_pass = 0;
    int64_t li_shipdate_pass   = 0;
    int64_t li_order_pass      = 0;
    int64_t li_emitted         = 0;

    {
    PROFILE_SCOPE("q12_lineitem_scan");
    for (uint32_t c = 0; c < num_chunks; ++c) {
        // Zone-map prune on receiptdate
        if (li.receiptdate_chunk_max[c] < rd_lo || li.receiptdate_chunk_min[c] >= rd_hi) {
            ++chunks_pruned;
            continue;
        }
        ++chunks_scanned;

        uint32_t row_start = c * CHUNK;
        uint32_t row_end   = std::min(row_start + CHUNK, n);

        for (uint32_t i = row_start; i < row_end; ++i) {
            // Filter: l_receiptdate in [rd_lo, rd_hi)
            uint16_t rdt = rda[i];
            ++li_rows_scanned;
            if (rdt < rd_lo || rdt >= rd_hi) continue;
            ++li_date_pass;

            // Filter: l_shipmode in (SHIPMODE1, SHIPMODE2) — branchless table lookup
            int slot = (int)sm_slot[sm[i]];
            if (slot == 0xFF) continue;
            ++li_shipmode_pass;

            // Filter: l_commitdate < l_receiptdate (direct comparison)
            uint16_t cdt = cda[i];
            if (rdt <= cdt) continue;
            ++li_commit_late_pass;

            // Filter: l_shipdate < l_commitdate
            if (sda[i] >= cdt) continue;
            ++li_shipdate_pass;

            // Join to orders via direct-address lookup
            int32_t orderkey = ok[i];
            if (orderkey < 0 || (uint32_t)orderkey >= ok_prio_size) continue;
            ++li_order_pass;

            uint8_t prio = ok_prio[(uint32_t)orderkey];
            bool is_high = ((int)prio == urgent_code || (int)prio == high_code);

            if (is_high)
                ++high_count[slot];
            else
                ++low_count[slot];
            ++li_emitted;
        }
    }
    } // end q12_lineitem_scan

    TRACE_COUNT("q12_chunks_total",       static_cast<int64_t>(num_chunks));
    TRACE_COUNT("q12_chunks_pruned",      chunks_pruned);
    TRACE_COUNT("q12_chunks_scanned",     chunks_scanned);
    TRACE_COUNT("q12_li_rows_scanned",    li_rows_scanned);
    TRACE_COUNT("q12_li_date_pass",       li_date_pass);
    TRACE_COUNT("q12_li_shipmode_pass",   li_shipmode_pass);
    TRACE_COUNT("q12_li_commit_late_pass",li_commit_late_pass);
    TRACE_COUNT("q12_li_shipdate_pass",   li_shipdate_pass);
    TRACE_COUNT("q12_li_order_pass",      li_order_pass);
    TRACE_COUNT("q12_li_emitted",         li_emitted);
    TRACE_COUNT("q12_high_count_slot0",   high_count[0]);
    TRACE_COUNT("q12_low_count_slot0",    low_count[0]);
    TRACE_COUNT("q12_high_count_slot1",   high_count[1]);
    TRACE_COUNT("q12_low_count_slot1",    low_count[1]);

    // -----------------------------------------------------------------------
    // Assemble result rows, ORDER BY l_shipmode ASC
    // -----------------------------------------------------------------------
    struct ResultRow {
        std::string shipmode;
        int64_t high_cnt;
        int64_t low_cnt;
    };

    std::vector<ResultRow> result_rows;
    for (int s = 0; s < MAX_CODES; ++s) {
        if (!active[s]) continue;
        // Deduplicate: if code1 == code2, emit only one row (from slot 0)
        if (s == 1 && tracked_codes[0] == tracked_codes[1]) continue;
        result_rows.push_back({li.l_shipmode_dict[tracked_codes[s]],
                               high_count[s], low_count[s]});
    }
    std::sort(result_rows.begin(), result_rows.end(),
              [](const ResultRow& a, const ResultRow& b) {
                  return a.shipmode < b.shipmode;
              });

    {
    PROFILE_SCOPE("q12_format_output");
    std::vector<std::vector<std::string>> rows;
    rows.push_back({"l_shipmode", "high_line_count", "low_line_count"});
    for (const auto& r : result_rows) {
        rows.push_back({r.shipmode,
                        std::to_string(r.high_cnt),
                        std::to_string(r.low_cnt)});
    }

    TRACE_COUNT("q12_output_rows", static_cast<int64_t>(rows.size() - 1));

    return rows;
    } // end q12_format_output
}

#include "query13.hpp"

#include <algorithm>
#include <cstdint>
#include <cstring>
#include <sstream>
#include <stdexcept>
#include <string>
#include <unordered_map>
#include <vector>

// SQL:
// select
//     c_count, count(*) as custdist
// from (
//     select
//         c_custkey,
//         count(o_orderkey)
//     from
//         customer left outer join orders on
//             c_custkey = o_custkey
//             and o_comment not like '%[WORD1]%[WORD2]%'
//     group by
//         c_custkey
//     ) as c_orders (c_custkey, c_count)
// group by
//     c_count
// order by
//     custdist desc,
//     c_count desc;

// ---------------------------------------------------------------------------
// Helper: check if 'comment' matches the pattern  %word1%word2%
// Returns true if it MATCHES (i.e. the order IS excluded from the count).
// ---------------------------------------------------------------------------
static bool comment_matches(const std::string& comment,
                             const std::string& word1,
                             const std::string& word2) {
    // Find word1 anywhere in comment
    const char* p = std::strstr(comment.c_str(), word1.c_str());
    if (!p) return false;
    // Find word2 strictly after the start of word1
    p += word1.size();
    if (!std::strstr(p, word2.c_str())) return false;
    return true;
}

std::vector<std::vector<std::string>> run_q13(Database* db, const Q13Args& args) {
    if (!db) throw std::runtime_error("run_q13: db is null");

    const Customer& cust = db->customer;
    const Orders&   ord  = db->orders;

    // -----------------------------------------------------------------------
    // Step 1: For each order row, precompute whether it is "excluded"
    // (i.e. o_comment LIKE '%word1%word2%').  Excluded orders are NOT counted
    // in the left-outer-join condition, effectively treating them as non-matching.
    // -----------------------------------------------------------------------
    const std::string& word1 = args.WORD1;
    const std::string& word2 = args.WORD2;

    const uint32_t n_orders = ord.row_count;
    std::vector<bool> excluded(n_orders, false);
    for (uint32_t row = 0; row < n_orders; ++row) {
        if (comment_matches(ord.o_comment[row], word1, word2)) {
            excluded[row] = true;
        }
    }

    // -----------------------------------------------------------------------
    // Step 2: For each customer, count qualifying orders using the prebuilt
    // CSR (cust_order_offsets / cust_order_keys).
    //
    // The left outer join means every customer is included: those with no
    // orders (or all orders excluded) get c_count = 0.
    // -----------------------------------------------------------------------
    const uint32_t n_custs  = cust.row_count;
    const uint32_t csr_size = (uint32_t)ord.cust_order_offsets.size(); // max_custkey + 2

    // Accumulate distribution: c_count -> number of customers with that count
    std::unordered_map<int32_t, int64_t> dist;
    dist.reserve(2048);

    for (uint32_t ci = 0; ci < n_custs; ++ci) {
        int32_t ck = cust.c_custkey[ci];
        if (ck < 0) continue;
        uint32_t uck = (uint32_t)ck;

        int32_t c_count = 0;

        if (uck + 1 < csr_size) {
            uint32_t off_begin = ord.cust_order_offsets[uck];
            uint32_t off_end   = ord.cust_order_offsets[uck + 1];

            for (uint32_t off = off_begin; off < off_end; ++off) {
                int32_t ok = ord.cust_order_keys[off];
                if (ok < 0 || (uint32_t)ok >= (uint32_t)ord.orderkey_to_row.size()) continue;
                uint32_t orow = ord.orderkey_to_row[(uint32_t)ok];
                if (orow == 0xFFFFFFFFu) continue;
                // Count this order only if the comment does NOT match the pattern
                if (!excluded[orow]) {
                    ++c_count;
                }
            }
        }
        // else: customer has no CSR entry -> c_count stays 0 (correct for LEFT OUTER JOIN)

        dist[c_count]++;
    }

    // -----------------------------------------------------------------------
    // Step 3: Sort by custdist DESC, c_count DESC
    // -----------------------------------------------------------------------
    std::vector<std::pair<int32_t, int64_t>> result(dist.begin(), dist.end());
    std::sort(result.begin(), result.end(),
              [](const std::pair<int32_t,int64_t>& a,
                 const std::pair<int32_t,int64_t>& b) {
                  if (a.second != b.second) return a.second > b.second; // custdist DESC
                  return a.first > b.first;                              // c_count DESC
              });

    // -----------------------------------------------------------------------
    // Step 4: Assemble output rows
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);
    rows.push_back({"c_count", "custdist"});
    for (const auto& [c_count, custdist] : result) {
        rows.push_back({std::to_string(c_count), std::to_string(custdist)});
    }
    return rows;
}

