// SQL:
/** select
    100.00 * sum(case
        when p_type like 'PROMO%'
        then l_extendedprice*(1-l_discount)
        else 0
    end) / sum(l_extendedprice * (1 - l_discount)) as promo_revenue
from
    lineitem,
    part
where
    l_partkey = p_partkey
    and l_shipdate >= date '[DATE]'
    and l_shipdate < date '[DATE]' + interval '1' month; */

// ---------------------------------------------------------------------------
// Date helpers (days since 1992-01-01 = DATE16 encoding)
// ---------------------------------------------------------------------------
static const int Q14_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};
static bool q14_leap(int y) { return (y%4==0&&y%100!=0)||y%400==0; }

static uint16_t q14_parse_date(const std::string& s) {
    int y = std::stoi(s.substr(0,4));
    int m = std::stoi(s.substr(5,2));
    int d = std::stoi(s.substr(8,2));
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q14_leap(i) ? 366 : 365;
    int lp = q14_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q14_DIM[lp][i-1];
    return static_cast<uint16_t>(tot + (d - 1));
}

// Add one month to a DATE16 value (e.g. 1997-03-01 -> 1997-04-01).
static uint16_t q14_add_one_month(uint16_t date16) {
    // Decode date16 to y/m/d
    int remaining = static_cast<int>(date16);
    int y = 1992;
    while (true) {
        int days_in_year = q14_leap(y) ? 366 : 365;
        if (remaining < days_in_year) break;
        remaining -= days_in_year;
        ++y;
    }
    int lp = q14_leap(y) ? 1 : 0;
    int m = 0; // 0-based month index
    while (remaining >= Q14_DIM[lp][m]) {
        remaining -= Q14_DIM[lp][m];
        ++m;
    }
    int d = remaining; // 0-based day within month
    // Advance one month
    m += 1;
    if (m >= 12) { m = 0; y += 1; }
    // Clamp day to new month's length (handles Jan->Feb edge case)
    int nlp = q14_leap(y) ? 1 : 0;
    if (d >= Q14_DIM[nlp][m]) d = Q14_DIM[nlp][m] - 1;
    // Re-encode
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q14_leap(i) ? 366 : 365;
    int lp2 = q14_leap(y) ? 1 : 0;
    for (int i = 0; i < m; ++i) tot += Q14_DIM[lp2][i];
    tot += d;
    return static_cast<uint16_t>(tot);
}

std::vector<std::vector<std::string>> run_q14(Database* db, const Q14Args& args) {
    if (!db) throw std::runtime_error("run_q14: db is null");

    // -----------------------------------------------------------------------
    // Parse parameters
    // -----------------------------------------------------------------------
    uint16_t date_lo = q14_parse_date(args.DATE);   // inclusive
    uint16_t date_hi = q14_add_one_month(date_lo);   // exclusive

    // -----------------------------------------------------------------------
    // Precompute: for each part type code, does the type start with "PROMO"?
    // -----------------------------------------------------------------------
    const Part& pt = db->part;
    const uint32_t num_types = static_cast<uint32_t>(pt.p_type_dict.size());
    std::vector<bool> type_is_promo(num_types, false);
    for (uint32_t t = 0; t < num_types; ++t) {
        const std::string& tname = pt.p_type_dict[t];
        if (tname.size() >= 5 && tname.compare(0, 5, "PROMO") == 0)
            type_is_promo[t] = true;
    }

    // -----------------------------------------------------------------------
    // Scan lineitem: filter on shipdate, join to part, accumulate sums.
    //
    // Storage encoding:
    //   l_extendedprice: int64, scaled x100 (e.g. 50.00 stored as 5000)
    //   l_discount:      uint8, 0-10  (actual discount = value / 100)
    //
    // disc_price (= extendedprice * (1-discount)) at scale x10000:
    //   disc_price_x10000 = ep_x100 * (100 - disc_x100)
    //
    // We accumulate two int64 sums at scale x10000:
    //   promo_sum: disc_price_x10000 where p_type LIKE 'PROMO%'
    //   total_sum: disc_price_x10000 for all qualifying rows
    //
    // promo_revenue = 100.00 * promo_sum / total_sum  (dimensionless percentage)
    // -----------------------------------------------------------------------
    const Lineitem& li = db->lineitem;
    const uint32_t  n  = li.row_count;

    const uint16_t* sd  = li.l_shipdate.data();
    const int32_t*  lpk = li.l_partkey.data();
    const int64_t*  ep  = li.l_extendedprice.data();
    const uint8_t*  dc  = li.l_discount.data();

    // Part direct-address lookup: partkey -> row index in part arrays
    const uint32_t* pk_to_row  = pt.partkey_to_row.data();
    const uint16_t* type_codes = pt.p_type_code.data();
    const uint32_t  pk_map_sz  = static_cast<uint32_t>(pt.partkey_to_row.size());

    // Use zone-maps to skip chunks of 65536 rows quickly
    constexpr uint32_t CHUNK = 65536;
    const uint32_t num_chunks = static_cast<uint32_t>(li.shipdate_chunk_min.size());

    int64_t promo_sum = 0;
    int64_t total_sum = 0;

    for (uint32_t c = 0; c < num_chunks; ++c) {
        // Skip entire chunk if its shipdate range doesn't overlap [date_lo, date_hi)
        if (li.shipdate_chunk_max[c] < date_lo) continue;
        if (li.shipdate_chunk_min[c] >= date_hi) continue;

        uint32_t row_start = c * CHUNK;
        uint32_t row_end   = std::min(row_start + CHUNK, n);

        for (uint32_t i = row_start; i < row_end; ++i) {
            uint16_t shipdate = sd[i];
            if (shipdate < date_lo || shipdate >= date_hi) continue;

            int32_t  partkey = lpk[i];
            uint32_t pk_u    = static_cast<uint32_t>(partkey);
            if (pk_u >= pk_map_sz) continue;  // safety guard
            uint32_t prow = pk_to_row[pk_u];

            // disc_price at scale x10000 = ep_x100 * (100 - disc_x100)
            int64_t disc_price = ep[i] * static_cast<int64_t>(100 - dc[i]);
            total_sum += disc_price;

            uint16_t tcode = type_codes[prow];
            if (tcode < num_types && type_is_promo[tcode])
                promo_sum += disc_price;
        }
    }

    // -----------------------------------------------------------------------
    // Compute promo_revenue = 100.00 * promo_sum / total_sum
    // Use double for the final division (matches DuckDB's DOUBLE output).
    // Format with 2 decimal places.
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.push_back({"promo_revenue"});

    double promo_revenue = 0.0;
    if (total_sum != 0)
        promo_revenue = (100.0 * static_cast<double>(promo_sum))
                        / static_cast<double>(total_sum);

    // Use round-trip double formatting to match DuckDB's output exactly.
    char buf[32];
    auto [ptr, ec] = std::to_chars(buf, buf + sizeof(buf), promo_revenue);
    std::string result_str;
    if (ec == std::errc()) {
        result_str = std::string(buf, ptr);
    } else {
        std::ostringstream oss;
        oss << std::setprecision(17) << std::defaultfloat << promo_revenue;
        result_str = oss.str();
    }
    rows.push_back({result_str});

    return rows;
}

