// SQL:
/** with revenue (supplier_no, total_revenue) as (
    select
        l_suppkey,
        sum(l_extendedprice * (1 - l_discount))
    from
        lineitem
    where
        l_shipdate >= date '[DATE]'
        and l_shipdate < date '[DATE]' + interval '3' month
    group by
        l_suppkey
)
select
    s_suppkey,
    s_name,
    s_address,
    s_phone,
    total_revenue
from
    supplier,
    revenue
where
    s_suppkey = supplier_no
    and total_revenue = (
        select
            max(total_revenue)
        from
            revenue
    )
order by
    s_suppkey; */

// ---------------------------------------------------------------------------
// Date helpers (days since 1992-01-01 = DATE16 encoding)
// ---------------------------------------------------------------------------
static const int Q15_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};
static bool q15_leap(int y) { return (y%4==0 && y%100!=0) || y%400==0; }

static uint16_t q15_parse_date(const std::string& s) {
    // Parse "YYYY-MM-DD" -> days since 1992-01-01
    int y = std::stoi(s.substr(0, 4));
    int m = std::stoi(s.substr(5, 2));
    int d = std::stoi(s.substr(8, 2));
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q15_leap(i) ? 366 : 365;
    int lp = q15_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q15_DIM[lp][i-1];
    return static_cast<uint16_t>(tot + (d - 1));
}

// Add N months to a DATE16 value.
static uint16_t q15_add_months(uint16_t date16, int months) {
    // Decode date16 to y/m/d
    int remaining = static_cast<int>(date16);
    int y = 1992;
    while (true) {
        int days_in_year = q15_leap(y) ? 366 : 365;
        if (remaining < days_in_year) break;
        remaining -= days_in_year;
        ++y;
    }
    int lp = q15_leap(y) ? 1 : 0;
    int m = 0; // 0-based month index
    while (remaining >= Q15_DIM[lp][m]) {
        remaining -= Q15_DIM[lp][m];
        ++m;
    }
    int d = remaining; // 0-based day within month
    // Advance by 'months' months
    m += months;
    y += m / 12;
    m = m % 12;
    // Clamp day if needed (e.g. Jan 31 + 1 month -> Feb 28/29)
    int nlp = q15_leap(y) ? 1 : 0;
    if (d >= Q15_DIM[nlp][m]) d = Q15_DIM[nlp][m] - 1;
    // Re-encode
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q15_leap(i) ? 366 : 365;
    int lp2 = q15_leap(y) ? 1 : 0;
    for (int i = 0; i < m; ++i) tot += Q15_DIM[lp2][i];
    tot += d;
    return static_cast<uint16_t>(tot);
}

// ---------------------------------------------------------------------------
// Format total_revenue: stored at scale x10000 (ep_x100 * (100-disc_x100)).
// DuckDB outputs DECIMAL(15,2) for this column -> exactly 2 decimal places.
// We divide by 100 to get value_x100, then format with 2dp.
// ---------------------------------------------------------------------------
static std::string fmt_money(int64_t v_x10000) {
    bool neg = v_x10000 < 0;
    if (neg) v_x10000 = -v_x10000;

    // Convert to x100 (2 decimal places) by truncating sub-cent precision
    int64_t value_x100 = v_x10000 / 100;
    int64_t int_part   = value_x100 / 100;
    int64_t frac_part  = value_x100 % 100;

    std::ostringstream oss;
    if (neg) oss << '-';
    oss << int_part << '.' << std::setw(2) << std::setfill('0') << frac_part;
    return oss.str();
}

std::vector<std::vector<std::string>> run_q15(Database* db, const Q15Args& args) {
    if (!db) throw std::runtime_error("run_q15: db is null");

    // -----------------------------------------------------------------------
    // Parse parameters
    // -----------------------------------------------------------------------
    uint16_t date_lo = q15_parse_date(args.DATE);   // inclusive
    uint16_t date_hi = q15_add_months(date_lo, 3);  // exclusive (+3 months)

    // -----------------------------------------------------------------------
    // Step 1: Scan lineitem, accumulate total_revenue per supplier.
    //
    // Storage encoding:
    //   l_extendedprice: int64, scaled x100
    //   l_discount:      uint8, 0..10 (actual discount = value/100)
    //
    // disc_price at scale x10000:
    //   disc_price_x10000 = ep_x100 * (100 - disc_x100)
    //
    // suppkeys are dense 1..N so we use a direct-address array indexed by suppkey.
    // -----------------------------------------------------------------------
    const Lineitem& li  = db->lineitem;
    const Supplier& sup = db->supplier;
    const uint32_t  n   = li.row_count;

    // suppkey_to_row is direct-addressed (size = max_suppkey+1)
    const uint32_t max_suppkey = static_cast<uint32_t>(sup.suppkey_to_row.size()) - 1;

    // revenue_by_suppkey: indexed by suppkey value (1-based), 0 = unused
    std::vector<int64_t> revenue_by_suppkey(max_suppkey + 1, 0LL);

    const uint16_t* sd  = li.l_shipdate.data();
    const int32_t*  lsk = li.l_suppkey.data();
    const int64_t*  ep  = li.l_extendedprice.data();
    const uint8_t*  dc  = li.l_discount.data();

    // Use zone-maps to skip chunks of 65536 rows quickly
    constexpr uint32_t CHUNK = 65536;
    const uint32_t num_chunks = static_cast<uint32_t>(li.shipdate_chunk_min.size());

    for (uint32_t c = 0; c < num_chunks; ++c) {
        if (li.shipdate_chunk_max[c] < date_lo) continue;
        if (li.shipdate_chunk_min[c] >= date_hi) continue;

        uint32_t row_start = c * CHUNK;
        uint32_t row_end   = std::min(row_start + CHUNK, n);

        for (uint32_t i = row_start; i < row_end; ++i) {
            uint16_t shipdate = sd[i];
            if (shipdate < date_lo || shipdate >= date_hi) continue;

            int32_t  sk   = lsk[i];
            uint32_t sk_u = static_cast<uint32_t>(sk);
            if (sk_u > max_suppkey) continue;  // safety guard

            // disc_price at scale x10000 = ep_x100 * (100 - disc_x100)
            int64_t disc_price = ep[i] * static_cast<int64_t>(100 - dc[i]);
            revenue_by_suppkey[sk_u] += disc_price;
        }
    }

    // -----------------------------------------------------------------------
    // Step 2: Find the maximum total_revenue across all suppliers.
    // -----------------------------------------------------------------------
    int64_t max_revenue = 0;
    for (uint32_t sk = 1; sk <= max_suppkey; ++sk) {
        if (revenue_by_suppkey[sk] > max_revenue)
            max_revenue = revenue_by_suppkey[sk];
    }

    // -----------------------------------------------------------------------
    // Step 3: Collect all suppliers where total_revenue == max_revenue,
    // ordered by s_suppkey ascending (natural iteration order).
    // -----------------------------------------------------------------------
    std::vector<uint32_t> result_suppkeys;
    for (uint32_t sk = 1; sk <= max_suppkey; ++sk) {
        if (revenue_by_suppkey[sk] == max_revenue)
            result_suppkeys.push_back(sk);
    }

    // -----------------------------------------------------------------------
    // Step 4: Build output rows.
    // Header: s_suppkey, s_name, s_address, s_phone, total_revenue
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.push_back({"s_suppkey", "s_name", "s_address", "s_phone", "total_revenue"});

    for (uint32_t sk : result_suppkeys) {
        uint32_t srow = sup.suppkey_to_row[sk];

        std::string suppkey_str = std::to_string(sup.s_suppkey[srow]);
        const std::string& sname    = sup.s_name[srow];
        const std::string& saddress = sup.s_address[srow];
        const std::string& sphone   = sup.s_phone[srow];
        std::string rev_str = fmt_money(revenue_by_suppkey[sk]);

        rows.push_back({suppkey_str, sname, saddress, sphone, rev_str});
    }

    return rows;
}

