// ---------------------------------------------------------------------------
// Q16
//
// SELECT p_brand, p_type, p_size, COUNT(DISTINCT ps_suppkey) AS supplier_cnt
// FROM partsupp, part
// WHERE p_partkey = ps_partkey
//   AND p_brand <> '[BRAND]'
//   AND p_type NOT LIKE '[TYPE]%'
//   AND p_size IN ([SIZE1]..[SIZE8])
//   AND ps_suppkey NOT IN (
//       SELECT s_suppkey FROM supplier WHERE s_comment LIKE '%Customer%Complaints%'
//   )
// GROUP BY p_brand, p_type, p_size
// ORDER BY supplier_cnt DESC, p_brand, p_type, p_size;
//
// Plan:
//  1. Parse the 8 size values into a small bool array indexed by value (1..50).
//  2. Resolve the excluded brand code and the set of excluded type codes
//     (those whose string starts with TYPE prefix).
//  3. Build a flat bool vector indexed by suppkey for O(1) "is bad" lookup.
//  4. For each qualifying part row, scan its contiguous partsupp rows
//     (partsupp is sorted by partkey), skip bad suppkeys, and accumulate
//     distinct suppkeys per group key (brand_code, type_code, size).
//  5. Materialise result rows, sort, and emit CSV.
// ---------------------------------------------------------------------------

std::vector<std::vector<std::string>> run_q16(Database* db, const Q16Args& args) {
    if (!db) {
        throw std::runtime_error("run_q16: db is null");
    }

    const Part&     prt = db->part;
    const PartSupp& ps  = db->partsupp;
    const Supplier& sup = db->supplier;

    // ------------------------------------------------------------------
    // Step 1: parse the 8 sizes into a small bool array (values 1..50)
    // NULL values from IN-list are represented as "<<NULL>>" – skip them.
    // ------------------------------------------------------------------
    bool size_in_set[51] = {};  // index 0 unused; values 1..50
    const std::string* size_args[8] = {
        &args.SIZE1, &args.SIZE2, &args.SIZE3, &args.SIZE4,
        &args.SIZE5, &args.SIZE6, &args.SIZE7, &args.SIZE8
    };
    for (int i = 0; i < 8; ++i) {
        const std::string& sv = *size_args[i];
        if (sv == "<<NULL>>") continue;
        int sz = std::stoi(sv);
        if (sz >= 1 && sz <= 50) {
            size_in_set[sz] = true;
        }
    }

    // ------------------------------------------------------------------
    // Step 2a: resolve excluded brand code
    // ------------------------------------------------------------------
    int brand_exclude_code = -1;
    for (int i = 0; i < (int)prt.p_brand_dict.size(); ++i) {
        if (prt.p_brand_dict[i] == args.BRAND) {
            brand_exclude_code = i;
            break;
        }
    }

    // ------------------------------------------------------------------
    // Step 2b: build excluded type-code set
    // p_type NOT LIKE '[TYPE]%'  =>  type string must NOT start with args.TYPE
    // ------------------------------------------------------------------
    const std::string& type_prefix = args.TYPE;
    std::vector<bool> type_excluded(prt.p_type_dict.size(), false);
    for (int i = 0; i < (int)prt.p_type_dict.size(); ++i) {
        const std::string& t = prt.p_type_dict[i];
        if (t.size() >= type_prefix.size() &&
            t.compare(0, type_prefix.size(), type_prefix) == 0) {
            type_excluded[i] = true;
        }
    }

    // ------------------------------------------------------------------
    // Step 3: build flat bad-suppkey vector indexed by suppkey value
    // s_bad_comment is indexed by supplier *row*; suppkey_to_row maps
    // suppkey -> row.  We invert: iterate all supplier rows.
    // ------------------------------------------------------------------
    uint32_t max_sk = static_cast<uint32_t>(sup.suppkey_to_row.size());
    std::vector<bool> suppkey_is_bad(max_sk, false);
    for (uint32_t row = 0; row < sup.row_count; ++row) {
        if (sup.s_bad_comment.test(row)) {
            int32_t sk = sup.s_suppkey[row];
            if (sk > 0 && static_cast<uint32_t>(sk) < max_sk) {
                suppkey_is_bad[static_cast<uint32_t>(sk)] = true;
            }
        }
    }

    // ------------------------------------------------------------------
    // Step 4: scan qualifying parts, gather distinct suppkeys per group.
    //
    // Group key packed as uint32_t:
    //   bits[31:24] = p_brand_code (uint8)
    //   bits[23:8]  = p_type_code  (uint16)
    //   bits[7:0]   = p_size       (uint8, 1..50)
    //
    // partsupp rows are sorted by ps_partkey, so for a given pk we scan
    // contiguously starting at partkey_to_first_row[pk].
    // ------------------------------------------------------------------
    std::unordered_map<uint32_t, std::unordered_set<int32_t>> group_supps;
    group_supps.reserve(4096);

    uint32_t n_parts = prt.row_count;
    // partkey_to_first_row has size max_pk+1; value 0xFFFFFFFF means no rows.
    uint32_t ps_size = static_cast<uint32_t>(ps.partkey_to_first_row.size());
    uint32_t n_ps    = ps.row_count;

    for (uint32_t row = 0; row < n_parts; ++row) {
        // --- brand filter: p_brand <> BRAND ---
        uint8_t bc = prt.p_brand_code[row];
        if (brand_exclude_code >= 0 && (int)bc == brand_exclude_code) continue;

        // --- type filter: p_type NOT LIKE '[TYPE]%' ---
        uint16_t tc = prt.p_type_code[row];
        if (tc < (uint16_t)type_excluded.size() && type_excluded[tc]) continue;

        // --- size filter: p_size IN sizes ---
        uint8_t sz = prt.p_size[row];
        if (sz == 0 || sz > 50 || !size_in_set[sz]) continue;

        // This part qualifies.
        int32_t pk = prt.p_partkey[row];
        if (pk <= 0 || static_cast<uint32_t>(pk) >= ps_size) continue;

        uint32_t ps_first = ps.partkey_to_first_row[static_cast<uint32_t>(pk)];
        if (ps_first == 0xFFFFFFFFu || ps_first >= n_ps) continue;

        // Pack group key
        uint32_t gk = ((uint32_t)bc << 24) | ((uint32_t)tc << 8) | (uint32_t)sz;
        auto& supp_set = group_supps[gk];

        // Iterate contiguous partsupp rows for this partkey
        for (uint32_t r = ps_first; r < n_ps && ps.ps_partkey[r] == pk; ++r) {
            int32_t sk = ps.ps_suppkey[r];
            if (sk <= 0 || static_cast<uint32_t>(sk) >= max_sk) continue;
            if (suppkey_is_bad[static_cast<uint32_t>(sk)]) continue;
            supp_set.insert(sk);
        }
    }

    // ------------------------------------------------------------------
    // Step 5: materialise result rows, sort, emit
    // ------------------------------------------------------------------
    struct ResultRow {
        std::string p_brand;
        std::string p_type;
        uint8_t     p_size_val;
        int32_t     supplier_cnt;
    };

    std::vector<ResultRow> result;
    result.reserve(group_supps.size());

    for (auto& [gk, supp_set] : group_supps) {
        if (supp_set.empty()) continue;
        uint8_t  bc2 = (uint8_t)((gk >> 24) & 0xFF);
        uint16_t tc2 = (uint16_t)((gk >>  8) & 0xFFFF);
        uint8_t  sz2 = (uint8_t)(gk & 0xFF);

        result.push_back({
            prt.p_brand_dict[bc2],
            prt.p_type_dict[tc2],
            sz2,
            (int32_t)supp_set.size()
        });
    }

    // ORDER BY supplier_cnt DESC, p_brand ASC, p_type ASC, p_size ASC
    std::sort(result.begin(), result.end(), [](const ResultRow& a, const ResultRow& b) {
        if (a.supplier_cnt != b.supplier_cnt) return a.supplier_cnt > b.supplier_cnt;
        if (a.p_brand      != b.p_brand)      return a.p_brand      < b.p_brand;
        if (a.p_type       != b.p_type)       return a.p_type       < b.p_type;
        return a.p_size_val < b.p_size_val;
    });

    // Assemble output rows (header + data)
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);
    rows.push_back({"p_brand", "p_type", "p_size", "supplier_cnt"});

    for (const auto& rr : result) {
        rows.push_back({
            rr.p_brand,
            rr.p_type,
            std::to_string(rr.p_size_val),
            std::to_string(rr.supplier_cnt)
        });
    }

    return rows;
}

