        &args.SIZE1, &args.SIZE2, &args.SIZE3, &args.SIZE4,
        &args.SIZE5, &args.SIZE6, &args.SIZE7, &args.SIZE8
    };
    uint64_t size_mask = 0; // bitmask for sizes 1..50 (bit i = size i)
    for (int i = 0; i < 8; ++i) {
        const std::string& sv = *size_args[i];
        if (sv == "<<NULL>>") continue;
        int sz = std::stoi(sv);
        if (sz >= 1 && sz <= 50) {
            size_in_set[sz] = true;
            size_mask |= (1ULL << sz);
        }
    }

    TRACE_COUNT("q16_n_parts",         static_cast<int64_t>(prt.row_count));
    TRACE_COUNT("q16_n_partsupp",      static_cast<int64_t>(ps.row_count));
    TRACE_COUNT("q16_n_suppliers",     static_cast<int64_t>(sup.row_count));
    TRACE_COUNT("q16_brand_dict_size", static_cast<int64_t>(prt.p_brand_dict.size()));
    TRACE_COUNT("q16_type_dict_size",  static_cast<int64_t>(prt.p_type_dict.size()));

    // ------------------------------------------------------------------
    // Step 2a: resolve excluded brand code
    // ------------------------------------------------------------------
    int brand_exclude_code = -1;
    for (int i = 0; i < (int)prt.p_brand_dict.size(); ++i) {
        if (prt.p_brand_dict[i] == args.BRAND) {
            brand_exclude_code = i;
            break;
        }
    }

    // ------------------------------------------------------------------
    // Step 2b: build excluded type-code set
    // p_type NOT LIKE '[TYPE]%'  =>  type string must NOT start with args.TYPE
    // ------------------------------------------------------------------
    const std::string& type_prefix = args.TYPE;
    std::vector<bool> type_excluded(prt.p_type_dict.size(), false);
    for (int i = 0; i < (int)prt.p_type_dict.size(); ++i) {
        const std::string& t = prt.p_type_dict[i];
        if (t.size() >= type_prefix.size() &&
            t.compare(0, type_prefix.size(), type_prefix) == 0) {
