    // ------------------------------------------------------------------
    uint32_t max_sk = static_cast<uint32_t>(sup.suppkey_to_row.size());
    std::vector<bool> suppkey_is_bad(max_sk, false);
    int64_t bad_supplier_count = 0;
    for (uint32_t row = 0; row < sup.row_count; ++row) {
        if (sup.s_bad_comment.test(row)) {
            int32_t sk = sup.s_suppkey[row];
            if (sk > 0 && static_cast<uint32_t>(sk) < max_sk) {
                suppkey_is_bad[static_cast<uint32_t>(sk)] = true;
                ++bad_supplier_count;
            }
        }
    }
    TRACE_COUNT("q16_bad_suppliers",       bad_supplier_count);
    TRACE_COUNT("q16_brand_excluded_code", static_cast<int64_t>(brand_exclude_code));
    {
        int64_t cnt = 0;
        for (bool b : type_excluded) { if (b) ++cnt; }
        TRACE_COUNT("q16_type_codes_excluded", cnt);
    }

    // ------------------------------------------------------------------
    // Step 4: scan qualifying parts, gather (group_key, suppkey) pairs.
    //
    // Group key packed as uint32_t:
    //   bits[31:24] = p_brand_code (uint8)
    //   bits[23:8]  = p_type_code  (uint16)
    //   bits[7:0]   = p_size       (uint8, 1..50)
    //
    // partsupp rows are sorted by ps_partkey, so for a given pk we scan
    // contiguously starting at partkey_to_first_row[pk].
    //
    // Instead of per-group unordered_set (expensive allocations), we
    // collect all (group_key, suppkey) pairs into a flat array, then
    // sort and count distinct via a linear sweep.
    // ------------------------------------------------------------------

    uint32_t n_parts = prt.row_count;
    uint32_t ps_size = static_cast<uint32_t>(ps.partkey_to_first_row.size());
    uint32_t n_ps    = ps.row_count;

    // Estimate output: ~15% of parts qualify * 4 partsupp rows each
    // Reserve generously to avoid reallocs
    std::vector<uint64_t> pairs; // packed: bits[63:32]=group_key, bits[31:0]=suppkey
    pairs.reserve(n_parts / 6 * 4 + 1024);

    {
    PROFILE_SCOPE("q16_part_scan");

    for (uint32_t row = 0; row < n_parts; ++row) {
        // --- brand filter: p_brand <> BRAND ---
        uint8_t bc = prt.p_brand_code[row];
        if (brand_exclude_code >= 0 && (int)bc == brand_exclude_code) continue;

        // --- type filter: p_type NOT LIKE '[TYPE]%' ---
        uint16_t tc = prt.p_type_code[row];
        if (tc < (uint16_t)type_excluded.size() && type_excluded[tc]) continue;

        // --- size filter: p_size IN sizes ---
        uint8_t sz = prt.p_size[row];
        if (sz == 0 || sz > 50 || !size_in_set[sz]) continue;

        int32_t pk = prt.p_partkey[row];
        if (pk <= 0 || static_cast<uint32_t>(pk) >= ps_size) continue;

        uint32_t ps_first = ps.partkey_to_first_row[static_cast<uint32_t>(pk)];
        if (ps_first == 0xFFFFFFFFu || ps_first >= n_ps) continue;

        // Pack group key
        uint32_t gk = ((uint32_t)bc << 24) | ((uint32_t)tc << 8) | (uint32_t)sz;

        // Iterate contiguous partsupp rows for this partkey
        for (uint32_t r = ps_first; r < n_ps && ps.ps_partkey[r] == pk; ++r) {
            int32_t sk = ps.ps_suppkey[r];
            if (sk <= 0 || static_cast<uint32_t>(sk) >= max_sk) continue;
            if (suppkey_is_bad[static_cast<uint32_t>(sk)]) continue;
            // Pack (group_key, suppkey) into a single uint64 for cache-friendly sort
            pairs.push_back(((uint64_t)gk << 32) | (uint32_t)sk);
        }
    }

    } // end PROFILE_SCOPE

    // ------------------------------------------------------------------
    // Step 5: sort pairs, count distinct suppkeys per group, emit result
    // ------------------------------------------------------------------

    // Sort by (group_key, suppkey) — single integer comparison on uint64
    std::sort(pairs.begin(), pairs.end());

    struct ResultRow {
        std::string p_brand;
        std::string p_type;
        uint8_t     p_size_val;
        int32_t     supplier_cnt;
    };

    std::vector<ResultRow> result;
    result.reserve(4096);

    // Linear scan over sorted pairs: group runs of same gk, count distinct sk
    {
        const size_t n = pairs.size();
        size_t i = 0;
        while (i < n) {
            uint64_t first = pairs[i];
            uint32_t cur_gk = (uint32_t)(first >> 32);
            uint32_t prev_sk = (uint32_t)(first & 0xFFFFFFFFu);
            int32_t cnt = 1;
            size_t j = i + 1;
            while (j < n) {
                uint64_t p = pairs[j];
                uint32_t gk2 = (uint32_t)(p >> 32);
                if (gk2 != cur_gk) break;
                uint32_t sk2 = (uint32_t)(p & 0xFFFFFFFFu);
                if (sk2 != prev_sk) {
                    ++cnt;
                    prev_sk = sk2;
                }
                ++j;
            }
            i = j;

            uint8_t  bc2 = (uint8_t)((cur_gk >> 24) & 0xFF);
            uint16_t tc2 = (uint16_t)((cur_gk >>  8) & 0xFFFF);
            uint8_t  sz2 = (uint8_t)(cur_gk & 0xFF);
            result.push_back({
                prt.p_brand_dict[bc2],
                prt.p_type_dict[tc2],
                sz2,
                cnt
            });
        }
    }

    // ORDER BY supplier_cnt DESC, p_brand ASC, p_type ASC, p_size ASC
    std::sort(result.begin(), result.end(), [](const ResultRow& a, const ResultRow& b) {
        if (a.supplier_cnt != b.supplier_cnt) return a.supplier_cnt > b.supplier_cnt;
        if (a.p_brand      != b.p_brand)      return a.p_brand      < b.p_brand;
        if (a.p_type       != b.p_type)       return a.p_type       < b.p_type;
        return a.p_size_val < b.p_size_val;
    });

    // Assemble output rows (header + data)
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);
    rows.push_back({"p_brand", "p_type", "p_size", "supplier_cnt"});

    for (const auto& rr : result) {
        rows.push_back({
            rr.p_brand,
            rr.p_type,
            std::to_string(rr.p_size_val),
            std::to_string(rr.supplier_cnt)
        });
    }

    TRACE_COUNT("q16_output_rows", static_cast<int64_t>(rows.size() - 1));
    return rows;
}

