#include <cmath>

// SQL:
/** select
    sum (l_extendedprice) / 7.0 as avg_yearly
from
    lineitem,
    part
where
    p_partkey = l_partkey
    and p_brand = '[BRAND]'
    and p_container = '[CONTAINER]'
    and l_quantity < (
        select
            0.2 * avg(l_quantity)
        from
            lineitem
        where
            l_partkey = p_partkey
    ); */

// ---------------------------------------------------------------------------
// Format helper: scaled integer -> decimal string with at least 2 decimal
// places (trailing zeros stripped beyond 2dp).
// ---------------------------------------------------------------------------
static std::string q17_fmt_scaled(int64_t v, int scale) {
    bool neg = (v < 0);
    if (neg) v = -v;
    int64_t div = 1;
    for (int i = 0; i < scale; ++i) div *= 10;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << v / div << '.' << std::setw(scale) << std::setfill('0') << v % div;
    std::string s = oss.str();
    size_t dot  = s.find('.');
    size_t last = s.size() - 1;
    while (last > dot + 2 && s[last] == '0') --last;
    s.resize(last + 1);
    return s;
}

std::vector<std::vector<std::string>> run_q17(Database* db, const Q17Args& args) {
    if (!db) {
        throw std::runtime_error("run_q17: db is null");
    }

    const Part&     pt = db->part;
    const Lineitem& li = db->lineitem;

    // -----------------------------------------------------------------------
    // Step 1: resolve brand code and container code from dictionaries.
    // -----------------------------------------------------------------------
    uint8_t brand_code = 0xFF;
    for (uint32_t i = 0; i < (uint32_t)pt.p_brand_dict.size(); ++i) {
        if (pt.p_brand_dict[i] == args.BRAND) {
            brand_code = static_cast<uint8_t>(i);
            break;
        }
    }
    uint8_t container_code = 0xFF;
    for (uint32_t i = 0; i < (uint32_t)pt.p_container_dict.size(); ++i) {
        if (pt.p_container_dict[i] == args.CONTAINER) {
            container_code = static_cast<uint8_t>(i);
            break;
        }
    }

    // -----------------------------------------------------------------------
    // Step 2: collect qualifying partkeys (brand AND container match).
    // -----------------------------------------------------------------------
    const uint32_t max_pk = static_cast<uint32_t>(pt.partkey_to_row.size());

    // Direct-addressed match bitmap over partkey space
    std::vector<uint8_t> pk_match(max_pk, 0);
    std::vector<int32_t> qualifying_partkeys;
    qualifying_partkeys.reserve(512);

    if (brand_code != 0xFF && container_code != 0xFF) {
        for (uint32_t pk = 1; pk < max_pk; ++pk) {
            uint32_t row = pt.partkey_to_row[pk];
            // partkey_to_row[pk]==0 is valid for pk==p_partkey[0]; for others 0 means unused.
            // Check that the part at 'row' actually has this partkey.
            if (row == 0 && (pt.p_partkey.empty() || pt.p_partkey[0] != (int32_t)pk)) continue;
            if (pt.p_brand_code[row]     == brand_code &&
                pt.p_container_code[row] == container_code) {
                pk_match[pk] = 1;
                qualifying_partkeys.push_back(static_cast<int32_t>(pk));
            }
        }
    }

    // Per-partkey accumulators indexed directly by partkey
    std::vector<int64_t> qty_sum(max_pk, 0);
    std::vector<int64_t> qty_cnt(max_pk, 0);

    // -----------------------------------------------------------------------
    // Step 3: first pass — accumulate qty_sum and qty_cnt for qualifying parts.
    // -----------------------------------------------------------------------
    const uint32_t n   = li.row_count;
    const int32_t*  lpk = li.l_partkey.data();
    const uint8_t*  qty = li.l_quantity.data();
    const int64_t*  ep  = li.l_extendedprice.data();

    for (uint32_t i = 0; i < n; ++i) {
        uint32_t pk = static_cast<uint32_t>(lpk[i]);
        if (pk >= max_pk || !pk_match[pk]) continue;
        qty_sum[pk] += qty[i];
        qty_cnt[pk] += 1;
    }

    // -----------------------------------------------------------------------
    // Step 4: second pass — apply quantity filter, accumulate extendedprice.
    //
    // Condition: l_quantity < 0.2 * avg(l_quantity)
    //          = l_quantity < 0.2 * (qty_sum / qty_cnt)
    //          ⟺ l_quantity * 5 * qty_cnt < qty_sum   (integer, no FP needed)
    // -----------------------------------------------------------------------
    std::vector<int64_t> ep_sum(max_pk, 0);

    for (uint32_t i = 0; i < n; ++i) {
        uint32_t pk = static_cast<uint32_t>(lpk[i]);
        if (pk >= max_pk || !pk_match[pk]) continue;
        int64_t cnt = qty_cnt[pk];
        if (cnt == 0) continue;
        // integer check: qty < 0.2 * (qty_sum/cnt)  ⟺  qty * 5 * cnt < qty_sum
        if (static_cast<int64_t>(qty[i]) * 5LL * cnt < qty_sum[pk]) {
            ep_sum[pk] += ep[i];
        }
    }

    // -----------------------------------------------------------------------
    // Step 5: sum filtered extendedprices across all qualifying parts, divide by 7.0.
    //
    // l_extendedprice is stored scaled x100 (e.g. 50.00 → 5000).
    // avg_yearly = sum(l_extendedprice_raw) / 7.0
    // As actual value: avg_yearly_actual = total_raw / 100.0 / 7.0
    //                                    = total_raw / 700.0
    // -----------------------------------------------------------------------
    int64_t total_ep_raw = 0;
    for (int32_t pk : qualifying_partkeys) {
        total_ep_raw += ep_sum[static_cast<uint32_t>(pk)];
    }

    double avg_yearly = static_cast<double>(total_ep_raw) / 700.0;

    // Round to cents (2 decimal places) then format.
    int64_t avg_yearly_x100 = static_cast<int64_t>(std::round(avg_yearly * 100.0));

    std::vector<std::vector<std::string>> rows;
    rows.push_back({"avg_yearly"});
    rows.push_back({q17_fmt_scaled(avg_yearly_x100, 2)});
    return rows;
}

