    //          = l_quantity < 0.2 * (qty_sum / qty_cnt)
    //          ⟺ l_quantity * 5 * qty_cnt < qty_sum   (integer, no FP needed)
    // -----------------------------------------------------------------------
    std::vector<int64_t> ep_sum(max_pk, 0);

    int64_t pass2_rows_hit      = 0;
    int64_t pass2_rows_accepted = 0;

    {
    PROFILE_SCOPE("q17_pass2_filter");
    for (uint32_t i = 0; i < n; ++i) {
        uint32_t pk = static_cast<uint32_t>(lpk[i]);
        if (pk >= max_pk || !pk_match[pk]) continue;
        ++pass2_rows_hit;
        int64_t cnt = qty_cnt[pk];
        if (cnt == 0) continue;
        // integer check: qty < 0.2 * (qty_sum/cnt)  ⟺  qty * 5 * cnt < qty_sum
        if (static_cast<int64_t>(qty[i]) * 5LL * cnt < qty_sum[pk]) {
            ep_sum[pk] += ep[i];
            ++pass2_rows_accepted;
        }
    }
    }

    TRACE_COUNT("q17_pass2_rows_hit",      pass2_rows_hit);
    TRACE_COUNT("q17_pass2_rows_accepted", pass2_rows_accepted);

    // -----------------------------------------------------------------------
    // Step 5: sum filtered extendedprices across all qualifying parts, divide by 7.0.
    //
    // l_extendedprice is stored scaled x100 (e.g. 50.00 → 5000).
    // avg_yearly = sum(l_extendedprice_raw) / 7.0
    // As actual value: avg_yearly_actual = total_raw / 100.0 / 7.0
    //                                    = total_raw / 700.0
    // -----------------------------------------------------------------------
    int64_t total_ep_raw = 0;
    for (int32_t pk : qualifying_partkeys) {
        total_ep_raw += ep_sum[static_cast<uint32_t>(pk)];
    }

    double avg_yearly = static_cast<double>(total_ep_raw) / 700.0;

    TRACE_COUNT("q17_total_ep_raw",    total_ep_raw);

    // Round to cents (2 decimal places) then format.
    int64_t avg_yearly_x100 = static_cast<int64_t>(std::round(avg_yearly * 100.0));

    TRACE_COUNT("q17_avg_yearly_x100", avg_yearly_x100);

    std::vector<std::vector<std::string>> rows;
    rows.push_back({"avg_yearly"});
    rows.push_back({q17_fmt_scaled(avg_yearly_x100, 2)});

    TRACE_COUNT("q17_output_rows", static_cast<int64_t>(rows.size() - 1));
    return rows;
}

