// SQL:
/**
 * select
 *     c_name, c_custkey, o_orderkey, o_orderdate, o_totalprice, sum(l_quantity)
 * from customer, orders, lineitem
 * where
 *     o_orderkey in (
 *         select l_orderkey from lineitem
 *         group by l_orderkey having sum(l_quantity) > [QUANTITY]
 *     )
 *     and c_custkey = o_custkey
 *     and o_orderkey = l_orderkey
 * group by c_name, c_custkey, o_orderkey, o_orderdate, o_totalprice
 * order by o_totalprice desc, o_orderdate;
 */

// ---------------------------------------------------------------------------
// Format helpers
// ---------------------------------------------------------------------------

// DATE16 (days since 1992-01-01) -> "YYYY-MM-DD"
static std::string q18_fmt_date(uint16_t d16) {
    static const int DIM[2][12] = {
        {31,28,31,30,31,30,31,31,30,31,30,31},
        {31,29,31,30,31,30,31,31,30,31,30,31}
    };
    int rem = static_cast<int>(d16);
    int y = 1992;
    while (true) {
        int dy = ((y % 4 == 0 && y % 100 != 0) || y % 400 == 0) ? 366 : 365;
        if (rem < dy) break;
        rem -= dy; ++y;
    }
    int lp = ((y % 4 == 0 && y % 100 != 0) || y % 400 == 0) ? 1 : 0;
    int m = 1;
    while (m <= 12 && rem >= DIM[lp][m - 1]) { rem -= DIM[lp][m - 1]; ++m; }
    char buf[12];
    std::snprintf(buf, sizeof(buf), "%04d-%02d-%02d", y, m, rem + 1);
    return std::string(buf);
}

// int64 scaled *100 -> "NNNN.NN" with exactly 2 decimal places
static std::string q18_fmt_money(int64_t v) {
    bool neg = (v < 0); if (neg) v = -v;
    int64_t whole = v / 100;
    int64_t frac  = v % 100;
    char buf[32];
    if (neg)
        std::snprintf(buf, sizeof(buf), "-%" PRId64 ".%02" PRId64, whole, frac);
    else
        std::snprintf(buf, sizeof(buf), "%" PRId64 ".%02" PRId64, whole, frac);
    return std::string(buf);
}

// ---------------------------------------------------------------------------
// Result row
// ---------------------------------------------------------------------------
struct Q18Row {
    int32_t  custkey;
    int32_t  orderkey;
    uint16_t orderdate;
    int64_t  totalprice;   // scaled *100
    int64_t  sum_qty;      // sum of l_quantity for this order
};

std::vector<std::vector<std::string>> run_q18(Database* db, const Q18Args& args) {
    if (!db) {
        throw std::runtime_error("run_q18: db is null");
    }

    // ------------------------------------------------------------------
    // Step 0: parse QUANTITY threshold
    // ------------------------------------------------------------------
    int64_t qty_threshold = 0;
    if (args.QUANTITY != "<<NULL>>") {
        qty_threshold = static_cast<int64_t>(std::stoi(args.QUANTITY));
    }

    const Lineitem& li   = db->lineitem;
    const Orders&   ord  = db->orders;
    const Customer& cust = db->customer;

    const uint32_t n_li      = li.row_count;
    const uint32_t li_idx_sz = static_cast<uint32_t>(li.orderkey_to_first_li.size());
    const uint32_t ok_map_sz = static_cast<uint32_t>(ord.orderkey_to_row.size());
    const uint32_t ck_map_sz = static_cast<uint32_t>(cust.custkey_to_row.size());

    // ------------------------------------------------------------------
    // Step 1: Subquery — scan all lineitems, sum l_quantity per orderkey,
    //         collect orderkeys where sum > qty_threshold.
    //         l_quantity is stored as the actual quantity (uint8, 1..50).
    // ------------------------------------------------------------------

    // Direct-addressed array over orderkeys (same size as orderkey_to_row).
    std::vector<int32_t> ok_sum_qty(ok_map_sz, 0);

    for (uint32_t i = 0; i < n_li; ++i) {
        int32_t ok = li.l_orderkey[i];
        if (ok >= 0 && static_cast<uint32_t>(ok) < ok_map_sz) {
            ok_sum_qty[static_cast<uint32_t>(ok)] +=
                static_cast<int32_t>(li.l_quantity[i]);
        }
    }

    // ------------------------------------------------------------------
    // Step 2: Scan orders; for each order whose orderkey passes the
    //         subquery filter, join with customer and re-sum l_quantity
    //         from the outer query's lineitem scan.
    // ------------------------------------------------------------------
    std::vector<Q18Row> results;
    results.reserve(512);

    const uint32_t n_orders = ord.row_count;
    for (uint32_t oi = 0; oi < n_orders; ++oi) {
        int32_t  ok  = ord.o_orderkey[oi];
        uint32_t uok = static_cast<uint32_t>(ok);

        // Subquery filter: sum(l_quantity) > qty_threshold
        if (uok >= ok_map_sz) continue;
        if (static_cast<int64_t>(ok_sum_qty[uok]) <= qty_threshold) continue;

        // Locate lineitem range for this orderkey
        if (uok >= li_idx_sz) continue;
        uint32_t li_start = li.orderkey_to_first_li[uok];
        if (li_start == 0xFFFFFFFFu) continue;

        // Sum l_quantity for this order (outer query re-aggregation)
        int64_t sum_qty = 0;
        for (uint32_t lr = li_start;
             lr < n_li && li.l_orderkey[lr] == ok;
             ++lr) {
            sum_qty += static_cast<int64_t>(li.l_quantity[lr]);
        }

        Q18Row r;
        r.orderkey   = ok;
        r.custkey    = ord.o_custkey[oi];
        r.orderdate  = ord.o_orderdate[oi];
        r.totalprice = ord.o_totalprice[oi];
        r.sum_qty    = sum_qty;
        results.push_back(r);
    }

    // ------------------------------------------------------------------
    // Step 3: Sort by o_totalprice DESC, then o_orderdate ASC
    // ------------------------------------------------------------------
    std::sort(results.begin(), results.end(), [](const Q18Row& a, const Q18Row& b) {
        if (a.totalprice != b.totalprice) return a.totalprice > b.totalprice;
        return a.orderdate < b.orderdate;
    });

    // ------------------------------------------------------------------
    // Step 4: Assemble output rows
    // ------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(results.size() + 1);
    rows.push_back({"c_name", "c_custkey", "o_orderkey", "o_orderdate",
                    "o_totalprice", "sum(l_quantity)"});

    for (const Q18Row& r : results) {
        int32_t  ck   = r.custkey;
        uint32_t crow = (ck >= 0 && static_cast<uint32_t>(ck) < ck_map_sz)
                        ? cust.custkey_to_row[static_cast<uint32_t>(ck)]
                        : 0xFFFFFFFFu;
        std::string c_name = (crow != 0xFFFFFFFFu) ? cust.c_name[crow] : "";

        rows.push_back({
            c_name,
            std::to_string(ck),
            std::to_string(r.orderkey),
            q18_fmt_date(r.orderdate),
            q18_fmt_money(r.totalprice),
            std::to_string(r.sum_qty)
        });
    }

    return rows;
}

