        p_partkey = l_partkey
        and p_brand = '[BRAND1]'
        and p_container in ( 'SM CASE', 'SM BOX', 'SM PACK', 'SM PKG')
        and l_quantity >= [QUANTITY1] and l_quantity <= [QUANTITY1] + 10
        and p_size between 1 and 5
        and l_shipmode in ('AIR', 'AIR REG')
        and l_shipinstruct = 'DELIVER IN PERSON'
    )
    or
    (
        p_partkey = l_partkey
        and p_brand = '[BRAND2]'
        and p_container in ('MED BAG', 'MED BOX', 'MED PKG', 'MED PACK')
        and l_quantity >= [QUANTITY2] and l_quantity <= [QUANTITY2] + 10
        and p_size between 1 and 10
        and l_shipmode in ('AIR', 'AIR REG')
        and l_shipinstruct = 'DELIVER IN PERSON'
    )
    or
    (
        p_partkey = l_partkey
        and p_brand = '[BRAND3]'
        and p_container in ( 'LG CASE', 'LG BOX', 'LG PACK', 'LG PKG')
        and l_quantity >= [QUANTITY3] and l_quantity <= [QUANTITY3] + 10
        and p_size between 1 and 15
        and l_shipmode in ('AIR', 'AIR REG')
        and l_shipinstruct = 'DELIVER IN PERSON'
    ); */

// ---------------------------------------------------------------------------
// Format helper: scaled integer -> decimal string with >= 2 decimal places
// ---------------------------------------------------------------------------
static std::string q19_fmt_scaled(int64_t v, int scale) {
    bool neg = (v < 0);
    if (neg) v = -v;
    int64_t divisor = 1;
    for (int i = 0; i < scale; ++i) divisor *= 10;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << v / divisor << '.' << std::setw(scale) << std::setfill('0') << v % divisor;
    std::string s = oss.str();
    size_t dot  = s.find('.');
    size_t last = s.size() - 1;
    while (last > dot + 2 && s[last] == '0') --last;
    s.resize(last + 1);
    return s;
}

// ---------------------------------------------------------------------------
// Helper: find code for a string value in a dict, returns 0xFF if not found
// ---------------------------------------------------------------------------
static uint8_t find_code8(const std::vector<std::string>& dict, const std::string& val) {
    for (uint32_t i = 0; i < (uint32_t)dict.size(); ++i)
        if (dict[i] == val) return static_cast<uint8_t>(i);
    return 0xFF; // not found => no rows will match
}

// ---------------------------------------------------------------------------
// Per-partkey classification for the three OR branches.
// Stored as a bitmask: bit0=branch1, bit1=branch2, bit2=branch3
// 0 means the part does not qualify for any branch.
// ---------------------------------------------------------------------------
static constexpr uint8_t BRANCH1 = 0x01;
static constexpr uint8_t BRANCH2 = 0x02;
static constexpr uint8_t BRANCH3 = 0x04;

std::vector<std::vector<std::string>> run_q19(Database* db, const Q19Args& args) {
    if (!db) {
        throw std::runtime_error("run_q19: db is null");
    }

    PROFILE_SCOPE("q19_total");

    const Part&     pt = db->part;
    const Lineitem& li = db->lineitem;

    // -----------------------------------------------------------------------
    // Parse quantity bounds (stored as uint8 whole numbers 1..50)
    // -----------------------------------------------------------------------
    uint8_t qty1 = static_cast<uint8_t>(std::stoi(args.QUANTITY1));
    uint8_t qty2 = static_cast<uint8_t>(std::stoi(args.QUANTITY2));
    uint8_t qty3 = static_cast<uint8_t>(std::stoi(args.QUANTITY3));
    // upper bounds: qty + 10 (clamped to 50)
    uint8_t qty1_hi = static_cast<uint8_t>(std::min(static_cast<int>(qty1) + 10, 50));
    uint8_t qty2_hi = static_cast<uint8_t>(std::min(static_cast<int>(qty2) + 10, 50));
    uint8_t qty3_hi = static_cast<uint8_t>(std::min(static_cast<int>(qty3) + 10, 50));

    // -----------------------------------------------------------------------
    // Resolve brand codes from the part brand dictionary
    // -----------------------------------------------------------------------
    uint8_t brand1_code = find_code8(pt.p_brand_dict, args.BRAND1);
    uint8_t brand2_code = find_code8(pt.p_brand_dict, args.BRAND2);
    uint8_t brand3_code = find_code8(pt.p_brand_dict, args.BRAND3);

    // -----------------------------------------------------------------------
    // Resolve container codes for each branch
    // Container sets:
    //   Branch 1: SM CASE, SM BOX, SM PACK, SM PKG
    //   Branch 2: MED BAG, MED BOX, MED PKG, MED PACK
    //   Branch 3: LG CASE, LG BOX, LG PACK, LG PKG
    // -----------------------------------------------------------------------
    static const char* SM_CONTAINERS[]  = {"SM CASE",  "SM BOX",  "SM PACK",  "SM PKG"};
    static const char* MED_CONTAINERS[] = {"MED BAG",  "MED BOX", "MED PKG",  "MED PACK"};
    static const char* LG_CONTAINERS[]  = {"LG CASE",  "LG BOX",  "LG PACK",  "LG PKG"};

    // Build boolean arrays over container_dict size
    const uint32_t num_containers = static_cast<uint32_t>(pt.p_container_dict.size());
    std::vector<uint8_t> cont_is_sm(num_containers, 0);
    std::vector<uint8_t> cont_is_med(num_containers, 0);
    std::vector<uint8_t> cont_is_lg(num_containers, 0);
    for (uint32_t i = 0; i < num_containers; ++i) {
        for (auto* s : SM_CONTAINERS)
            if (pt.p_container_dict[i] == s) { cont_is_sm[i] = 1; break; }
        for (auto* s : MED_CONTAINERS)
            if (pt.p_container_dict[i] == s) { cont_is_med[i] = 1; break; }
        for (auto* s : LG_CONTAINERS)
            if (pt.p_container_dict[i] == s) { cont_is_lg[i] = 1; break; }
    }

    // -----------------------------------------------------------------------
    // Resolve shipmode codes for AIR and AIR REG
    // -----------------------------------------------------------------------
    uint8_t air_code     = find_code8(li.l_shipmode_dict, "AIR");
    uint8_t airreg_code  = find_code8(li.l_shipmode_dict, "AIR REG");

    // -----------------------------------------------------------------------
    // Resolve shipinstruct code for DELIVER IN PERSON
    // -----------------------------------------------------------------------
    uint8_t dip_code = find_code8(li.l_shipinstruct_dict, "DELIVER IN PERSON");

    // -----------------------------------------------------------------------
    // Build a 256-entry LUT for the packed (shipmode<<2)|shipinstruct byte.
    // An entry is 1 iff shipmode IN (AIR, AIR REG) AND shipinstruct = DELIVER IN PERSON.
    // Since the packed byte uses at most 5 bits (32 combos), only 32 entries matter,
    // but we allocate 256 for safety and to avoid bounds-check overhead.
    // -----------------------------------------------------------------------
    uint8_t sm_si_lut[256] = {};
    if (dip_code != 0xFF) {
        for (uint32_t sm = 0; sm < (uint32_t)li.l_shipmode_dict.size(); ++sm) {
            if (sm == air_code || sm == airreg_code) {
                uint8_t packed = static_cast<uint8_t>((sm << 2) | dip_code);
                sm_si_lut[packed] = 1;
            }
        }
    }

    TRACE_COUNT("q19_n_li",            static_cast<int64_t>(li.row_count));
    TRACE_COUNT("q19_n_parts",         static_cast<int64_t>(pt.row_count));
    TRACE_COUNT("q19_brand1_code",     static_cast<int64_t>(brand1_code));
    TRACE_COUNT("q19_brand2_code",     static_cast<int64_t>(brand2_code));
    TRACE_COUNT("q19_brand3_code",     static_cast<int64_t>(brand3_code));
    TRACE_COUNT("q19_qty1_lo",         static_cast<int64_t>(qty1));
    TRACE_COUNT("q19_qty2_lo",         static_cast<int64_t>(qty2));
    TRACE_COUNT("q19_qty3_lo",         static_cast<int64_t>(qty3));
    TRACE_COUNT("q19_num_containers",  static_cast<int64_t>(num_containers));
    TRACE_COUNT("q19_air_code",        static_cast<int64_t>(air_code));
    TRACE_COUNT("q19_airreg_code",     static_cast<int64_t>(airreg_code));
    TRACE_COUNT("q19_dip_code",        static_cast<int64_t>(dip_code));

    // -----------------------------------------------------------------------
    // Phase 1: Build per-partkey branch-membership bitmap
    // Values: bitmask of BRANCH1 | BRANCH2 | BRANCH3
    // -----------------------------------------------------------------------
    const uint32_t max_pk = static_cast<uint32_t>(pt.partkey_to_row.size());
    TRACE_COUNT("q19_max_pk",          static_cast<int64_t>(max_pk));

    int64_t pk_branch1_cnt = 0, pk_branch2_cnt = 0, pk_branch3_cnt = 0;
    std::vector<uint8_t> pk_branch(max_pk, 0);
    {
        PROFILE_SCOPE("q19_part_classify");

        for (uint32_t pk = 1; pk < max_pk; ++pk) {
            uint32_t row = pt.partkey_to_row[pk];
            // Guard: partkey_to_row[pk]==0 is valid only when pk==p_partkey[0]
            if (row == 0 && (pt.p_partkey.empty() || pt.p_partkey[0] != (int32_t)pk))
                continue;

            uint8_t bc = pt.p_brand_code[row];
            uint8_t cc = pt.p_container_code[row];
            uint8_t sz = pt.p_size[row]; // 1..50
            uint8_t flags = 0;

            // Branch 1: brand1, SM containers, size 1..5
            if (bc == brand1_code && cc < num_containers && cont_is_sm[cc] &&
                sz >= 1 && sz <= 5)
                flags |= BRANCH1;

            // Branch 2: brand2, MED containers, size 1..10
            if (bc == brand2_code && cc < num_containers && cont_is_med[cc] &&
                sz >= 1 && sz <= 10)
                flags |= BRANCH2;

            // Branch 3: brand3, LG containers, size 1..15
            if (bc == brand3_code && cc < num_containers && cont_is_lg[cc] &&
                sz >= 1 && sz <= 15)
                flags |= BRANCH3;

            pk_branch[pk] = flags;
        }
    } // end PROFILE_SCOPE q19_part_classify

    // Count qualifying parts per branch after classification
    for (uint32_t pk = 1; pk < max_pk; ++pk) {
        uint8_t f = pk_branch[pk];
        if (f & BRANCH1) ++pk_branch1_cnt;
        if (f & BRANCH2) ++pk_branch2_cnt;
        if (f & BRANCH3) ++pk_branch3_cnt;
    }

    TRACE_COUNT("q19_pk_branch1_cnt", pk_branch1_cnt);
    TRACE_COUNT("q19_pk_branch2_cnt", pk_branch2_cnt);
    TRACE_COUNT("q19_pk_branch3_cnt", pk_branch3_cnt);

    // -----------------------------------------------------------------------
    // Phase 2: Scan lineitem: accumulate revenue = sum(extendedprice * (100-discount))
    //
    // Storage encoding:
    //   l_extendedprice: int64 scaled x100
    //   l_discount:      uint8 0..10   (actual = value/100)
    //   l_quantity:      uint8 1..50   (whole number)
    //
    // disc_price at scale x10000 = ep_x100 * (100 - disc_x100)
    // -----------------------------------------------------------------------
    const uint32_t  n   = li.row_count;
    const int32_t*  lpk = li.l_partkey.data();
    const int32_t*  ep  = li.l_extendedprice.data();
    const uint8_t*  dc  = li.l_discount.data();
    const uint8_t*  qty = li.l_quantity.data();
    const uint8_t*  smsi = li.l_sm_si_packed.data();

    int64_t rows_dip_fail = 0;
    int64_t rows_air_fail = 0;
    int64_t rows_pk_fail  = 0;
    int64_t rows_qty_fail = 0;
    int64_t rows_accepted = 0;
    int64_t revenue_x10000 = 0;

    {
        PROFILE_SCOPE("q19_lineitem_scan");

        for (uint32_t i = 0; i < n; ++i) {
            // Fast pre-filter: single byte load + LUT lookup replaces two separate array reads
            if (!sm_si_lut[smsi[i]]) { ++rows_air_fail; continue; }

            uint32_t pk = static_cast<uint32_t>(lpk[i]);
            if (pk >= max_pk) { ++rows_pk_fail; continue; }
            uint8_t flags = pk_branch[pk];
            if (flags == 0) { ++rows_pk_fail; continue; }

            uint8_t q = qty[i];
            bool ok = false;
            if ((flags & BRANCH1) && q >= qty1 && q <= qty1_hi) ok = true;
            if (!ok && (flags & BRANCH2) && q >= qty2 && q <= qty2_hi) ok = true;
            if (!ok && (flags & BRANCH3) && q >= qty3 && q <= qty3_hi) ok = true;
            if (!ok) { ++rows_qty_fail; continue; }

            // disc_price at x10000 = ep_x100 * (100 - disc_x100)
            revenue_x10000 += ep[i] * static_cast<int64_t>(100 - dc[i]);
            ++rows_accepted;
        }
    } // end PROFILE_SCOPE q19_lineitem_scan

    TRACE_COUNT("q19_rows_total",     static_cast<int64_t>(n));
    TRACE_COUNT("q19_rows_dip_fail",  rows_dip_fail);
    TRACE_COUNT("q19_rows_air_fail",  rows_air_fail);
    TRACE_COUNT("q19_rows_pk_fail",   rows_pk_fail);
    TRACE_COUNT("q19_rows_qty_fail",  rows_qty_fail);
    TRACE_COUNT("q19_rows_accepted",  rows_accepted);
    TRACE_COUNT("q19_revenue_x10000", revenue_x10000);

    // -----------------------------------------------------------------------
    // Assemble result
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.push_back({"revenue"});
    rows.push_back({q19_fmt_scaled(revenue_x10000, 4)});

    TRACE_COUNT("q19_output_rows", static_cast<int64_t>(rows.size() - 1));
    return rows;
}

#include "query20.hpp"

#include <algorithm>
#include <cstdint>
#include <stdexcept>
#include <string>
#include <unordered_map>
#include <unordered_set>
#include <vector>

// SQL:
/** select
    s_name,
    s_address
from
    supplier, nation
where
    s_suppkey in (
        select
            ps_suppkey
        from
            partsupp
        where
            ps_partkey in (
                select
                    p_partkey
                from
                    part
                where
                    p_name like '[COLOR]%'
                    )
        and ps_availqty > (
            select
                0.5 * sum(l_quantity)
            from
                lineitem
            where
                l_partkey = ps_partkey
                and l_suppkey = ps_suppkey
                and l_shipdate >= date('[DATE]')
                and l_shipdate < date('[DATE]') + interval '1' year
        )
    )
    and s_nationkey = n_nationkey
    and n_name = '[NATION]'
order by
    s_name; */

// ---------------------------------------------------------------------------
// Date helpers: parse "YYYY-MM-DD" -> DATE16 (days since 1992-01-01)
// ---------------------------------------------------------------------------
static bool q20_leap(int y) {
    return (y % 4 == 0 && y % 100 != 0) || (y % 400 == 0);
}
static const int Q20_DIM[2][12] = {
    {31,28,31,30,31,30,31,31,30,31,30,31},
    {31,29,31,30,31,30,31,31,30,31,30,31}
};
static uint16_t q20_parse_date(const std::string& s) {
    // "YYYY-MM-DD"
    const char* c = s.c_str();
    int y = (c[0]-'0')*1000 + (c[1]-'0')*100 + (c[2]-'0')*10 + (c[3]-'0');
    int m = (c[5]-'0')*10 + (c[6]-'0');
    int d = (c[8]-'0')*10 + (c[9]-'0');
    int tot = 0;
    for (int i = 1992; i < y; ++i) tot += q20_leap(i) ? 366 : 365;
    int lp = q20_leap(y) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q20_DIM[lp][i - 1];
    return static_cast<uint16_t>(tot + (d - 1));
}

// Add exactly one year to a DATE16 value.
static uint16_t q20_add_one_year(uint16_t d16) {
    // Decode d16 -> (y, m, d)
    int rem = static_cast<int>(d16);
    int y = 1992;
    while (true) {
        int dy = q20_leap(y) ? 366 : 365;
        if (rem < dy) break;
        rem -= dy; ++y;
    }
    int lp = q20_leap(y) ? 1 : 0;
    int m = 1;
    while (m <= 12 && rem >= Q20_DIM[lp][m-1]) {
        rem -= Q20_DIM[lp][m-1];
        ++m;
    }
    int d = rem + 1; // 1-based day of month

    // Advance year by 1
    int ny = y + 1;
    // Clamp Feb-29 -> Feb-28 in non-leap target year
    if (m == 2 && d == 29 && !q20_leap(ny)) d = 28;

    // Re-encode to DATE16
    int tot = 0;
    for (int i = 1992; i < ny; ++i) tot += q20_leap(i) ? 366 : 365;
    int nlp = q20_leap(ny) ? 1 : 0;
    for (int i = 1; i < m; ++i) tot += Q20_DIM[nlp][i - 1];
    return static_cast<uint16_t>(tot + (d - 1));
}

std::vector<std::vector<std::string>> run_q20(Database* db, const Q20Args& args) {
    if (!db) throw std::runtime_error("run_q20: db is null");

    const Part&     pt  = db->part;
    const PartSupp& ps  = db->partsupp;
    const Supplier& sup = db->supplier;
    const Nation&   nat = db->nation;
    const Lineitem& li  = db->lineitem;

    // -----------------------------------------------------------------------
    // Step 1: resolve nation name -> nationkey
    // -----------------------------------------------------------------------
    int nation_key = nat.name_to_key(args.NATION);
    if (nation_key < 0) {
        std::vector<std::vector<std::string>> rows;
        rows.push_back({"s_name", "s_address"});
        return rows;
    }

    // -----------------------------------------------------------------------
    // Step 2: collect partkeys where p_name starts with COLOR prefix
    //         p_name LIKE '[COLOR]%'  =>  p_name starts with COLOR
    // -----------------------------------------------------------------------
    const std::string& color = args.COLOR;
    uint32_t max_pk = static_cast<uint32_t>(pt.partkey_to_row.size()); // max_partkey+1

    // pk_color_match[pk] = true if this part qualifies
    std::vector<bool> pk_color_match(max_pk, false);
    for (uint32_t row = 0; row < pt.row_count; ++row) {
        const std::string& name = pt.p_name[row];
        if (name.size() >= color.size() &&
            name.compare(0, color.size(), color) == 0) {
            int32_t pk = pt.p_partkey[row];
            if (pk > 0 && static_cast<uint32_t>(pk) < max_pk)
                pk_color_match[static_cast<uint32_t>(pk)] = true;
        }
    }

    // -----------------------------------------------------------------------
    // Step 3: compute date range  [date_lo, date_hi)
    //         date_lo = DATE,  date_hi = DATE + 1 year
    // -----------------------------------------------------------------------
    uint16_t date_lo = q20_parse_date(args.DATE);
    uint16_t date_hi = q20_add_one_year(date_lo);

    // -----------------------------------------------------------------------
    // Step 4: build (ps_partkey, ps_suppkey) -> sum_l_quantity map
    //         by scanning lineitem once.
    //
    //         Key: pack (partkey, suppkey) into a uint64_t.
    //         l_quantity is uint8 (whole number 1..50).
    // -----------------------------------------------------------------------
    // Only include entries where the partkey is color-matching.
    auto pack_key = [](int32_t pk, int32_t sk) -> uint64_t {
        return (static_cast<uint64_t>(static_cast<uint32_t>(pk)) << 32) |
                static_cast<uint64_t>(static_cast<uint32_t>(sk));
    };

    std::unordered_map<uint64_t, int64_t> qty_sum; // (pk,sk) -> sum of l_quantity
    {
        const uint32_t  n_li = li.row_count;
        const int32_t*  lpk  = li.l_partkey.data();
        const int32_t*  lsk  = li.l_suppkey.data();
        const uint8_t*  qty  = li.l_quantity.data();
        const uint16_t* sd   = li.l_shipdate.data();

        for (uint32_t i = 0; i < n_li; ++i) {
            uint16_t shipdate = sd[i];
            if (shipdate < date_lo || shipdate >= date_hi) continue;

            int32_t pk = lpk[i];
            if (pk <= 0 || static_cast<uint32_t>(pk) >= max_pk) continue;
            if (!pk_color_match[static_cast<uint32_t>(pk)]) continue;

            qty_sum[pack_key(pk, lsk[i])] += static_cast<int64_t>(qty[i]);
        }
    }

    // -----------------------------------------------------------------------
    // Step 5: scan partsupp to find qualifying suppkeys.
    //         Condition: ps_partkey is color-matching AND
    //                    ps_availqty > 0.5 * sum_qty(ps_partkey, ps_suppkey)
    //
    //         Avoid floating point: 2 * availqty > sum_qty is equivalent.
    //         If no lineitem rows exist, sum_qty = 0, so availqty > 0.
    // -----------------------------------------------------------------------
    std::unordered_set<int32_t> qualifying_suppkeys;
    {
        const uint32_t n_ps = ps.row_count;
        for (uint32_t r = 0; r < n_ps; ++r) {
            int32_t pk = ps.ps_partkey[r];
            if (pk <= 0 || static_cast<uint32_t>(pk) >= max_pk) continue;
            if (!pk_color_match[static_cast<uint32_t>(pk)]) continue;

            int32_t sk       = ps.ps_suppkey[r];
            int32_t availqty = ps.ps_availqty[r];

            auto it = qty_sum.find(pack_key(pk, sk));
            // SQL: ps_availqty > 0.5 * sum(l_quantity)
            // If no lineitem rows match, SUM returns NULL, and NULL comparison = FALSE.
            // So only qualify if there is at least one matching lineitem row.
            if (it == qty_sum.end()) continue; // no matching rows -> NULL -> skip
            int64_t sq = it->second;
            // availqty > 0.5 * sq  <=>  2 * availqty > sq  (integer arithmetic)
            if (static_cast<int64_t>(availqty) * 2 > sq) {
                qualifying_suppkeys.insert(sk);
            }
        }
    }

    // -----------------------------------------------------------------------
    // Step 6: collect suppliers in the nation that are in qualifying set.
    //         Sort by s_name ASC.
    // -----------------------------------------------------------------------
    struct ResultRow {
        std::string s_name;
        std::string s_address;
    };
    std::vector<ResultRow> result;
    result.reserve(qualifying_suppkeys.size());

    for (uint32_t row = 0; row < sup.row_count; ++row) {
        if (sup.s_nationkey[row] != static_cast<uint8_t>(nation_key)) continue;
        int32_t sk = sup.s_suppkey[row];
        if (qualifying_suppkeys.count(sk) == 0) continue;
        result.push_back({sup.s_name[row], sup.s_address[row]});
    }

    std::sort(result.begin(), result.end(),
              [](const ResultRow& a, const ResultRow& b) {
                  return a.s_name < b.s_name;
              });

    // -----------------------------------------------------------------------
    // Step 7: assemble output rows
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);
    rows.push_back({"s_name", "s_address"});
    for (const auto& rr : result)
        rows.push_back({rr.s_name, rr.s_address});
    return rows;
}

