// SQL:
/**
select
    s_name,
    count(*) as numwait
from
    supplier,
    lineitem l1,
    orders,
    nation
where
    s_suppkey = l1.l_suppkey
    and o_orderkey = l1.l_orderkey
    and o_orderstatus = 'F'
    and l1.l_receiptdate > l1.l_commitdate
    and exists (
        select *
        from
            lineitem l2
        where
            l2.l_orderkey = l1.l_orderkey
            and l2.l_suppkey <> l1.l_suppkey
    )
    and not exists (
        select *
        from
            lineitem l3
        where
            l3.l_orderkey = l1.l_orderkey
            and l3.l_suppkey <> l1.l_suppkey
            and l3.l_receiptdate > l3.l_commitdate
    )
    and s_nationkey = n_nationkey
    and n_name = '[NATION]'
group by
    s_name
order by
    numwait desc,
    s_name;
*/

std::vector<std::vector<std::string>> run_q21(Database* db, const Q21Args& args) {
    if (!db) {
        throw std::runtime_error("run_q21: db is null");
    }

    const Nation&   nat = db->nation;
    const Supplier& sup = db->supplier;
    const Orders&   ord = db->orders;
    const Lineitem& li  = db->lineitem;

    // -----------------------------------------------------------------------
    // Step 1: resolve nation name -> nationkey
    // -----------------------------------------------------------------------
    int nation_key = nat.name_to_key(args.NATION);
    if (nation_key < 0) {
        // No matching nation: return empty result with header
        std::vector<std::vector<std::string>> rows;
        rows.push_back({"s_name", "numwait"});
        return rows;
    }

    // -----------------------------------------------------------------------
    // Step 2: build a bool vector: is_nation_sup[suppkey] = true
    //         for suppliers in the target nation.
    // -----------------------------------------------------------------------
    const uint32_t max_sk = static_cast<uint32_t>(sup.suppkey_to_row.size());
    std::vector<bool> is_nation_sup(max_sk, false);
    for (uint32_t row = 0; row < sup.row_count; ++row) {
        if (sup.s_nationkey[row] == static_cast<uint8_t>(nation_key)) {
            int32_t sk = sup.s_suppkey[row];
            if (sk > 0 && static_cast<uint32_t>(sk) < max_sk)
                is_nation_sup[static_cast<uint32_t>(sk)] = true;
        }
    }

    // -----------------------------------------------------------------------
    // Step 3: Scan all orders with status 'F'.
    //         For each such order, iterate its lineitems once to evaluate
    //         the EXISTS / NOT-EXISTS subqueries.
    //
    //         Per order, collect:
    //           all_sk32[]:  all distinct suppkeys on the order
    //           late_sk32[]: distinct suppkeys that have commit_late=true
    //           candidates:  (li_row, suppkey) where suppkey is a nation-
    //                        supplier AND commit_late=true  (these are l1)
    //
    //         For each candidate l1 with suppkey s:
    //           EXISTS(l2)     : any all_sk32[x] != s
    //           NOT EXISTS(l3) : no late_sk32[x] != s
    // -----------------------------------------------------------------------
    // Result accumulator: supplier row index -> numwait count
    std::unordered_map<uint32_t, int64_t> numwait;

    const uint32_t li_rows   = li.row_count;
    const uint32_t ok_idx_sz = static_cast<uint32_t>(li.orderkey_to_first_li.size());
    const uint32_t ord_rows  = ord.row_count;

    for (uint32_t oi = 0; oi < ord_rows; ++oi) {
        // Only consider orders with status 'F' (encoded as 0)
        if (ord.o_orderstatus[oi] != 0) continue;

        const int32_t  ok  = ord.o_orderkey[oi];
        const uint32_t uok = static_cast<uint32_t>(ok);
        if (uok >= ok_idx_sz) continue;
        const uint32_t li_start = li.orderkey_to_first_li[uok];
        if (li_start == 0xFFFFFFFFu) continue;

        // TPC-H: max 7 line items per order — use small fixed-size arrays
        int32_t all_sk32[7];  int all_cnt  = 0;
        int32_t late_sk32[7]; int late_cnt = 0;
        int32_t cand_sk[7];   int cand_cnt = 0;  // l1 candidate suppkeys

        for (uint32_t r = li_start; r < li_rows && li.l_orderkey[r] == ok; ++r) {
            int32_t sk = li.l_suppkey[r];
            bool    late = li.l_commit_late.test(r);

            // Track all distinct suppkeys
            bool found_all = false;
            for (int x = 0; x < all_cnt; ++x)
                if (all_sk32[x] == sk) { found_all = true; break; }
            if (!found_all && all_cnt < 7) all_sk32[all_cnt++] = sk;

            // Track distinct suppkeys with commit_late
            if (late) {
                bool found_late = false;
                for (int x = 0; x < late_cnt; ++x)
                    if (late_sk32[x] == sk) { found_late = true; break; }
                if (!found_late && late_cnt < 7) late_sk32[late_cnt++] = sk;
            }

            // Candidate l1: nation supplier AND commit_late
            if (late &&
                static_cast<uint32_t>(sk) < max_sk &&
                is_nation_sup[static_cast<uint32_t>(sk)]) {
                // Only add if not already a candidate (same suppkey can appear
                // multiple times across line items, but we want distinct
                // suppkeys — actually count ALL qualifying l1 rows, not just
                // distinct: each qualifying lineitem row contributes one count)
                if (cand_cnt < 7) { cand_sk[cand_cnt++] = sk; }
            }
        }

        if (cand_cnt == 0) continue;

        // Evaluate EXISTS and NOT-EXISTS for each candidate l1 suppkey
        for (int c = 0; c < cand_cnt; ++c) {
            int32_t s = cand_sk[c];

            // EXISTS(l2): some all_sk32[x] != s
            bool exists_l2 = false;
            for (int x = 0; x < all_cnt; ++x)
                if (all_sk32[x] != s) { exists_l2 = true; break; }
            if (!exists_l2) continue;

            // NOT EXISTS(l3): no late_sk32[x] != s
            bool has_other_late = false;
            for (int x = 0; x < late_cnt; ++x)
                if (late_sk32[x] != s) { has_other_late = true; break; }
            if (has_other_late) continue;

            // This l1 qualifies — increment numwait for its supplier
            uint32_t sup_row = sup.suppkey_to_row[static_cast<uint32_t>(s)];
            numwait[sup_row]++;
        }
    }

    // -----------------------------------------------------------------------
    // Step 4: collect results, sort by numwait DESC then s_name ASC
    // -----------------------------------------------------------------------
    struct ResultRow {
        std::string s_name;
        int64_t     numwait;
    };
    std::vector<ResultRow> result;
    result.reserve(numwait.size());
    for (const auto& [sup_row, cnt] : numwait) {
        result.push_back({sup.s_name[sup_row], cnt});
    }
    std::sort(result.begin(), result.end(),
              [](const ResultRow& a, const ResultRow& b) {
                  if (a.numwait != b.numwait) return a.numwait > b.numwait;
                  return a.s_name < b.s_name;
              });

    // -----------------------------------------------------------------------
    // Step 5: assemble output rows
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);
    rows.push_back({"s_name", "numwait"});
    for (const auto& rr : result)
        rows.push_back({rr.s_name, std::to_string(rr.numwait)});
    return rows;
}

#include "query21.hpp"

#include "trace.hpp"

#include <algorithm>
#include <cstdint>
#include <stdexcept>
#include <string>
#include <unordered_map>
#include <vector>

// SQL:
/**
select
    s_name,
    count(*) as numwait
from
    supplier,
    lineitem l1,
    orders,
    nation
where
    s_suppkey = l1.l_suppkey
    and o_orderkey = l1.l_orderkey
    and o_orderstatus = 'F'
    and l1.l_receiptdate > l1.l_commitdate
    and exists (
        select *
        from
            lineitem l2
        where
            l2.l_orderkey = l1.l_orderkey
            and l2.l_suppkey <> l1.l_suppkey
    )
    and not exists (
        select *
        from
            lineitem l3
        where
            l3.l_orderkey = l1.l_orderkey
            and l3.l_suppkey <> l1.l_suppkey
            and l3.l_receiptdate > l3.l_commitdate
    )
    and s_nationkey = n_nationkey
    and n_name = '[NATION]'
group by
    s_name
order by
    numwait desc,
    s_name;
*/

std::vector<std::vector<std::string>> run_q21(Database* db, const Q21Args& args) {
    if (!db) {
        throw std::runtime_error("run_q21: db is null");
    }

    PROFILE_SCOPE("q21_total");

    const Nation&   nat = db->nation;
    const Supplier& sup = db->supplier;
    const Orders&   ord = db->orders;
    const Lineitem& li  = db->lineitem;

    TRACE_COUNT("q21_n_li",        static_cast<int64_t>(li.row_count));
    TRACE_COUNT("q21_n_orders",    static_cast<int64_t>(ord.row_count));
    TRACE_COUNT("q21_n_suppliers", static_cast<int64_t>(sup.row_count));

    // -----------------------------------------------------------------------
    // Step 1: resolve nation name -> nationkey
    // -----------------------------------------------------------------------
    int nation_key = nat.name_to_key(args.NATION);
    if (nation_key < 0) {
        std::vector<std::vector<std::string>> rows;
        rows.push_back({"s_name", "numwait"});
        return rows;
    }
    TRACE_COUNT("q21_nation_key", static_cast<int64_t>(nation_key));

    // -----------------------------------------------------------------------
    // Step 2: build is_nation_sup[suppkey] byte array for fast lookup.
    // -----------------------------------------------------------------------
    const uint32_t max_sk = static_cast<uint32_t>(sup.suppkey_to_row.size());
    int64_t nation_sup_cnt = 0;
    // uint8_t is faster than std::vector<bool> (no bit unpacking)
    std::vector<uint8_t> is_nation_sup(max_sk, 0);
    for (uint32_t row = 0; row < sup.row_count; ++row) {
        if (sup.s_nationkey[row] == static_cast<uint8_t>(nation_key)) {
            int32_t sk = sup.s_suppkey[row];
            if (sk > 0 && static_cast<uint32_t>(sk) < max_sk) {
                is_nation_sup[static_cast<uint32_t>(sk)] = 1;
                ++nation_sup_cnt;
            }
        }
    }
    TRACE_COUNT("q21_nation_sup_cnt", nation_sup_cnt);

    // -----------------------------------------------------------------------
    // Step 3: Scan F-orders using order_row_to_li_start (dense, compact index).
    //         For each F-order, scan its lineitem group sequentially.
    //
    //  Per order group (max 7 lineitems):
    //    sk_slot[7]   - distinct suppkeys in this order
    //    cand_cnt[7]  - count of late l1-rows for nation-supplier slots (0=not cand)
    //    slot_mask    - bit i set if slot i is occupied (EXISTS check)
    //    late_smask   - bit i set if slot i has >= 1 late row (NOT EXISTS check)
    //
    //  After scanning all rows:
    //    For each candidate slot c (cand_cnt[c] > 0):
    //      EXISTS(l2):     (slot_mask & ~c_bit) != 0
    //      NOT EXISTS(l3): (late_smask & ~c_bit) == 0
    //      If both: numwait[supplier] += cand_cnt[c]
    //
    //  Key improvements vs original:
    //    - Uses order_row_to_li_start (dense compact) instead of
    //      orderkey_to_first_li (sparse ~480MB at SF20)
    //    - Replaces std::vector<bool> with uint8_t for is_nation_sup
    //    - Uses bitmask ops for EXISTS/NOT-EXISTS instead of linear search
    //    - Avoids redundant dedup tracking (single slot array covers all checks)
    // -----------------------------------------------------------------------
    std::unordered_map<uint32_t, int64_t> numwait;
    numwait.reserve(static_cast<size_t>(nation_sup_cnt) * 2);

    const uint32_t li_rows  = li.row_count;
    const uint32_t ord_rows = ord.row_count;

    int64_t orders_scanned = 0;
    int64_t cands_accepted = 0;

    {
        PROFILE_SCOPE("q21_order_scan");

        int32_t sk_slot[7];
        uint8_t cand_cnt[7];

        for (uint32_t oi = 0; oi < ord_rows; ++oi) {
            // Only F-orders (encoded as 0)
            if (ord.o_orderstatus[oi] != 0) continue;

            // Use dense compact index (order row -> first li row)
            const uint32_t li_start = ord.order_row_to_li_start[oi];
            if (li_start == 0xFFFFFFFFu) continue;

            ++orders_scanned;

            uint8_t slot_mask  = 0;
            uint8_t late_smask = 0;

            const int32_t ok = ord.o_orderkey[oi];

            for (uint32_t r = li_start; r < li_rows && li.l_orderkey[r] == ok; ++r) {
                const int32_t sk   = li.l_suppkey[r];
                const bool    late = li.l_commit_late.test(r);

                // Find or allocate slot for this suppkey
                int slot = -1;
                for (uint8_t sm = slot_mask; sm; ) {
                    int i = __builtin_ctz(sm);
                    sm &= (uint8_t)(sm - 1);
                    if (sk_slot[i] == sk) { slot = i; break; }
                }
                if (slot < 0) {
                    slot = __builtin_ctz((unsigned)(~(unsigned)slot_mask));
                    sk_slot[slot]  = sk;
                    cand_cnt[slot] = 0;
                    slot_mask |= (uint8_t)(1u << slot);
                }

                if (late) {
                    late_smask |= (uint8_t)(1u << slot);
                    if (static_cast<uint32_t>(sk) < max_sk &&
                        is_nation_sup[static_cast<uint32_t>(sk)])
                        ++cand_cnt[slot];
                }
            }

            // Evaluate each candidate slot
            if (late_smask == 0) continue;

            for (uint8_t sm = slot_mask; sm; ) {
                int c  = __builtin_ctz(sm);
                sm    &= (uint8_t)(sm - 1);
                if (cand_cnt[c] == 0) continue;

                const uint8_t c_bit   = (uint8_t)(1u << c);
                const uint8_t no_cbit = (uint8_t)(~c_bit);

                // EXISTS(l2)
                if ((slot_mask & no_cbit) == 0) continue;

                // NOT EXISTS(l3)
                if ((late_smask & no_cbit) != 0) continue;

                // Qualifies
                int32_t  s       = sk_slot[c];
                uint32_t sup_row = sup.suppkey_to_row[static_cast<uint32_t>(s)];
                numwait[sup_row] += cand_cnt[c];
                cands_accepted   += cand_cnt[c];
            }
        }
    }

    TRACE_COUNT("q21_orders_scanned",      orders_scanned);
    TRACE_COUNT("q21_cands_accepted",      cands_accepted);
    TRACE_COUNT("q21_suppliers_with_wait", static_cast<int64_t>(numwait.size()));

    // -----------------------------------------------------------------------
    // Step 4: collect results, sort by numwait DESC then s_name ASC
    // -----------------------------------------------------------------------
    struct ResultRow {
        std::string s_name;
        int64_t     numwait;
    };
    std::vector<ResultRow> result;
    result.reserve(numwait.size());
    for (const auto& [sup_row, cnt] : numwait) {
        result.push_back({sup.s_name[sup_row], cnt});
    }
    std::sort(result.begin(), result.end(),
              [](const ResultRow& a, const ResultRow& b) {
                  if (a.numwait != b.numwait) return a.numwait > b.numwait;
                  return a.s_name < b.s_name;
              });

    // -----------------------------------------------------------------------
    // Step 5: assemble output rows
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);
    rows.push_back({"s_name", "numwait"});
    for (const auto& rr : result)
        rows.push_back({rr.s_name, std::to_string(rr.numwait)});

    TRACE_COUNT("q21_output_rows", static_cast<int64_t>(rows.size() - 1));
    return rows;
}

