// SQL:
/** select
    cntrycode,
    count(*) as numcust,
    sum(c_acctbal) as totacctbal
from (
    select
        substring(c_phone from 1 for 2) as cntrycode,
        c_acctbal
    from
        customer
    where
        substring(c_phone from 1 for 2) in ('[I1]','[I2]','[I3]','[I4]','[I5]','[I6]','[I7]')
        and c_acctbal > (
            select
                avg(c_acctbal)
            from
                customer
            where
                c_acctbal > 0.00
                and substring (c_phone from 1 for 2) in ('[I1]','[I2]','[I3]','[I4]','[I5]','[I6]','[I7]')
        )
        and not exists (
            select *
            from
                orders
            where
                o_custkey = c_custkey
        )
    ) as custsale
group by
    cntrycode
order by
    cntrycode; */

// ---------------------------------------------------------------------------
// Helper: format int64 scaled *100 as decimal with 2 fractional digits
// ---------------------------------------------------------------------------
static std::string fmt_acctbal(int64_t v) {
    bool neg = (v < 0);
    if (neg) v = -v;
    int64_t whole = v / 100;
    int64_t frac  = v % 100;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << whole << '.' << std::setw(2) << std::setfill('0') << frac;
    return oss.str();
}

std::vector<std::vector<std::string>> run_q22(Database* db, const Q22Args& args) {
    if (!db) {
        throw std::runtime_error("run_q22: db is null");
    }

    const Customer& cust = db->customer;
    const Orders&   ord  = db->orders;

    // -----------------------------------------------------------------------
    // Step 1: Build the set of valid country codes (phone prefixes).
    //         Args I1..I7 may be "<<NULL>>" — skip those.
    // -----------------------------------------------------------------------
    const std::string* raw_codes[7] = {
        &args.I1, &args.I2, &args.I3, &args.I4,
        &args.I5, &args.I6, &args.I7
    };
    static const std::string NULL_MARKER = "<<NULL>>";

    // Collect distinct non-null codes
    std::vector<std::string> codes;
    codes.reserve(7);
    for (int k = 0; k < 7; ++k) {
        const std::string& s = *raw_codes[k];
        if (s == NULL_MARKER) continue;
        // Avoid duplicates (unlikely but safe)
        bool dup = false;
        for (const auto& c : codes)
            if (c == s) { dup = true; break; }
        if (!dup) codes.push_back(s);
    }

    // Helper lambda: does phone_prefix match any of the codes?
    // c_phone stores the full phone string; the country code is the
    // first 2 characters (substring(c_phone from 1 for 2) in SQL).
    auto prefix_in_set = [&](const std::string& phone) -> bool {
        if (phone.size() < 2) return false;
        std::string_view pfx(phone.data(), 2);
        for (const auto& c : codes)
            if (pfx == std::string_view(c.data(), c.size())) return true;
        return false;
    };

    // -----------------------------------------------------------------------
    // Step 2: Compute the average c_acctbal for customers whose phone prefix
    //         is in the set AND c_acctbal > 0.
    //         c_acctbal is stored scaled *100 (int64), so >0 means >0 as int64.
    // -----------------------------------------------------------------------
    int64_t sum_acctbal_pos = 0;
    int64_t cnt_acctbal_pos = 0;

    const uint32_t n_custs = cust.row_count;
    for (uint32_t ci = 0; ci < n_custs; ++ci) {
        const int64_t acctbal = cust.c_acctbal[ci];
        if (acctbal <= 0) continue;
        if (!prefix_in_set(cust.c_phone[ci])) continue;
        sum_acctbal_pos += acctbal;
        ++cnt_acctbal_pos;
    }

    // avg_threshold (scaled *100): if no qualifying rows, threshold = 0
    // (every positive acctbal would qualify, effectively)
    int64_t avg_threshold = 0;
    if (cnt_acctbal_pos > 0) {
        // Integer average (truncate), still in scale *100 units
        avg_threshold = sum_acctbal_pos / cnt_acctbal_pos;
    }

    // -----------------------------------------------------------------------
    // Step 3: Scan customers with:
    //   - phone prefix in set
    //   - c_acctbal > avg_threshold
    //   - NOT EXISTS any order for this customer
    //         (use custkey_has_order bitmap)
    //
    // Group by cntrycode (the 2-char phone prefix).
    // -----------------------------------------------------------------------
    // Map: cntrycode -> (numcust, sum_acctbal)
    struct CtryStat { int64_t numcust = 0; int64_t totacctbal = 0; };
    // Use a small array indexed by position in `codes` for efficiency
    std::vector<CtryStat> stats(codes.size());

    const uint32_t cust_order_bv_sz = ord.custkey_has_order.count;

    for (uint32_t ci = 0; ci < n_custs; ++ci) {
        const int64_t acctbal = cust.c_acctbal[ci];
        if (acctbal <= avg_threshold) continue;  // must be strictly greater

        const std::string& phone = cust.c_phone[ci];
        if (phone.size() < 2) continue;
        std::string_view pfx(phone.data(), 2);

        // Find which code this prefix matches (if any)
        int code_idx = -1;
        for (int k = 0; k < (int)codes.size(); ++k) {
            if (pfx == std::string_view(codes[k].data(), codes[k].size())) {
                code_idx = k;
