        // NOT EXISTS: check that the customer has no orders
        const int32_t ck = cust.c_custkey[ci];
        if (ck >= 0 && static_cast<uint32_t>(ck) < cust_order_bv_sz) {
            if (ord.custkey_has_order.test(static_cast<uint32_t>(ck))) continue;
        }
        // If ck is out of range of the bitmap, it has no orders (safe to include)

        stats[code_idx].numcust++;
        stats[code_idx].totacctbal += acctbal;
    }

    // -----------------------------------------------------------------------
    // Step 4: Collect non-empty groups, sort by cntrycode ASC
    // -----------------------------------------------------------------------
    struct ResultRow {
        std::string cntrycode;
        int64_t     numcust;
        int64_t     totacctbal;
    };
    std::vector<ResultRow> result;
    result.reserve(codes.size());
    for (int k = 0; k < (int)codes.size(); ++k) {
