    // -----------------------------------------------------------------------
    // Step 5: Assemble output rows
    // -----------------------------------------------------------------------
    std::vector<std::vector<std::string>> rows;
    rows.reserve(result.size() + 1);
    rows.push_back({"cntrycode", "numcust", "totacctbal"});
    for (const auto& rr : result) {
        rows.push_back({
            rr.cntrycode,
            std::to_string(rr.numcust),
            fmt_acctbal(rr.totacctbal)
        });
    }
    return rows;
}

