// ---------------------------------------------------------------------------
// Helper: format int64 scaled *100 as decimal with 2 fractional digits
// ---------------------------------------------------------------------------
static std::string fmt_acctbal(int64_t v) {
    bool neg = (v < 0);
    if (neg) v = -v;
    int64_t whole = v / 100;
    int64_t frac  = v % 100;
    std::ostringstream oss;
    if (neg) oss << '-';
    oss << whole << '.' << std::setw(2) << std::setfill('0') << frac;
    return oss.str();
}

std::vector<std::vector<std::string>> run_q22(Database* db, const Q22Args& args) {
    if (!db) {
