    uint8_t pfx_match[128][128] = {};  // zero-initialized = no match
    uint16_t code_pfx[7] = {};         // still used for code_idx lookup in stats
    for (int k = 0; k < n_codes; ++k) {
        const std::string& s = codes[k];
        if (s.size() >= 2) {
            unsigned char c0 = static_cast<unsigned char>(s[0]);
            unsigned char c1 = static_cast<unsigned char>(s[1]);
            code_pfx[k] = (static_cast<uint16_t>(c0) << 8) | static_cast<uint16_t>(c1);
            if (c0 < 128 && c1 < 128)
