    // -----------------------------------------------------------------------
    int64_t sum_acctbal_pos = 0;
    int64_t cnt_acctbal_pos = 0;

    const uint32_t n_custs = cust.row_count;

    {
        PROFILE_SCOPE("q22_avg_scan");

        for (uint32_t ci = 0; ci < n_custs; ++ci) {
            const int64_t acctbal = cust.c_acctbal[ci];
            if (acctbal <= 0) continue;
            const uint16_t pfx = cust.c_phone_prefix[ci];
            if (prefix_idx(pfx) < 0) continue;
            sum_acctbal_pos += acctbal;
            ++cnt_acctbal_pos;
        }
    } // end PROFILE_SCOPE q22_avg_scan

    // avg_threshold (scaled *100): if no qualifying rows, threshold = 0
    // (every positive acctbal would qualify, effectively)
    int64_t avg_threshold = 0;
    if (cnt_acctbal_pos > 0) {
