    int64_t cust_acctbal_fail   = 0;  // failed acctbal > avg_threshold
    int64_t cust_prefix_fail    = 0;  // failed phone prefix in set (or too short)
    int64_t cust_has_order_fail = 0;  // failed NOT EXISTS orders
    int64_t cust_accepted       = 0;  // passed all filters

