    TRACE_COUNT("q22_cust_has_order_fail", cust_has_order_fail);
    TRACE_COUNT("q22_cust_accepted",       cust_accepted);

    // -----------------------------------------------------------------------
    // Step 4: Collect non-empty groups, sort by cntrycode ASC
    // -----------------------------------------------------------------------
    struct ResultRow {
        std::string cntrycode;
        int64_t     numcust;
        int64_t     totacctbal;
    };
    std::vector<ResultRow> result;
    result.reserve(codes.size());
    for (int k = 0; k < (int)codes.size(); ++k) {
        if (stats[k].numcust > 0) {
            result.push_back({codes[k], stats[k].numcust, stats[k].totacctbal});
        }
    }
    std::sort(result.begin(), result.end(),
